#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The flags `has_one` and `has_minus_one` reflect the state of a[0...i]
            // before considering a[i] itself.
            // If a[i] is 1 or -1, it contributes to the flags for elements before it.
            if (a[i] == 1) has_one = true;
            if (a[i] == -1) has_minus_one = true;
            continue;
        }

        // If a[i] != b[i], we need to change a[i].
        // This means we must have added some a_k (k < i) to a[i].
        // The current a[i] is the original a[i].
        // The target is b[i].
        // We need to achieve b[i] from a[i] using operations from a_k (k < i).

        if (b[i] > a[i]) { // Need to increase a[i]
            if (!has_one) { // Cannot increase if no '1' is available from a_k (k < i)
                possible = false;
                break;
            }
        } else { // b[i] < a[i], need to decrease a[i]
            if (!has_minus_one) { // Cannot decrease if no '-1' is available from a_k (k < i)
                possible = false;
                break;
            }
        }

        // If a[i] is 1 or -1, it contributes to the flags for elements before it.
        if (a[i] == 1) has_one = true;
        if (a[i] == -1) has_minus_one = true;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

