void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;

    int current_color_for_T_half = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (T_is_even && a[i] == T_half) {
            // Elements equal to T/2
            p[i] = current_color_for_T_half;
            current_color_for_T_half = 1 - current_color_for_T_half; // Alternate colors
        } else if (a[i] < T_half) {
            // Elements less than T/2
            // These should ideally be paired with elements > T/2.
            // If a[i] is in c, T-a[i] should be in d.
            // If a[i] is in d, T-a[i] should be in c.
            // To simplify, let's put all a[i] < T/2 into one group (e.g., color 0).
            // And all a[i] > T/2 into the other group (e.g., color 1).
            // This ensures that if a[i] + a[j] = T, and a[i] < T/2, then a[j] > T/2.
            // So they will be in different groups.
            p[i] = 0;
        } else { // a[i] > T_half (or a[i] < T_half if T is odd, but we already handled a[i] < T_half)
            // Elements greater than T/2
            p[i] = 1;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

