}

#include <iostream>
#include <vector>
#include <algorithm> // For std::max_element

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_for_i) {
                max_val_for_i = a[i][j];
            }
        }
        // If max_val_for_i is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_for_i.
        // This logic is derived from the observation that if p[i] is not n,
        // then max_{j!=i} min(p[i], p[j]) = p[i].
        // If p[i] is n, then max_{j!=i} min(n, p[j]) = max_{j!=i} p[j] = n-1.
        // So, if max_val_for_i == n-1, then p[i] must be n.
        // Otherwise, p[i] must be max_val_for_i.
        if (max_val_for_i == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_for_i;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_so_far_from_right = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, starting from the second to last element
    // The last element a[n-1] can never be a bad price because there are no days after it.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_so_far_from_right) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_so_far_from_right,
            // it means a[i] is a new minimum or equal to the current minimum
            // when considering elements from a[i] to a[n-1].
            // So, update min_so_far_from_right.
            min_so_far_from_right = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

