#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_dist = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' character encountered, or -1 for cell 0.

        // The frog starts at cell 0.
        // The first jump is from cell 0. It can jump to any cell in [1, min(n+1, d)].
        // The distance from 0 to the first 'R' cell (or n+1 if no 'R's) determines a lower bound for d.
        // We need to find the maximum gap between consecutive 'R's (or 0 and first 'R', or last 'R' and n+1).

        // Consider the jump from cell 0. It must reach the first 'R' cell or n+1.
        // The distance from 0 to the first 'R' cell (1-indexed) is (first_R_idx - 0).
        // If there are no 'R's, the frog must jump from 0 to n+1, so d must be at least n+1.
        // If there are 'R's, the frog must jump from 0 to the first 'R' cell.
        // The distance from cell 0 to cell `i` is `i`.
        // So, the distance from 0 to the first 'R' cell (let's say at index `i` in string, so cell `i+1`) is `i+1`.
        // This is covered by `last_r_pos = -1` and `i` being the index of the first 'R'.
        // The distance is `(i+1) - (-1+1) = i+1`.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current 'R' is at cell (i+1).
                // Previous 'R' (or start) was at cell (last_r_pos + 1).
                // The distance between these two cells is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                max_dist = std::max(max_dist, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' cell to cell (n+1).
        // The last 'R' was at cell (last_r_pos + 1).
        // The target is cell (n+1).
        // The distance is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_dist = std::max(max_dist, n - last_r_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs 3 students).
        // So, the number of teams 'k' must satisfy:
        // k <= c
        // k <= m
        // 3 * k <= c + m + x

        // From the first two conditions, k <= min(c, m).
        // Let's try to find the maximum k that satisfies all conditions.
        // The maximum possible value for k is min(c, m, (c + m + x) / 3).
        // However, this is not quite right because the 'x' students can only fill
        // the "third" slot in a team, or additional slots if c or m are abundant.

        // A more robust approach is to use binary search for the answer.
        // The number of teams 'k' can range from 0 to 10^8 (max c, m, x).
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // An upper bound for k
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // This uses 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining unspecialized students: x

            // Total students available for the "third" slots (or additional coder/mathematician slots):
            // (c - mid) + (m - mid) + x

            // Each of the 'mid' teams needs 3 members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' more members to fill the remaining slots in these 'mid' teams.
            // These 'mid' members can come from the remaining coders, mathematicians, or unspecialized students.

            if ((c - mid) + (m - mid) + x >= mid) {
                // If we have enough remaining students to fill the 'mid' additional slots,
                // then 'mid' teams are possible. Try for more.
                ans = mid;
                low = mid + 1;
            } else {
                // Not enough students for 'mid' teams. Try for fewer.
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

