int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int k = 1; k < n; ++k) {
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 1; // Cost for a staircase with 1 stair
        long long sum_of_powers_of_2 = 1; // Sum of 2^0

        while (true) {
            if (x >= current_cost) {
                x -= current_cost;
                count++;
            } else {
                break;
            }

            // Calculate cost for the next nice staircase
            // If current staircase has n stairs, the next one has 2n+1 stairs.
            // The cost for n stairs is sum of squares of 1, 2, 4, ..., 2^k where n = 2^(k+1)-1.
            // The cost for 2n+1 stairs is sum of squares of 1, 2, 4, ..., 2^k, 2^(k+1).
            // So, the additional cost is (2^(k+1))^2.
            // The sum of powers of 2 for the side lengths is 1 + 2 + 4 + ... + 2^k.
            // For the next staircase, this sum becomes 1 + 2 + 4 + ... + 2^k + 2^(k+1).
            // So, sum_of_powers_of_2 becomes sum_of_powers_of_2 * 2 + 1.

            // The next staircase will have 2 * (current number of stairs) + 1 stairs.
            // The number of stairs for the current staircase is sum_of_powers_of_2.
            // So, the next staircase will have 2 * sum_of_powers_of_2 + 1 stairs.
            // The cost of a staircase with N stairs is N * (N+1) / 2.
            // However, we are using the property of nice staircases.
            // A nice staircase with n stairs (where n = 2^k - 1) has cost sum_{i=0}^{k-1} (2^i)^2.
            // Let S_k be the cost for a staircase with 2^k - 1 stairs.
            // S_k = 1^2 + 2^2 + ... + (2^(k-1))^2.
            // S_{k+1} = S_k + (2^k)^2.
            // The variable `current_cost` stores S_k.
            // The variable `sum_of_powers_of_2` stores 2^k - 1 (the number of stairs).
            // No, `sum_of_powers_of_2` stores 1 + 2 + 4 + ... + 2^(k-1).
            // The number of stairs is `sum_of_powers_of_2`.
            // The next number of stairs is `2 * sum_of_powers_of_2 + 1`.
            // The cost for the next staircase is `current_cost + (sum_of_powers_of_2 * 2 + 1)^2`.
            // This is incorrect.
            // The cost for a staircase with N stairs is N*(N+1)/2.
            // For a nice staircase, N is of the form 2^k - 1.
            // Let's track the number of stairs `n_stairs` and the cost `cost_n`.
            // Initially, n_stairs = 1, cost_n = 1.
            // Next, n_stairs = 3, cost_n = 1 + 2^2 = 5.
            // Next, n_stairs = 7, cost_n = 5 + 4^2 = 21.
            // Next, n_stairs = 15, cost_n = 21 + 8^2 = 85.
            // The pattern for `n_stairs` is `n_stairs = n_stairs * 2 + 1`.
            // The pattern for `cost_n` is `cost_n = cost_n + (n_stairs_old + 1)^2`.
            // Where `n_stairs_old` is the number of stairs for the previous staircase.
            // Let `prev_n_stairs` be the number of stairs for the current staircase.
            // The next staircase will have `next_n_stairs = prev_n_stairs * 2 + 1` stairs.
            // The cost for the next staircase will be `current_cost + (prev_n_stairs + 1)^2`.
            // Let's re-evaluate `sum_of_powers_of_2`.
            // `sum_of_powers_of_2` is `1, 3, 7, 15, ...` which is `2^k - 1`.
            // `current_cost` is `1, 5, 21, 85, ...`.
            // The next term to add to `current_cost` is `(sum_of_powers_of_2 + 1)^2`.
            // `sum_of_powers_of_2` is `2^k - 1`. So `sum_of_powers_of_2 + 1` is `2^k`.
            // So we add `(2^k)^2`.
            // `sum_of_powers_of_2` for the next iteration becomes `sum_of_powers_of_2 * 2 + 1`.

            long long term_to_square = sum_of_powers_of_2 + 1; // This is 2^k
            sum_of_powers_of_2 = sum_of_powers_of_2 * 2 + 1; // This is 2^(k+1) - 1
            current_cost = current_cost + term_to_square * term_to_square; // This is S_{k+1}
        }
        std::cout << count << "\n";
    }
    return 0;
}

