    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int target_open = k / 2;
    int target_close = k / 2;

    for (char c : s) {
        if (c == '(') {
            if (open_count < target_open) {
                result += '(';
                open_count++;
            }
        } else { // c == ')'
            if (close_count < target_close && open_count > close_count) {
                result += ')';
                close_count++;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of multiples of m up to n

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Precompute last digits for multiples of m up to 10m
        // The cycle of last digits of (i * m) % 10 has a length of at most 10.
        // Specifically, it's the cycle of (i * (m % 10)) % 10.
        // The sequence of last digits (m%10, 2m%10, ..., 10m%10) will always contain a full cycle.
        // For example, if m=2, last digits are 2,4,6,8,0,2,4,6,8,0. Cycle length 5.
        // If m=5, last digits are 5,0,5,0,5,0,5,0,5,0. Cycle length 2.
        // If m=1, last digits are 1,2,3,4,5,6,7,8,9,0. Cycle length 10.
        // The sum of last digits for i=1 to 10 is always a full cycle sum.

        std::vector<long long> cycle_digits(10);
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_digits[i - 1] = (static_cast<long long>(i) * m) % 10;
            cycle_sum += cycle_digits[i - 1];
        }

        long long num_full_cycles = k / 10;
        long long remaining_elements = k % 10;

        long long total_sum = num_full_cycles * cycle_sum;

        for (int i = 0; i < remaining_elements; ++i) {
            total_sum += cycle_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
