#include <string>
#include <algorithm> // For std::min and std::max

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subsegment is just [1] at pos[1].
    // min_idx = pos[1], max_idx = pos[1].
    // min_val = 1, max_val = 1.
    // Length = max_idx - min_idx + 1 = 1.
    // Condition: max_val - min_val + 1 == length.
    // 1 - 1 + 1 == 1. True.
    // So m=1 is always beautiful.
    ans[0] = '1';

    // Initialize current min and max indices for the segment containing 1 to current_m.
    // For m=1, this segment is just p[pos[1]].
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // When considering m, we need to extend the current segment
        // (which contains 1 to m-1) to also include m.
        // The new number m is at pos[m].
        // We update current_min_idx and current_max_idx to cover the range
        // from min(pos[1...m]) to max(pos[1...m]).
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if there exists a subsegment p[l...r]
        // that is a permutation of 1, 2, ..., m.
        // This implies three conditions:
        // 1. The subsegment must contain all numbers from 1 to m.
        //    The smallest possible segment containing all numbers from 1 to m
        //    is p[current_min_idx ... current_max_idx].
        // 2. The maximum value in this subsegment must be m.
        //    By construction, current_max_idx and current_min_idx are updated
        //    to include all numbers up to m. The maximum value in p[current_min_idx ... current_max_idx]
        //    will be m (assuming p is a permutation and we're building up from 1).
        // 3. The length of the subsegment must be exactly m.
        //    Length = current_max_idx - current_min_idx + 1.
        //    If this length equals m, then the segment p[current_min_idx ... current_max_idx]
        //    contains exactly m distinct numbers (1 to m) and no other numbers.
        //    Thus, it is a permutation of 1 to m.

        if (current_max_idx - current_min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }

    std::cout << ans << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_good(const std::vector<int>& b) {
    int m = b.size();
    if (m <= 1) {
        return true;
    }

    // Find the peak (maximum element) in the array.
    // If there are multiple peaks with the same maximum value,
    // any of them can be considered the "peak" for this logic.
    // We are looking for the point where the array stops decreasing
    // from the right and starts increasing towards the right.
    // Or, stops increasing from the left and starts decreasing towards the left.

    // Find the rightmost point where the array is non-increasing from the right.
    // This means a[i] >= a[i+1]
    int right_idx = m - 1;
    while (right_idx > 0 && b[right_idx - 1] >= b[right_idx]) {
        right_idx--;
    }
    // After this loop, b[right_idx] is the first element from the right
    // such that b[right_idx-1] < b[right_idx] (if right_idx > 0).
    // Or, right_idx is 0 if the whole array is non-increasing.

    // Find the leftmost point where the array is non-decreasing from the left.
    // This means a[i] <= a[i+1]
    int left_idx = 0;
    while (left_idx < m - 1 && b[left_idx] <= b[left_idx + 1]) {
        left_idx++;
    }
    // After this loop, b[left_idx] is the first element from the left
    // such that b[left_idx] > b[left_idx+1] (if left_idx < m-1).
    // Or, left_idx is m-1 if the whole array is non-decreasing.

    // The array is good if the "decreasing from right" part
    // and the "increasing from left" part meet or overlap.
    // This means the elements from index 0 to left_idx form a non-decreasing sequence,
    // and elements from right_idx to m-1 form a non-increasing sequence.
    // For the array to be good, these two "monotonic" parts must cover the entire array.
    // That is, the "peak" must be somewhere between left_idx and right_idx.
    // More precisely, the condition is that the index where the array stops increasing
    // from the left (left_idx) must be greater than or equal to the index where
    // the array stops decreasing from the right (right_idx).
    // If left_idx >= right_idx, it means the array can be partitioned into
    // a non-decreasing prefix and a non-increasing suffix, which is the condition for being good.
    return left_idx >= right_idx;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is a candidate for a good array.
    // This means we are looking for the longest suffix that could potentially be good.
    // The logic for `is_good` is based on finding the "peak" structure.
    // We need to find the first index `i` from the right such that `a[i]` breaks the
    // non-increasing sequence from the right, and then the first index `j` from `i`
    // to the left such that `a[j]` breaks the non-decreasing sequence.
    // The prefix to remove would be `j`.

    // Step 1: Find the rightmost index `i` such that `a[i...n-1]` is non-increasing.
    // This means `a[k] >= a[k+1]` for `k` from `i` to `n-2`.
    // We iterate from `n-2` down to `0`.
    int i = n - 1; // `i` is the start of the non-increasing suffix
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, `a[i...n-1]` is non-increasing.
    // If `i` is 0, the whole array is non-increasing.

    // Step 2: From `i`, find the rightmost index `j` such that `a[j...i-1]` is non-decreasing.
    // This means `a[k] <= a[k+1]` for `k` from `j` to `i-2`.
    // We iterate from `i-1` down to `0`.
    int j = i; // `j` is the start of the non-decreasing part before the non-increasing part
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, `a[j...i-1]` is non-decreasing.
    // If `j` is 0, then `a[0...i-1]` is non-decreasing.

    // The length of the prefix to erase is `j`.
    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2;

    // First, ensure the median element itself is s
    operations += std::abs(a[mid_idx] - s);

    // Ensure elements to the left of median are <= s
    // If a[i] > s, we must decrease it to s.
    // If a[i] <= s, it's fine, no operations needed for this condition.
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Ensure elements to the right of median are >= s
    // If a[i] < s, we must increase it to s.
    // If a[i] >= s, it's fine, no operations needed for this condition.
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
    } else {
        // Box 1: (-inf, -1]
        // Final toy must be negative and magnitude >= 1
        // This requires an odd number of negative factors.
        // And at least one factor with magnitude >= 1, or multiple factors with magnitude > 1/x.
        // To guarantee magnitude >= 1, we need to be able to produce a value >= 1 or <= -1.
        // This is possible if we can produce a negative value.
        // The total number of negative toys (A+B) must be odd.
        // If A+B is odd, we can always make the final sign negative.
        // To make magnitude >= 1:
        // If A > 0 or D > 0, we have toys with magnitude >= 1.
        // If A+B is odd, and (A > 0 or D > 0), then Box 1 is possible.
        // What if A=0, D=0? Then all toys are in B and C.
        // If A+B is odd, and A=0, D=0, then B must be odd.
        // If B is odd, and C can be anything, the final product will be negative.
        // But all initial magnitudes are < 1. The product of values < 1 will always be < 1.
        // So if A=0 and D=0, Box 1 is impossible.
        // Therefore, Box 1 is possible if (A+B) is odd AND (A > 0 or D > 0).
        if ((A + B) % 2 != 0 && (A > 0 || D > 0)) {
            ans1 = "Ya";
        }

        // Box 2: (-1, 0)
        // Final toy must be negative and magnitude < 1
        // This requires an odd number of negative factors.
        // And all factors must be able to result in a product with magnitude < 1.
        // This is always possible if we can produce a negative value.
        // If A+B is odd, we can always make the final sign negative.
        // To make magnitude < 1:
        // If B > 0 or C > 0, we have toys with magnitude < 1.
        // We can always pick values close to 0 for B and C toys.
        // If A+B is odd, then Box 2 is possible.
        // Exception: If A+B is odd, but B=0, C=0. Then all toys are in A and D.
        // If A+B is odd, and B=0, C=0, then A must be odd.
        // If A is odd, and D can be anything, the final product will be negative.
        // But all initial magnitudes are >= 1. The product of values >= 1 will always be >= 1.
        // So if B=0 and C=0, Box 2 is impossible.
        // Therefore, Box 2 is possible if (A+B) is odd AND (B > 0 || C > 0).
        if ((A + B) % 2 != 0 && (B > 0 || C > 0)) {
            ans2 = "Ya";
        }

        // Box 3: (0, 1)
        // Final toy must be positive and magnitude < 1
        // This requires an even number of negative factors.
        // And all factors must be able to result in a product with magnitude < 1.
        // This is always possible if we can produce a positive value.
        // If A+B is even, we can always make the final sign positive.
        // To make magnitude < 1:
        // If B > 0 or C > 0, we have toys with magnitude < 1.
        // We can always pick values close to 0 for B and C toys.
        // If A+B is even, then Box 3 is possible.
        // Exception: If A+B is even, but B=0, C=0. Then all toys are in A and D.
        // If A+B is even, and B=0, C=0, then A must be even.
        // If A is even, and D can be anything, the final product will be positive.
        // But all initial magnitudes are >= 1. The product of values >= 1 will always be >= 1.
        // So if B=0 and C=0, Box 3 is impossible.
        // Therefore, Box 3 is possible if (A+B) % 2 == 0 && (B > 0 || C > 0).
        if ((A + B) % 2 == 0 && (B > 0 || C > 0)) {
            ans3 = "Ya";
        }

        // Box 4: [1, inf)
        // Final toy must be positive and magnitude >= 1
        // This requires an even number of negative factors.
        // And at least one factor with magnitude >= 1, or multiple factors with magnitude > 1/x.
        // To guarantee magnitude >= 1, we need to be able to produce a value >= 1 or <= -1.
        // This is possible if we can produce a positive value.
        // If A+B is even, we can always make the final sign positive.
        // To make magnitude >= 1:
        // If A > 0 or D > 0, we have toys with magnitude >= 1.
        // If A+B is even, and (A > 0 or D > 0), then Box 4 is possible.
        // What if A=0, D=0? Then all toys are in B and C.
        // If A+B is even, and A=0, D=0, then B must be even.
        // If B is even, and C can be anything, the final product will be positive.
        // But all initial magnitudes are < 1. The product of values < 1 will always be < 1.
        // So if A=0 and D=0, Box 4 is impossible.
        // Therefore, Box 4 is possible if (A+B) % 2 == 0 && (A > 0 || D > 0).
        if ((A + B) % 2 == 0 && (A > 0 || D > 0)) {
            ans4 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

