// Function to check if a prefix of length `len` is a permutation
// `a` is the input array (0-indexed)
// `len` is the length of the prefix
// `max_val_prefix` is the maximum value in the prefix
// `counts_prefix` stores frequency counts for elements in the prefix
bool is_permutation_prefix(int len, int max_val_prefix, const std::vector<int>& counts_prefix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_val_prefix != len) return false;
    for (int i = 1; i <= len; ++i) {
        if (counts_prefix[i] != 1) {
            return false;
        }
    }
    return true;
}

// Function to check if a suffix of length `len` is a permutation
// `a` is the input array (0-indexed)
// `start_idx` is the starting index of the suffix
// `len` is the length of the suffix
// `max_val_suffix` is the maximum value in the suffix
// `counts_suffix` stores frequency counts for elements in the suffix
bool is_permutation_suffix(int start_idx, int len, int max_val_suffix, const std::vector<int>& counts_suffix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_val_suffix != len) return false;
    for (int i = 1; i <= len; ++i) {
        if (counts_suffix[i] != 1) {
            return false;
        }
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<int> counts_prefix(n + 1, 0);
    int max_val_prefix = 0;
    for (int l1 = 1; l1 < n; ++l1) {
        int val = a[l1 - 1];
        counts_prefix[val]++;
        if (counts_prefix[val] > 1) { // Duplicate found, cannot be a permutation
            break;
        }
        max_val_prefix = std::max(max_val_prefix, val);
        if (max_val_prefix == l1) { // Max value matches length, potential permutation
            is_prefix_perm[l1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<int> counts_suffix(n + 1, 0);
    int max_val_suffix = 0;
    for (int l2 = 1; l2 < n; ++l2) {
        int val = a[n - l2];
        counts_suffix[val]++;
        if (counts_suffix[val] > 1) { // Duplicate found, cannot be a permutation
            break;
        }
        max_val_suffix = std::max(max_val_suffix, val);
        if (max_val_suffix == l2) { // Max value matches length, potential permutation
            is_suffix_perm[l2] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<long long> L(n);
    L[0] = 0; // a'_0 must be 0 for a'_0 < a'_1
    for (int i = 1; i < n; ++i) {
        L[i] = std::min(a[i], L[i-1] + 1);
    }

    std::vector<long long> R(n);
    R[n-1] = 0; // a'_{n-1} must be 0 for a'_{n-1} < a'_{n-2} (if n-1 is not k)
    for (int i = n - 2; i >= 0; --i) {
        R[i] = std::min(a[i], R[i+1] + 1);
    }

    for (int k = 0; k < n; ++k) {
        // For a given k (0-indexed), we need:
        // a'_0 < a'_1 < ... < a'_k
        // a'_k > a'_{k+1} > ... > a'_{n-1}
        //
        // The values a'_i must be non-negative.
        //
        // From the left, we need a'_i >= i.
        // So, a'_k must be at least k.
        //
        // From the right, we need a'_i >= (n-1-i).
        // So, a'_k must be at least (n-1-k).
        //
        // Combining these, a'_k must be at least max(k, n-1-k).
        //
        // Our L[k] represents the maximum possible value for a'_k
        // such that a'_0 < ... < a'_k and a'_i >= i for i <= k.
        // Specifically, L[k] is the largest value such that we can form
        // 0, 1, ..., L[k] using a_0, ..., a_k.
        //
        // Similarly, R[k] represents the maximum possible value for a'_k
        // such that a'_k > ... > a'_{n-1} and a'_i >= (n-1-i) for i >= k.
        // Specifically, R[k] is the largest value such that we can form
        // R[k], R[k]-1, ..., 0 using a_k, ..., a_{n-1}.
        //
        // If we can find a k such that L[k] >= k AND R[k] >= (n-1-k),
        // then we can construct the sharpened array.
        // The peak value a'_k can be chosen as min(L[k], R[k]).
        // If min(L[k], R[k]) is large enough to satisfy both conditions,
        // i.e., min(L[k], R[k]) >= k AND min(L[k], R[k]) >= (n-1-k),
        // then it's possible.
        // This simplifies to L[k] >= k AND R[k] >= (n-1-k).
        //
        // Example: a = [100, 11, 15, 9, 7, 8], n=6
        // L = [0, 1, 2, 3, 4, 5]
        // R = [5, 4, 3, 2, 1, 0]
        //
        // k=0: L[0]=0, R[0]=5. Need L[0]>=0, R[0]>=5. Both true. Yes.
        // k=1: L[1]=1, R[1]=4. Need L[1]>=1, R[1]>=4. Both true. Yes.
        // k=2: L[2]=2, R[2]=3. Need L[2]>=2, R[2]>=3. Both true. Yes.
        // k=3: L[3]=3, R[3]=2. Need L[3]>=3, R[3]>=2. Both true. Yes.
        // k=4: L[4]=4, R[4]=1. Need L[4]>=4, R[4]>=1. Both true. Yes.
        // k=5: L[5]=5, R[5]=0. Need L[5]>=5, R[5]>=0. Both true. Yes.
        //
        // The condition is simply L[k] >= k and R[k] >= (n-1-k).
        // This is because L[k] is the maximum possible value for a'_k
        // given the prefix constraints (a'_i = i for i < k, a'_k = L[k]).
        // And R[k] is the maximum possible value for a'_k
        // given the suffix constraints (a'_i = n-1-i for i > k, a'_k = R[k]).
        // If L[k] >= k, it means we can achieve a prefix 0, 1, ..., k.
        // If R[k] >= (n-1-k), it means we can achieve a suffix k, k-1, ..., 0.
        // If both are true, we can pick a'_k = k and form the array.
        //
        // More precisely, L[k] is the maximum value `v` such that we can form
        // `0, 1, ..., v` using `a_0, ..., a_k`.
        // R[k] is the maximum value `v` such that we can form
        // `v, v-1, ..., 0` using `a_k, ..., a_{n-1}`.
        //
        // For a peak at index k, we need to be able to form `0, 1, ..., P`
        // for the left part and `P, P-1, ..., 0` for the right part,
        // where P is the peak value.
        // This means we need `L[k] >= P` and `R[k] >= P`.
        // Also, P must be at least `k` (for the left part) and at least `n-1-k` (for the right part).
        // So, we need to find a `k` such that `L[k] >= k` and `R[k] >= (n-1-k)`.
        // If such a `k` exists, we can choose `P = std::max(k, n-1-k)`.
        // Then `L[k] >= P` and `R[k] >= P` would imply it's possible.
        //
        // Let's re-evaluate the definition of L and R.
        // L[i] = max value for a'_i such that a'_0 < ... < a'_i.
        // L[0] = a[0].
        // L[i] = min(a[i], L[i-1]+1). This is correct.
        // R[i] = max value for a'_i such that a'_i > ... > a'_{n-1}.
        // R[n-1] = a[n-1].
        // R[i] = min(a[i], R[i+1]+1). This is correct.
        //
        // For a peak at index k, we need a'_k to be some value P.
        // We need a'_0 < ... < a'_k = P. This means P must be at least k.
        // And we need a'_k = P > a'_{k+1} > ... > a'_{n-1}. This means P must be at least (n-1-k).
        // So, P >= max(k, n-1-k).
        //
        // To achieve a peak P at index k, we need:
        // 1. a_i >= i for i <= k (to form 0, 1, ..., k)
        // 2. a_i >= (n-1-i) for i >= k (to form n-1-k, ..., 0)
        //
        // The L[k] value calculated is the maximum possible value for a'_k
        // if we try to make a'_i = i for i < k and a'_k = L[k].
        // So, if L[k] >= k, it means we can achieve 0, 1, ..., k.
        //
        // The R[k] value calculated is the maximum possible value for a'_k
        // if we try to make a'_i = n-1-i for i > k and a'_k = R[k].
        // So, if R[k] >= (n-1-k), it means we can achieve (n-1-k), ..., 0.
        //
        // If both L[k] >= k and R[k] >= (n-1-k) are true, then we can form
        // 0, 1, ..., k, ..., 0.
        // The peak value would be k.
        //
        // Let's re-check the example: a = [100, 11, 15, 9, 7, 8], n=6
        // L:
        // L[0] = a[0] = 100
        // L[1] = min(a[1], L[0]+1) = min(11, 101) = 11
        // L[2] = min(a[2], L[1]+1) = min(15, 12) = 12
        // L[3] = min(a[3], L[2]+1) = min(9, 13) = 9
        // L[4] = min(a[4], L[3]+1) = min(7, 10) = 7
        // L[5] = min(a[5], L[4]+1) = min(8, 8) = 8
        // L = [100, 11, 12, 9, 7, 8]
        //
        // R:
        // R[5] = a[5] = 8
        // R[4] = min(a[4], R[5]+1) = min(7, 9) = 7
        // R[3] = min(a[3], R[4]+1) = min(9, 8) = 8
        // R[2] = min(a[2], R[3]+1) = min(15, 9) = 9
        // R[1] = min(a[1], R[2]+1) = min(11, 10) = 10
        // R[0] = min(a[0], R[1]+1) = min(100, 11) = 11
        // R = [11, 10, 9, 8, 7, 8]
        //
        // Now check condition: L[k] >= k AND R[k] >= (n-1-k)
        // k=0: L[0]=100 >= 0, R[0]=11 >= 5. False (11 < 5 is false, 11 >= 5 is true).
        // k=1: L[1]=11 >= 1, R[1]=10 >= 4. True.
        // k=2: L[2]=12 >= 2, R[2]=9 >= 3. True.
        // k=3: L[3]=9 >= 3, R[3]=8 >= 2. True.
        // k=4: L[4]=7 >= 4, R[4]=7 >= 1. True.
        // k=5: L[5]=8 >= 5, R[5]=8 >= 0. True.
        //
        // Since k=1 satisfies the condition, output Yes.
        // This logic seems correct.

        if (L[k] >= k && R[k] >= (n - 1 - k)) {
            std::cout << "Yes\n";
            return;
        }
    }

    std::cout << "No\n";
}

