int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // Condition: current_sum = 2 * current_xor_sum
        // If already good, append 0 elements.
        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
        } else {
            // We need to append at most 3 elements.
            // Let's try to append 2 elements.
            // We want (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)
            // Let b1 = current_xor_sum.
            // Then current_xor_sum ^ b1 = current_xor_sum ^ current_xor_sum = 0.
            // The equation becomes (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2)
            // (current_sum + current_xor_sum + b2) = 2 * b2
            // current_sum + current_xor_sum = b2
            // So, b2 = current_sum + current_xor_sum.

            // Let's verify this.
            // New sum S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
            // S' = 2 * (current_sum + current_xor_sum)
            // New XOR sum X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
            // X' = 0 ^ (current_sum + current_xor_sum)
            // X' = current_sum + current_xor_sum
            // So, S' = 2 * X'. This works.

            long long b1 = current_xor_sum;
            long long b2 = current_sum + current_xor_sum;

            std::cout << 2 << "\n";
            std::cout << b1 << " " << b2 << "\n";
        }
    }
    return 0;
}

