    }

    long long total_pairs = 0;

    // Count pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Count pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs with same (x, y) coordinates (counted twice)
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // Step 1: Use s_i = '0' to determine necessary '0's in w
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s_i is '0', then both w_{i-x} and w_{i+x} must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will be the s generated from our w
    for (int i = 0; i < n; ++i) {
        bool found_one = false;
        // Check w_{i-x}
        if (i - x >= 0 && w[i - x] == '1') {
            found_one = true;
        }
        // Check w_{i+x}
        if (i + x < n && w[i + x] == '1') {
            found_one = true;
        }
        if (found_one) {
            s_prime[i] = '1';
        }
    }

    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

