#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
// e.g., 241 -> "001" (padded to 18 digits: "000000000000000001")
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to a fixed length (18 for max 10^18-1)
    // The problem states "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // And "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // This means we should normalize both to a common length. Max length is 18.
    // Since we build the string from right to left, we need to reverse it and then pad.
    // However, the problem states "i-th from the right digit".
    // So, 241 -> 1 (rightmost) is odd, 4 is even, 2 is even. Pattern is 001.
    // If we build it as "100" and then reverse, it's "001".
    // If we pad "001" to 18 digits, it becomes "000000000000000001".
    // This is equivalent to building it directly from right to left and padding.
    // Example: 241.
    // n=241, n%10=1 (odd) -> pattern_str="1"
    // n=24, n%10=4 (even) -> pattern_str="10"
    // n=2, n%10=2 (even) -> pattern_str="100"
    // After loop, pattern_str="100".
    // We need to reverse it to get "001" for comparison.
    // But if we pad first, then reverse, it's easier.
    // Let's just pad to 18 digits.
    // The pattern matching is "i-th from the right digit".
    // So, 241 -> 1 (rightmost) is odd, 4 is even, 2 is even.
    // The pattern for 241 is effectively "001".
    // If we store "001" and query for "010", we compare:
    // 1 vs 0 (mismatch)
    // 0 vs 1 (mismatch)
    // 0 vs 0 (match)
    // This means we should store the pattern as it is, from right to left.
    // So, 241 -> "100" (rightmost digit first).
    // Then pad to 18 digits: "100000000000000000".
    // And query pattern "010" should also be padded: "010000000000000000".
    // This way, we compare character by character.

    // Let's re-evaluate the example: s = 010.
    // 92: 2 (even) -> 0, 9 (odd) -> 1. Pattern for 92 is "01".
    // 2212: 2 (even) -> 0, 1 (odd) -> 1, 2 (even) -> 0, 2 (even) -> 0. Pattern for 2212 is "0100".
    // 50: 0 (even) -> 0, 5 (odd) -> 1. Pattern for 50 is "01".
    // 414: 4 (even) -> 0, 1 (odd) -> 1, 4 (even) -> 0. Pattern for 414 is "010".

    // The example says: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left.
    // Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies normalization to a common length, and then comparison.
    // The example `s = 010` matches `92`.
    // `92` (decimal) -> `01` (parity pattern).
    // `s = 010`.
    // Normalized to length 3 (max of 2 and 3):
    // `92` -> `092` -> `010` (parity pattern)
    // `s = 010`
    // They match.

    // So, the strategy is:
    // 1. Convert number to its parity pattern string.
    // 2. Pad this string with '0's from the LEFT to a fixed length (e.g., 18).
    // 3. Store this fixed-length string.
    // 4. For query pattern, pad it with '0's from the LEFT to the same fixed length.
    // 5. Use map<string, int> to store counts.

    std::string result = "";
    if (n == 0) {
        result = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                result += '0';
            } else { // Odd digit
                result += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long.
    // This effectively pads the original number with '0's from the left.
    // Example: 241 -> "100" (rightmost digit first).
    // Pad to 18: "100000000000000000".
    // Example: 92 -> "01" (rightmost digit first).
    // Pad to 18: "010000000000000000".
    // Example: 0 -> "0". Pad to 18: "000000000000000000".
    while (result.length() < 18) {
        result += '0';
    }
    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the right to make it 18 characters long.
            // This corresponds to padding the original pattern with '0's from the left.
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

