// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must have at least a_i factors of f_i for all i.
        // To make x not divisible by q, we need to remove enough factors of some f_i from p
        // such that the resulting x has fewer than a_i factors of f_i.
        // To maximize x, we should remove the minimum necessary factors.
        // This means for each prime factor f_i of q, we try to form x by dividing p by f_i
        // until x is no longer divisible by q (specifically, until x has fewer than a_i factors of f_i).
        // The largest such x will be the answer.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q.
            // This means current_p will have fewer factors of 'factor' than q.
            while (current_p % q == 0) {
                current_p /= factor;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int k = 0; k <= 9; ++k) {
        std::string coloring(n, ' ');
        std::vector<char> s1_digits;
        std::vector<char> s2_digits;
        bool possible_k = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit - '0' < k) {
                coloring[i] = '1';
                s1_digits.push_back(digit);
            } else if (digit - '0' > k) {
                coloring[i] = '2';
                s2_digits.push_back(digit);
            } else { // digit - '0' == k
                // This is the tricky part. Digits equal to k can go to either S1 or S2.
                // To maintain non-decreasing order, if we put k into S1, it must be >= last S1 digit.
                // If we put k into S2, it must be >= last S1 digit (if S1 is not empty) and >= last S2 digit.
                // The strategy is to put all 'k's that appear before the first 'k' that is forced into S2 into S1.
                // And all 'k's that appear after or at the first 'k' forced into S2, into S2.
                // The first 'k' that is forced into S2 is the one that appears after some digit > k has already been assigned to S2.
                // Or, more simply, we can find the first occurrence of 'k' that we *must* assign to color 2.
                // This happens if a digit 'k' appears after a digit 'k' that was already assigned to color 2.
                // Or, if a digit 'k' appears after a digit 'k' that was assigned to color 1, and then a digit 'k' appears after that,
                // and we need to assign it to color 2.
                // Let's try a simpler greedy approach for digits equal to k:
                // Assign '1' if possible, otherwise '2'.
                // 'Possible' means it doesn't violate s1_digits non-decreasing property.
                // If s1_digits is empty or digit >= s1_digits.back(), assign to '1'.
                // Otherwise, assign to '2'.
                // This greedy choice for 'k's is what makes the solution work.
                if (s1_digits.empty() || digit >= s1_digits.back()) {
                    coloring[i] = '1';
                    s1_digits.push_back(digit);
                } else {
                    coloring[i] = '2';
                    s2_digits.push_back(digit);
                }
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 1; i < s1_digits.size(); ++i) {
            if (s1_digits[i] < s1_digits[i-1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 1; i < s2_digits.size(); ++i) {
            if (s2_digits[i] < s2_digits[i-1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if last S1 digit <= first S2 digit
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_k = false;
            }
        }

        if (possible_k) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

