#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];

        adj[c1].insert(c2);
        adj[c2].insert(c1);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::set<char> visited;
    char start_char = '\0';

    // Find a starting character for a chain (degree 1 or first char of s if all degree 2)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If all characters involved in the password have degree 2 (e.g., 'ababa'),
    // or if the password is just one character, pick the first character of s.
    // If no character has degree 1, it means all connected components are cycles or isolated nodes.
    // For a valid layout, we need a path.
    // If all characters in 's' have degree 2, it means 's' forms a cycle.
    // We can still pick any character from 's' as a starting point.
    if (start_char == '\0' && !s.empty()) {
        start_char = s[0];
    } else if (s.empty()) { // Should not happen based on constraints |s| >= 1
        start_char = 'a'; // Default for empty string, though not needed
    }


    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the first step

        while (visited.find(current) == visited.end()) {
            layout += current;
            visited.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
            if (current == '\0' && adj[prev].size() == 2 && visited.find(*adj[prev].begin()) != visited.end() && visited.find(*adj[prev].rbegin()) != visited.end()) {
                // This means we've completed a cycle and current is not set,
                // but both neighbors are already visited. This is fine, we just stop.
                break;
            }
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    if (layout.length() != 26) {
        std::cout << "NO\n"; // Should not happen if logic is correct, but as a safeguard
    } else {
        std::cout << "YES\n";
        std::cout << layout << "\n";
    }
}

