int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    double total_win_prob = 0.0;

    // Iterate over all possible initial shifts k_orig (Kolya's choice)
    for (int k_orig = 0; k_orig < L; ++k_orig) {
        char char0_observed = s[k_orig]; // t[0] = s[k_orig]

        double max_win_prob_for_k_orig = 0.0;

        // Vasya chooses j to maximize his win probability for this k_orig
        for (int j = 1; j < L; ++j) {
            char charj_observed = s[(k_orig + j) % L]; // t[j] = s[(k_orig + j) % L]

            // Count how many k' values are consistent with (char0_observed, charj_observed)
            int consistent_k_count = 0;
            for (int k_prime = 0; k_prime < L; ++k_prime) {
                if (s[k_prime] == char0_observed && s[(k_prime + j) % L] == charj_observed) {
                    consistent_k_count++;
                }
            }

            // If only one k' is consistent, Vasya wins for this (k_orig, j) pair
            if (consistent_k_count == 1) {
                max_win_prob_for_k_orig = std::max(max_win_prob_for_k_orig, 1.0);
                // If Vasya can win for sure with some j, he will pick that j.
                // No need to check other j's for this k_orig.
                break; 
            }
        }
        total_win_prob += max_win_prob_for_k_orig;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

