int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    for (int i = 0; i < n; ++i) {
        int block_idx = i / k;
        int start_val = (block_idx + 1) * k;
        int val_in_block = start_val - (i % k);

        if (val_in_block > n) {
            val_in_block = n - (i % k);
            // This adjustment is for the last block if it's not full.
            // The values should be n, n-1, ..., (n - (n%k) + 1)
            // The first element of the last block is (block_idx * k) + 1.
            // The values are (block_idx * k) + k, (block_idx * k) + k - 1, ..., (block_idx * k) + 1
            // But we need to cap them at n.
            // So if block_idx * k + k > n, then the values are n, n-1, ..., (block_idx * k) + 1
            // The current value is (block_idx * k) + k - (i % k)
            // If this is > n, we need to adjust.
            // The actual value should be n - (i - block_idx * k)
            val_in_block = n - (i - block_idx * k);
        }

        std::cout << val_in_block << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

