void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_diff = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // and suffix sums for the right side (jars n+1 to 2n)
    // The values are 1 for strawberry, -1 for blueberry.
    // We want to find L jars removed from left and R jars removed from right
    // such that the remaining jars have a total difference of 0.
    // This means the sum of values of removed jars (L_sum + R_sum) must equal initial_diff.

    // left_diff[k] stores the sum of values of jars 1 to k.
    // This is the difference if k jars are removed from the right side (jars n+1 to 2n)
    // and jars 1 to n are kept.
    // No, this is not correct.
    // Let's define `left_prefix_diff[k]` as the sum of values for jars `1` to `k`.
    // Let's define `right_suffix_diff[k]` as the sum of values for jars `2n-k+1` to `2n`.

    // `left_sums[k]` will store the sum of values of jars `n-k+1` to `n`.
    // This is the sum of values of `k` jars removed from the left side.
    // `left_sums[0]` = 0 (no jars removed from left)
    // `left_sums[k]` = sum(a[n-k]...a[n-1])
    std::map<int, int> left_removed_diff_to_count;
    left_removed_diff_to_count[0] = 0; // 0 jars removed from left, diff is 0

    int current_left_diff = 0;
    for (int k = 1; k <= n; ++k) {
        // Jar n-k+1 is the k-th jar from the right end of the left segment (jars 1 to n)
        // or (n-k)-th index in 0-indexed array.
        // We are removing jars from the left: 1, 2, ..., k.
        // So, current_left_diff is sum of values of jars 1 to k.
        // No, the problem states "first non-empty jar to his left".
        // This means jars 1, 2, ..., L are removed.
        // So, `left_removed_diff[k]` is the sum of values of jars `1` to `k`.
        // `left_removed_diff[k]` = `left_removed_diff[k-1]` + `value(a[k-1])`
        // Let's use 0-indexed array `a`. Jars are `0` to `2n-1`.
        // Karlsson is between `n-1` and `n`.
        // Left jars: `0` to `n-1`. Right jars: `n` to `2n-1`.

        // `left_removed_diff_to_count[diff]` stores the minimum number of jars `k`
        // such that removing `k` jars from the left (jars `0` to `k-1`) results in `diff`.
        // `current_left_diff` will be the sum of values of jars `0` to `k-1`.
        // `k` is the number of jars removed.
        current_left_diff += (a[n - k] == 1 ? 1 : -1);
        if (left_removed_diff_to_count.find(current_left_diff) == left_removed_diff_to_count.end()) {
            left_removed_diff_to_count[current_left_diff] = k;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removed jars

    // Case 1: No jars removed from the right side.
    // We need `current_left_diff` to be equal to `initial_diff`.
    // This means `initial_diff - current_left_diff = 0`.
    // The remaining jars (from `k` to `2n-1`) must have a total difference of 0.
    // This means the sum of values of removed jars must equal the initial total difference.
    // `sum(jars 0 to k-1) + sum(jars 2n-R to 2n-1) = initial_diff`.
    // If R=0, then `sum(jars 0 to k-1) = initial_diff`.
    // We are looking for `diff_removed_left + diff_removed_right = initial_diff`.
    // Or, `diff_remaining = 0`.
    // `diff_remaining = initial_diff - diff_removed_left - diff_removed_right`.
    // So we need `diff_removed_left + diff_removed_right = initial_diff`.

    // Let's re-evaluate.
    // `left_removed_diff_to_count[diff]` stores the minimum `k` such that removing `k` jars from the left
    // (jars `n-k` to `n-1`) results in a sum of `diff`.
    // This is for jars `n-1`, `n-2`, ..., `n-k`.
    // `left_removed_diff_to_count[0] = 0` (0 jars removed from left, sum is 0)
    current_left_diff = 0;
    for (int k = 1; k <= n; ++k) {
        current_left_diff += (a[n - k] == 1 ? 1 : -1); // Sum of jars n-1, n-2, ..., n-k
        if (left_removed_diff_to_count.find(current_left_diff) == left_removed_diff_to_count.end()) {
            left_removed_diff_to_count[current_left_diff] = k;
        }
    }

    // `right_removed_diff_to_count[diff]` stores the minimum `k` such that removing `k` jars from the right
    // (jars `n` to `n+k-1`) results in a sum of `diff`.
    // `right_removed_diff_to_count[0] = 0` (0 jars removed from right, sum is 0)
    // We iterate through possible `k` jars removed from the right.
    // `current_right_diff` will be the sum of values of jars `n` to `n+k-1`.
    // `k` is the number of jars removed.
    current_left_diff = 0; // This variable name is confusing, it's for right side now.
    // This is the sum of values of jars `n` to `n+k-1`.
    // `k` is the number of jars removed from the right.
    // `k=0`: 0 jars removed from right, sum is 0.
    // `k=1`: jar `n` removed. Sum is `value(a[n])`.
    // `k=2`: jars `n`, `n+1` removed. Sum is `value(a[n]) + value(a[n+1])`.
    // ...
    // `k=n`: jars `n` to `2n-1` removed. Sum is `value(a[n]) + ... + value(a[2n-1])`.

    // For each `k` jars removed from the right (jars `n` to `n+k-1`):
    // `current_right_diff` is the sum of values of these `k` jars.
    // We need `current_right_diff + diff_from_left_removed = initial_diff`.
    // So, `diff_from_left_removed = initial_diff - current_right_diff`.
    // We look up `initial_diff - current_right_diff` in `left_removed_diff_to_count`.
    // If found, `k_left = left_removed_diff_to_count[initial_diff - current_right_diff]`.
    // Total removed jars = `k_left + k`.

    // Start with 0 jars removed from right.
    // `current_right_diff` is 0.
    // Required `diff_from_left_removed = initial_diff - 0 = initial_diff`.
    if (left_removed_diff_to_count.count(initial_diff)) {
        min_removed = std::min(min_removed, left_removed_diff_to_count[initial_diff]);
    }

    current_left_diff = 0; // Re-using variable, this is `current_right_diff`
    for (int k = 1; k <= n; ++k) {
        current_left_diff += (a[n + k - 1] == 1 ? 1 : -1); // Sum of jars n, n+1, ..., n+k-1
        int target_diff_from_left = initial_diff - current_left_diff;
        if (left_removed_diff_to_count.count(target_diff_from_left)) {
            min_removed = std::min(min_removed, k + left_removed_diff_to_count[target_diff_from_left]);
        }
    }

    std::cout << min_removed << std::endl;
}

