#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0); // L[i] = max length of 0-block ending at i
    std::vector<int> R(n, 0); // R[i] = max length of 0-block starting at i

    // Calculate L
    if (a[0] == 0) L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // Calculate R
    if (a[n - 1] == 0) R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros > 0 && right_zeros > 0) {
                max_k = std::max(max_k, std::min(left_zeros, right_zeros) / 2 + 1);
            }
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> final_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 1) {
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros > 0 && right_zeros > 0) {
                if (std::min(left_zeros, right_zeros) >= 2 * max_k) {
                    final_a[i] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

