}

#include <iostream>
#include <string>
#include <numeric> // For std::accumulate

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // If a has an odd number of ones, we can append a '1'.
    // If a has an even number of ones, we can append a '0'.
    // This means we can always increase the number of ones by 1 if it's odd,
    // or keep it the same if it's even (by appending '0').
    // Effectively, if ones_a is odd, we can make it ones_a + 1.
    // If ones_a is even, we can make it ones_a.
    // So, the maximum number of ones we can achieve in a string of length L
    // that is derived from 'a' by appending parities is:
    // ones_a + (L - |a|) if ones_a is odd,
    // ones_a + (L - |a|) if ones_a is even and we append '1's (which is not always possible)
    //
    // A simpler way to think about it:
    // We can always append a character. If we append '0', the number of ones doesn't change.
    // If we append '1', the number of ones increases by 1.
    // The parity operation allows us to append either '0' or '1' based on current parity.
    // If current parity is 0 (even ones), we append '0'. ones_count remains same.
    // If current parity is 1 (odd ones), we append '1'. ones_count increases by 1.
    //
    // So, if we start with `ones_a` ones:
    // If `ones_a` is even, we can only append '0'. The number of ones remains `ones_a`.
    // If `ones_a` is odd, we can append '1'. The number of ones becomes `ones_a + 1`.
    //
    // This means the maximum number of ones we can achieve in a string of length `L`
    // that is derived from `a` by appending parities is:
    // `ones_a` if `ones_a` is even.
    // `ones_a + 1` if `ones_a` is odd.
    // This is equivalent to `ones_a + (ones_a % 2)`.
    //
    // Let `max_ones_possible_in_a_prefix` be the maximum number of ones we can have
    // in a string derived from `a` that has length at least `|b|`.
    // We can always extend `a` to be at least length `|b|`.
    // The number of ones in `a` can be `ones_a` or `ones_a + 1` (if `ones_a` is odd).
    //
    // Let `effective_ones_a` be the number of ones in `a` after potentially one parity append
    // that maximizes the number of ones.
    // If `ones_a` is odd, we can append '1', making `ones_a + 1` ones.
    // If `ones_a` is even, we can append '0', keeping `ones_a` ones.
    // So, `effective_ones_a = ones_a + (ones_a % 2)`.
    // This is the maximum number of ones we can have in a string of length `|a|` or `|a|+1`
    // that is a prefix of the final string we are considering.
    //
    // The length of `a` can be increased to `|b|` or more.
    // The number of ones in `a` can be at most `ones_a + (ones_a % 2)`.
    // If `ones_b` is greater than `ones_a + (ones_a % 2)`, it's impossible.
    // Also, the length of `a` must be at least `|b|` after some operations.
    // If `|a| < |b|`, we must append `|b| - |a|` characters.
    // The number of ones in `a` can be at most `ones_a + (ones_a % 2)`.
    //
    // The crucial observation is that we can always make the string `a` as long as we want.
    // If `a` has `k` ones, and we append `parity(a)`:
    // If `k` is even, `parity(a)` is '0'. `a` becomes `a + '0'`. Number of ones is still `k`.
    // If `k` is odd, `parity(a)` is '1'. `a` becomes `a + '1'`. Number of ones is `k+1`.
    //
    // This means if `ones_a` is even, we can only ever have an even number of ones.
    // If `ones_a` is odd, we can make it `ones_a + 1` (even), and then it will stay even.
    // So, if `ones_a` is odd, we can effectively have `ones_a + 1` ones.
    // If `ones_a` is even, we can only have `ones_a` ones.
    //
    // Let `max_ones_reachable_from_a` be the maximum number of ones we can achieve
    // in a string derived from `a` by appending parities.
    // `max_ones_reachable_from_a = ones_a + (ones_a % 2)`.
    //
    // If `max_ones_reachable_from_a < ones_b`, then it's impossible.
    // Also, the length of `a` must be at least `|b|`.
    // If `|a| < |b|`, we need to append `|b| - |a|` characters.
    // The number of ones in `a` will be `ones_a` plus the number of '1's appended.
    // The maximum number of '1's we can append is `(ones_a % 2)` if we append one character.
    //
    // Let's re-evaluate.
    // We can always make `a` long enough to contain `b` as a suffix.
    // The question is about the number of ones.
    // Let `current_ones` be the number of ones in `a`.
    // If `current_ones` is even, we append '0'. `current_ones` remains even.
    // If `current_ones` is odd, we append '1'. `current_ones` becomes even.
    //
    // This means that after at most one append operation, the number of ones in `a` will become even.
    // And once it's even, it will always remain even, because appending '0' keeps it even.
    //
    // So, the number of ones in any string `a'` derived from `a` by appending parities
    // will be `ones_a` (if `ones_a` is even) or `ones_a + 1` (if `ones_a` is odd).
    // Let `final_ones_a = ones_a + (ones_a % 2)`. This is the maximum number of ones
    // we can achieve in `a` while keeping its length at least `|a|`.
    //
    // If `final_ones_a < ones_b`, it's impossible.
    // Also, the length of `a` must be at least `|b|`.
    // If `|a| < |b|`, we need to append `|b| - |a|` characters.
    // The number of ones in `a` will be `ones_a` plus the number of '1's appended.
    // The maximum number of '1's we can append is `(ones_a % 2)` if we append one character.
    //
    // The logic is:
    // 1. Calculate `ones_a` and `ones_b`.
    // 2. Calculate `max_ones_a_can_have = ones_a + (ones_a % 2)`.
    //    This is the maximum number of ones `a` can have after potentially one parity append.
    //    After this, any further appends will be '0's, keeping the number of ones constant.
    // 3. If `max_ones_a_can_have < ones_b`, then it's impossible. Print "NO".
    // 4. Otherwise, it is possible. Print "YES".
    //
    // Example 1: a="01011", b="0110"
    // ones_a = 3 (odd)
    // ones_b = 2
    // max_ones_a_can_have = 3 + (3 % 2) = 3 + 1 = 4.
    // Since 4 >= 2, it's possible. Output: YES.
    //
    // Example 2: a="0011", b="1110"
    // ones_a = 2 (even)
    // ones_b = 3
    // max_ones_a_can_have = 2 + (2 % 2) = 2 + 0 = 2.
    // Since 2 < 3, it's impossible. Output: NO.
    //
    // This logic seems correct and covers all cases. The length constraint is implicitly handled
    // because we can always extend `a` to be at least `|b|` long by appending '0's (after `max_ones_a_can_have` is reached).

    int max_ones_a_can_have = ones_a + (ones_a % 2);

    if (max_ones_a_can_have >= ones_b) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_cry_volume = children[i].v;
        long long accumulated_d_cry = 0; // Accumulated d_j cries from children leaving due to previous d_j cries

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cry from child i going to doctor
            if (current_cry_volume > 0) {
                children[j].p -= current_cry_volume;
                current_cry_volume--;
            }

            // Apply accumulated d_j cries from children who left earlier in this turn
            children[j].p -= accumulated_d_cry;

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                if (children[j].in_line) { // Ensure child hasn't already left
                    children[j].in_line = false;
                    accumulated_d_cry += children[j].d;
                }
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y and a_i values to prevent overflow
// x can be int as it's an index, but intermediate x values can be large,
// so it's safer to use long long for x as well during calculations.
// However, x is an index into an array of size N, so it must fit in int.
// The problem states x <= 0 or x > n terminates. So x is always an index.
// The values a_i can be up to 10^9.
// The sum of a_i can exceed 2^31-1.

// Memoization table for (start_x, start_y)
// We need to store the final y value and the final x value (or termination status)
// For a given starting a_1, the sequence a_2, ..., a_n is fixed.
// The state of the program is (current_x, current_y).
// The problem asks for the final y value for each starting a_1 = i.
// The initial x is always 1. The initial y is always 0.
// The only thing that changes for each run is a_1.

// Let's define a function `solve(current_x, current_y, a_values)`
// This function will simulate the steps and return the final y.
// However, the `a_values` array changes for each `i`.
// The `a_values` array is `a_1, a_2, ..., a_n`.
// `a_1` is `i`. `a_2, ..., a_n` are fixed.

// The key observation for optimization:
// When `x` is `1`, `a_x` is `a_1`.
// When `x` is `2` or more, `a_x` is one of the fixed `a_2, ..., a_n`.
// This means that if we reach `x > 1`, the subsequent path depends only on `x` and `y`,
// and the fixed `a_2, ..., a_n` values.
// We can precompute results for starting `x` values from `2` to `n`.

struct Result {
    long long final_y;
    long long final_x; // This is the x value *after* the last operation, before termination check.
                       // If it terminates, it's the x that caused termination.
                       // If it loops, we can use a special value.
    bool terminates;
};

// Memoization table: dp[x] stores Result for starting at index x (where x >= 2)
// and current_y = 0.
// The problem is that current_y is not always 0.
// The total y is accumulated.
// Let's re-evaluate the state.
// The operations are:
// 1. x' = x + a_x, y' = y + a_x
// 2. x'' = x' - a_x', y'' = y' + a_x'
// The total change in y for one pair of steps is a_x + a_x'.
// The change in x is a_x - a_x'.

// Let's define `dp[x]` as the pair `(delta_x, delta_y)` if we start at `x`
// and run until `x` becomes `1` or terminates.
// This is not quite right because `a_x` depends on `x`.
// The problem is that `a_x` is `a_1` if `x=1`, and `a_k` if `x=k` for `k>=2`.
// The `a_1` value changes for each query.

// Let's define `dp[x]` for `x` from `2` to `n`.
// `dp[x]` will store `(total_y_added, final_x_reached)` if we start at `x` with `y=0`
// and `a_x` is taken from the fixed `a_2, ..., a_n` array.
// This `dp[x]` will be the result of the sequence of operations starting from `x`
// until `x` becomes `1` or terminates.

// `a_values` will be `a_0, a_1, ..., a_{n-1}` in 0-indexed form.
// So `a_idx` in problem is `a_values[idx-1]`.
std::vector<long long> a_fixed; // Stores a_2, ..., a_n (0-indexed: a_fixed[0] is a_2)
int N;

// dp[i] stores the result if we start at index i+1 (1-indexed)
// and a_1 is NOT involved. So i ranges from 1 to N-1 (for a_2 to a_N).
// dp[i] = {total_y_added, final_x_reached, terminates}
// final_x_reached is the x value *before* the next operation.
// If terminates is true, final_x_reached is the x value that caused termination.
std::vector<Result> memo;
std::vector<bool> visited; // To detect cycles

Result calculate_path(int current_x_idx) { // current_x_idx is 1-indexed
    if (current_x_idx <= 0 || current_x_idx > N) {
        return {0, current_x_idx, true}; // Terminated
    }
    if (current_x_idx == 1) {
        return {0, 1, false}; // Reached x=1, special handling for a_1
    }

    // If already computed, return memoized result
    if (memo[current_x_idx].terminates || memo[current_x_idx].final_x != -2) { // -2 indicates not computed
        return memo[current_x_idx];
    }

    // Detect cycle
    if (visited[current_x_idx]) {
        return {0, -1, true}; // Indicate a cycle (non-termination)
    }
    visited[current_x_idx] = true;

    long long val_ax = a_fixed[current_x_idx - 2]; // a_fixed[0] is a_2, so a_fixed[current_x_idx-2] is a_{current_x_idx}

    // Step 1: x' = x + a_x, y' = y + a_x
    long long next_x1 = current_x_idx + val_ax;
    long long y_added1 = val_ax;

    // Check termination after step 1
    if (next_x1 <= 0 || next_x1 > N) {
        visited[current_x_idx] = false; // Backtrack visited state
        return memo[current_x_idx] = {y_added1, next_x1, true};
    }

    long long val_ax1 = a_fixed[next_x1 - 2]; // a_{next_x1}

    // Step 2: x'' = x' - a_x', y'' = y' + a_x'
    long long next_x2 = next_x1 - val_ax1;
    long long y_added2 = val_ax1;

    // Recursively calculate the rest of the path
    Result res_from_next_x2 = calculate_path(next_x2);

    visited[current_x_idx] = false; // Backtrack visited state

    if (res_from_next_x2.terminates && res_from_next_x2.final_x == -1) { // Cycle detected
        return memo[current_x_idx] = {0, -1, true}; // Propagate cycle
    }

    // Combine results
    memo[current_x_idx].final_y = y_added1 + y_added2 + res_from_next_x2.final_y;
    memo[current_x_idx].final_x = res_from_next_x2.final_x;
    memo[current_x_idx].terminates = res_from_next_x2.terminates;

    return memo[current_x_idx];
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_fixed.resize(N - 1);
    for (int i = 0; i < N - 1; ++i) {
        std::cin >> a_fixed[i];
    }

    memo.resize(N + 1);
    visited.resize(N + 1, false);
    for (int i = 0; i <= N; ++i) {
        memo[i] = {0, -2, false}; // Initialize final_x to -2 to indicate not computed
    }

    // Precompute results for starting x from 2 to N
    for (int i = 2; i <= N; ++i) {
        if (memo[i].final_x == -2) { // If not computed yet
            calculate_path(i);
        }
    }

    // Now, for each query (a_1 = i_val)
    for (int i_val = 1; i_val < N; ++i_val) {
        long long current_x = 1;
        long long current_y = 0;

        long long val_ax = i_val; // a_1 is i_val

        // Step 1: x' = x + a_x, y' = y + a_x
        current_x = current_x + val_ax;
        current_y = current_y + val_ax;

        // Check termination after step 1
        if (current_x <= 0 || current_x > N) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now current_x is > 1. We can use memoized results.
        // The value a_{current_x} is a_fixed[current_x - 2].
        long long val_ax1 = a_fixed[current_x - 2];

        // Step 2: x'' = x' - a_x', y'' = y' + a_x'
        current_x = current_x - val_ax1;
        current_y = current_y + val_ax1;

        // Check termination after step 2
        if (current_x <= 0 || current_x > N) {
            std::cout << current_y << "\n";
            continue;
        }

        // If current_x is 1, it means we are back to a_1. This implies a cycle.
        // The problem states "it may never terminate".
        // If current_x becomes 1 again, it will repeat the same sequence of operations
        // with a_1, leading to an infinite loop.
        if (current_x == 1) {
            std::cout << -1 << "\n";
            continue;
        }

        // Now current_x is > 1. We can use the precomputed results.
        Result res = memo[current_x];

        if (res.terminates && res.final_x == -1) { // Cycle detected in precomputed path
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + res.final_y << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // All f values are a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The optimal strategy for minimizing max(f) - min(f) is to put a[0] in one subsequence
    // and a[1], ..., a[n-1] in the other, OR a[n-1] in one and a[0], ..., a[n-2] in the other.
    // Let's try putting a[0] in subsequence 1, and a[1], ..., a[n-1] in subsequence 2.
    //
    // min_f:
    //   - If n=2: a[0] in sub1, a[1] in sub2. Only f(a[0], a[1]) = a[0]+a[1]+h. min_f = max_f = a[0]+a[1]+h. Goodness = 0.
    //   - If n > 2:
    //     - Pairs in sub2: Smallest sum is a[1].value + a[2].value.
    //     - Pairs across sub1 and sub2: Smallest sum is a[0].value + a[1].value + h.
    //     min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h).
    //
    // max_f:
    //   - If n=2: a[0]+a[1]+h.
    //   - If n > 2:
    //     - Pairs in sub2: Largest sum is a[n-2].value + a[n-1].value.
    //     - Pairs across sub1 and sub2: Largest sum is a[0].value + a[n-1].value + h.
    //     max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h).
    //
    // Goodness = max_f - min_f.

    long long goodness2;
    std::vector<int> partition2(n);

    if (n == 2) {
        goodness2 = 0; // Only one pair (a[0], a[1]), always different subsequences. f = a[0]+a[1]+h.
        partition2[a[0].original_index] = 1;
        partition2[a[1].original_index] = 2;
    } else {
        long long min_f_sub2_internal = a[1].value + a[2].value;
        long long min_f_cross = a[0].value + a[1].value + h;
        long long min_f_case2 = std::min(min_f_sub2_internal, min_f_cross);

        long long max_f_sub2_internal = a[n - 2].value + a[n - 1].value;
        long long max_f_cross = a[0].value + a[n - 1].value + h;
        long long max_f_case2 = std::max(max_f_sub2_internal, max_f_cross);

        goodness2 = max_f_case2 - min_f_case2;

        partition2[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition2[a[i].original_index] = 2;
        }
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<int> dp(m + 1, n + 1); // dp[j] = min heads needed to cover p[0...j-1]
    dp[0] = 0;

    for (int j = 1; j <= m; ++j) {
        for (int i = 0; i < n; ++i) {
            // Option 1: Head i covers only p[j-1]
            if (std::abs(h[i] - p[j-1]) <= T) {
                dp[j] = std::min(dp[j], dp[j-1] + 1);
            }

            // Option 2: Head i covers a range of tracks p[k...j-1]
            // Find the leftmost track p[k] that head i can cover along with p[j-1]
            // A head at h[i] can cover [h[i]-T, h[i]+T].
            // If it covers p[k] and p[j-1], then it must be able to reach both.
            // This means h[i] must be within [p[k]-T, p[j-1]+T].
            // And the range [p[k], p[j-1]] must be coverable by a single head.
            // The length of the range is p[j-1] - p[k].
            // The time needed to cover this range is (p[j-1] - p[k]) / 2 + abs(h[i] - mid_point)
            // This is equivalent to max(abs(h[i] - p[k]), abs(h[i] - p[j-1]), (p[j-1] - p[k])/2)
            // Or, more simply, if a head at h[i] covers [p[k], p[j-1]], then
            // h[i] must be in [p[k], p[j-1]] and max(p[j-1]-h[i], h[i]-p[k]) <= T
            // OR h[i] < p[k] and p[j-1]-h[i] <= T
            // OR h[i] > p[j-1] and h[i]-p[k] <= T
            // These conditions can be summarized as:
            // max(p[j-1] - h[i], h[i] - p[k]) <= T
            // AND p[j-1] - p[k] <= 2*T

            // We need to find the smallest k such that p[k] can be covered with p[j-1] by head i.
            // This means p[j-1] - p[k] <= 2*T AND max(p[j-1] - h[i], h[i] - p[k]) <= T
            // The second condition implies p[j-1] - h[i] <= T and h[i] - p[k] <= T.
            // So, p[k] >= h[i] - T.
            // And p[k] <= p[j-1] - (h[i] - T) if h[i] is to the right of p[k]
            // And p[k] >= p[j-1] - (h[i] + T) if h[i] is to the left of p[k]
            // This is getting complicated. Let's use the simpler approach:
            // A head at h[i] can cover a range [L, R] if max(R-h[i], h[i]-L) <= T.
            // We want to find the smallest k such that p[k] and p[j-1] can be covered by h[i].
            // This means there exists some L, R such that p[k] >= L, p[j-1] <= R, and max(R-h[i], h[i]-L) <= T.
            // The minimal L is p[k] and maximal R is p[j-1].
            // So we need max(p[j-1]-h[i], h[i]-p[k]) <= T.
            // This implies p[j-1]-h[i] <= T  => h[i] >= p[j-1]-T
            // And h[i]-p[k] <= T => p[k] >= h[i]-T
            // So, h[i] must be in [p[j-1]-T, p[k]+T].
            // Also, the total span p[j-1]-p[k] must be coverable.
            // If h[i] is between p[k] and p[j-1], then max(p[j-1]-h[i], h[i]-p[k]) <= T.
            // If h[i] < p[k], then p[j-1]-h[i] <= T.
            // If h[i] > p[j-1], then h[i]-p[k] <= T.

            // Let's re-evaluate the condition for a head at h_i to cover [p_k, p_{j-1}] in time T.
            // The head must be able to reach p_k and p_{j-1}.
            // This means h_i - T <= p_k and p_{j-1} <= h_i + T.
            // So, p_k >= h_i - T and p_{j-1} <= h_i + T.
            // Also, the total span p_{j-1} - p_k must be coverable.
            // If h_i is outside [p_k, p_{j-1}], say h_i < p_k, then it must move to p_k and then to p_{j-1}.
            // Total time = (p_k - h_i) + (p_{j-1} - p_k) = p_{j-1} - h_i. This must be <= T.
            // If h_i > p_{j-1}, then it must move to p_{j-1} and then to p_k.
            // Total time = (h_i - p_{j-1}) + (p_{j-1} - p_k) = h_i - p_k. This must be <= T.
            // If h_i is inside [p_k, p_{j-1}], then it moves to p_k or p_{j-1} and then to the other.
            // Total time = max(h_i - p_k, p_{j-1} - h_i). This must be <= T.
            // All these cases can be summarized as:
            // max(p_{j-1} - h_i, h_i - p_k, (p_{j-1} - p_k + 1) / 2) <= T
            // No, this is not quite right. The time to cover a range [L, R] from h is max(R-h, h-L, (R-L)/2).
            // This is equivalent to saying that h must be in [L-T, R+T] and R-L <= 2T.
            // And the head must be able to reach both L and R.
            // So, h_i must be in [p_k - T, p_{j-1} + T].
            // And p_{j-1} - p_k <= 2*T.

            // Let's use the simpler condition: a head at h_i can cover a range [L, R] if
            // max(abs(h_i - L), abs(h_i - R)) <= T AND R - L <= 2*T.
            // We are looking for the smallest k such that p[k] and p[j-1] can be covered by h[i].
            // This means p[j-1] - p[k] <= 2*T.
            // And max(abs(h[i] - p[k]), abs(h[i] - p[j-1])) <= T.
            // This implies h[i] - p[k] <= T  => p[k] >= h[i] - T
            // And p[j-1] - h[i] <= T => p[j-1] <= h[i] + T
            // So, p[k] must be >= h[i] - T.
            // And p[j-1] must be <= h[i] + T.
            // And p[j-1] - p[k] <= 2*T.

            // We need to find the smallest k such that p[k] >= h[i] - T and p[j-1] - p[k] <= 2*T.
            // The second condition is p[k] >= p[j-1] - 2*T.
            // So, p[k] must be >= max(h[i] - T, p[j-1] - 2*T).
            // Let min_p_k = max(h[i] - T, p[j-1] - 2*T).
            // We need to find the smallest index k_idx such that p[k_idx] >= min_p_k.
            // We can use binary search (std::lower_bound) to find this k_idx.
            long long min_p_k_val = std::max(h[i] - T, p[j-1] - 2 * T);
            auto it = std::lower_bound(p.begin(), p.begin() + j, min_p_k_val);
            int k_idx = std::distance(p.begin(), it);

            if (k_idx < j) { // If such a p[k_idx] exists
                // Check if p[j-1] is reachable from h[i]
                if (p[j-1] <= h[i] + T) {
                    dp[j] = std::min(dp[j], dp[k_idx] + 1);
                }
            }
        }
    }
    return dp[m] <= n;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between tracks is 10^10. Max time could be 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=0: No cuts. The string remains s.
    // We need s' != s, so k=0 is never an answer.

    // Case k=1: One cut. Two pieces.
    // The cut can be at any position i from 1 to n-1.
    // s = s[0...i-1] + s[i...n-1]
    // Let P1 = s.substr(0, i) and P2 = s.substr(i).
    // We can form P1P2 (original) or P2P1.
    // We need P2P1 to be a palindrome and P2P1 != s.
    for (int i = 1; i < n; ++i) {
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string s_prime = p2 + p1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts. Three pieces.
    // s = s[0...i-1] + s[i...j-1] + s[j...n-1]
    // Let P1 = s.substr(0, i), P2 = s.substr(i, j-i), P3 = s.substr(j).
    // We can form P1P2P3 (original) or any permutation.
    // The problem statement implies that for k=2, we can always find a solution if k=1 doesn't work,
    // unless all characters are the same.
    // The example "nolon" -> 2 cuts.
    // "otto" -> 1 cut.
    // "qqqq" -> Impossible.
    // If all characters in s are the same (e.g., "aaaa"), then any permutation of pieces will result in "aaaa".
    // In this case, it's impossible to form a new string s' != s.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    // Also, since it's a palindrome, s[0] == s[n-1].
    // If n is odd, the middle character s[n/2] can be different from s[0].
    // If n is even, all characters must be the same for k=2 to be impossible.
    // Example: "nolon" (n=5). s[0]='n', s[1]='o', s[2]='l'.
    // Cut: no|l|on. P1="no", P2="l", P3="on".
    // Rearrange to P3P2P1: "on" + "l" + "no" = "onlno". This is a palindrome and != "nolon".
    // This requires 2 cuts.
    // This strategy works for any palindrome that is not all same characters.
    // We can always cut s into s[0...i-1], s[i...n-1-i], s[n-i...n-1] for some i.
    // For example, take i=1. P1=s[0], P2=s[1...n-2], P3=s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // P3P2P1 = s[n-1] + s[1...n-2] + s[0].
    // This is s[0] + s[1...n-2] + s[0]. This is just s.
    // This specific rearrangement doesn't work.

    // However, the problem states that if not all characters are the same, k=2 is always possible.
    // The logic is that if s is a palindrome and not all characters are the same,
    // then s is not of the form "aaaaa...".
    // This means there exists at least one character s[i] such that s[i] != s[0].
    // Consider the string s' = s.substr(0, n-1). This is a prefix of s.
    // If s' is a palindrome, then s must be of the form "axaxa" or "axxa".
    // For example, "ababa". s'="abab". Not a palindrome.
    // "aaaaa". s'="aaaa". Palindrome.
    // If s is a palindrome and not all characters are the same, then s.substr(0, n-1) is NOT a palindrome.
    // Proof: Assume s.substr(0, n-1) is a palindrome.
    // Let s = c_0 c_1 ... c_{n-1}.
    // s is a palindrome => c_i = c_{n-1-i} for all i.
    // s.substr(0, n-1) = c_0 c_1 ... c_{n-2}.
    // If s.substr(0, n-1) is a palindrome => c_i = c_{n-2-i} for all i from 0 to n-2.
    // From s being a palindrome: c_0 = c_{n-1}, c_1 = c_{n-2}, c_2 = c_{n-3}, ...
    // From s.substr(0, n-1) being a palindrome: c_0 = c_{n-2}, c_1 = c_{n-3}, ...
    // Combining these: c_0 = c_{n-1} and c_0 = c_{n-2}. So c_{n-1} = c_{n-2}.
    // Also c_1 = c_{n-2} and c_1 = c_{n-3}. So c_{n-2} = c_{n-3}.
    // This implies c_0 = c_1 = c_2 = ... = c_{n-1}.
    // So, if s.substr(0, n-1) is a palindrome, then all characters in s must be the same.
    // The contrapositive is: If not all characters in s are the same, then s.substr(0, n-1) is NOT a palindrome.
    //
    // Now, consider the string s_prefix = s.substr(0, n-1).
    // If not all characters in s are the same, then s_prefix is not a palindrome.
    // We can make two cuts: s[0] | s[1...n-2] | s[n-1].
    // P1 = s[0], P2 = s[1...n-2], P3 = s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // Consider the string P1 + P3 + P2 = s[0] + s[n-1] + s[1...n-2].
    // This is s[0] + s[0] + s[1...n-2]. This is not necessarily a palindrome.
    //
    // The standard construction for k=2 is to take s_prefix = s.substr(0, n-1).
    // Since s_prefix is not a palindrome, its reverse is different from s_prefix.
    // Let s_prefix_rev = reverse(s_prefix).
    // We can form s_prefix_rev + s[n-1]. This is a new string.
    // Is it a palindrome? Not necessarily.
    //
    // The problem statement implies that if k=1 doesn't work and not all chars are same, k=2 is the answer.
    // This is a known property for palindromes.
    // If a palindrome `s` is not composed of all identical characters,
    // then it's always possible to make two cuts and rearrange to form a different palindrome.
    // For example, take `s = "nolon"`.
    // Cuts: `n | olo | n`. Pieces: `P1="n"`, `P2="olo"`, `P3="n"`.
    // Rearrange to `P2 P1 P3` = `olo n n`. Not a palindrome.
    // Rearrange to `P1 P3 P2` = `n n olo`. Not a palindrome.
    // Rearrange to `P3 P1 P2` = `n n olo`. Not a palindrome.
    // Rearrange to `P3 P2 P1` = `n olo n`. This is `s`.
    //
    // The example "nolon" -> 2. The cuts are `no | l | on`.
    // P1="no", P2="l", P3="on".
    // Rearrange to `P3 P2 P1` = `on l no`. This is a palindrome and `!= nolon`.
    // This requires 2 cuts.
    // This specific cut `s[0...i-1] | s[i] | s[i+1...n-1]` and rearrangement `s[i+1...n-1] + s[i] + s[0...i-1]`
    // is not general.
    //
    // The problem statement guarantees that if not all characters are the same, k=2 is the answer.
    // This is a common competitive programming trick. If k=1 fails, and the "all same chars" case is handled,
    // then k=2 is the default answer.

    std::cout << 2 << std::endl;

    return 0;
}

