#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long N;
        std::cin >> N;
        long long chanek_coins = 0;
        long long opponent_coins = 0;
        bool chanek_turn = true;

        while (N > 0) {
            if (N % 2 == 1) { // N is odd
                if (chanek_turn) {
                    chanek_coins += 1;
                } else {
                    opponent_coins += 1;
                }
                N -= 1;
            } else { // N is even
                // If N is a power of 2, taking N/2 is always optimal for the current player
                // unless N=2, where taking 1 is equivalent.
                // If N is not a power of 2, N = 2^k * M where M > 1 and M is odd.
                // Taking N/2 leaves 2^(k-1) * M.
                // Taking 1 leaves N-1 (odd).

                // Check if N is a power of 2
                if ((N & (N - 1)) == 0) { // N is a power of 2
                    if (N == 2) { // Special case for N=2, taking 1 is optimal for Chanek
                                  // to ensure opponent gets 1, leaving Chanek with 1.
                                  // If Chanek takes N/2=1, opponent gets 1. Same result.
                                  // But if Chanek takes 1, N becomes 1, opponent takes 1.
                                  // Chanek gets 1, opponent gets 1.
                                  // If Chanek takes N/2, N becomes 1, opponent takes 1.
                                  // Chanek gets 1, opponent gets 1.
                                  // The problem statement example for N=6 implies Chanek takes N/2.
                                  // For N=2, it doesn't matter. Let's stick to the general rule.
                                  // For N=2, if Chanek takes 1, N=1, Opponent takes 1. C:1, O:1.
                                  // For N=2, if Chanek takes N/2=1, N=1, Opponent takes 1. C:1, O:1.
                                  // So for N=2, Chanek gets 1.
                                  // The logic below handles N=2 correctly.
                        if (chanek_turn) {
                            chanek_coins += N / 2;
                        } else {
                            opponent_coins += N / 2;
                        }
                        N /= 2;
                    } else { // N is a power of 2 and N > 2
                        // The current player should take N/2.
                        // This leaves N/2, which is also a power of 2.
                        // The next player will also take N/2 of the remaining.
                        // This continues until N=2, where the player takes 1.
                        // The player who gets N=2 will take 1, leaving 1 for the opponent.
                        // The player who gets N=4 will take 2, leaving 2 for the opponent.
                        // The player who gets N=8 will take 4, leaving 4 for the opponent.
                        // In general, for N=2^k, the current player takes 2^(k-1).
                        // The total coins are split equally.
                        // So, if N is a power of 2, the current player takes N/2.
                        if (chanek_turn) {
                            chanek_coins += N / 2;
                        } else {
                            opponent_coins += N / 2;
                        }
                        N /= 2;
                    }
                } else { // N is even but not a power of 2
                    // N = 2^k * M, where M > 1 and M is odd.
                    // If current player takes N/2, N becomes 2^(k-1) * M.
                    // If current player takes 1, N becomes N-1 (odd).
                    // Taking 1 is always better if it leads to an odd number for the opponent,
                    // because the opponent will be forced to take 1.
                    // If Chanek takes 1, N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                    // If Chanek takes N/2, N becomes N/2.
                    // The optimal strategy for the current player when N is even and not a power of 2
                    // is to take N/2. This is because taking 1 would leave an odd number for the opponent,
                    // who would then take 1, leaving an even number for the current player.
                    // This essentially delays the N/2 move.
                    // By taking N/2, the current player gets a larger chunk immediately.
                    if (chanek_turn) {
                        chanek_coins += N / 2;
                    } else {
                        opponent_coins += N / 2;
                    }
                    N /= 2;
                }
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_coins << "\n";
    }
    return 0;
}

