int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = std::numeric_limits<long long>::max();
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself, and we are using min_idx as source
            }
            // For each other pile a[i], we can add min_val to it as many times as possible
            // without exceeding k.
            // The number of times is (k - a[i]) / min_val
            if (min_val > 0) { // To avoid division by zero, though problem constraints say a_i >= 1
                total_spells += (k - a[i]) / min_val;
            }
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reverse of a permutation always has the same fingerprint.
    // If the original permutation is not a palindrome, its reverse is a different permutation.
    // The problem guarantees a solution exists, and for n >= 2, a permutation is a palindrome
    // only if p_i = p_{n-i+1} for all i.
    // For n >= 2, the reverse of p is always different from p unless p is a palindrome.
    // For example, if n=2, p=[1,2], p_rev=[2,1]. These are different.
    // If n=3, p=[1,2,3], p_rev=[3,2,1]. These are different.
    // If p is a palindrome, e.g., [1,2,1] (not a permutation), or [2,1,2] (not a permutation).
    // A permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2).
    // For example, if n=3, p=[1,3,2]. p_rev=[2,3,1]. Different.
    // If p_i = p_{n-i+1} for all i, then p_1 = p_n, p_2 = p_{n-1}, etc.
    // Since all elements must be distinct in a permutation, this can only happen if n=1.
    // But n >= 2.
    // Therefore, p is never a palindrome, and p_rev is always different from p.

    // So, simply reversing the permutation p gives a valid p'.
    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

