        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];
        long long remaining_days = d;

        for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
            int pile_index = i; // 0-indexed
            int pile_number = i + 1; // 1-indexed
            int haybales_in_pile = a[pile_index];
            int cost_per_haybale = pile_index; // cost to move to pile 0 (1-indexed pile 1)

            if (cost_per_haybale == 0) { // This should only happen for pile 1 itself, which is handled by current_a1
                continue;
            }

            // Calculate how many haybales can be moved from this pile
            // based on remaining_days and cost_per_haybale
            long long max_movable_from_this_pile = remaining_days / cost_per_haybale;

            // The actual number of haybales moved is the minimum of
            // haybales available in the pile and what can be afforded
            long long moved_haybales = std::min((long long)haybales_in_pile, max_movable_from_this_pile);

            current_a1 += moved_haybales;
            remaining_days -= moved_haybales * cost_per_haybale;

            if (remaining_days <= 0) {
                break; // No more days left
            }
        }
        std::cout << current_a1 << std::endl;
