#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only numbers up to 2048 are useful for forming 2048
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // We only care about the sum up to 2048.
        // If current_sum + val * count exceeds 2048, we can cap it at 2048
        // because any excess value beyond 2048 is not useful for forming 2048.
        // For example, if we have 1024 and 1024, current_sum becomes 2048.
        // If we then have another 1024, it doesn't help us get *another* 2048,
        // nor does it help us get *the* 2048 if we already have enough.
        // The problem is about *obtaining* 2048, not maximizing the sum.
        // The key insight is that we can always combine smaller powers of two
        // to form larger ones. So, if we have a total sum of values (up to 2048)
        // that is >= 2048, we can always form 2048.
        // Example: {1024, 512, 512} -> sum = 2048. Can form 2048.
        // Example: {1024, 1024} -> sum = 2048. Can form 2048.
        // Example: {1024, 256, 256, 256, 256} -> sum = 2048. Can form 2048.
        // The sum of all numbers less than or equal to 2048 is what matters.
        // If this sum is >= 2048, we can always combine them to form 2048.
        // This is because any two identical powers of two can be combined into the next higher power.
        // This process can be thought of as "carrying over" values.
        // For example, two 1s make a 2. Two 2s make a 4.
        // So, if we have 2048 1s, we can make 1024 2s, then 512 4s, ..., then one 2048.
        // The total sum of values (capped at 2048) is the effective "progress" towards 2048.
        current_sum += (long long)val * count;
        if (current_sum >= 2048) {
            current_sum = 2048; // Cap the sum at 2048, as anything beyond this is not needed
        }
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

