    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks to minimize |median(C1) - median(C2)|.
        // After sorting the entire array a, the optimal strategy is to
        // form two classes such that one median is a[n-1] and the other is a[n].
        // This is because if we pick any other two elements as medians, say a[i] and a[j]
        // with i < n-1 or j > n, we can always improve or keep the same difference
        // by moving towards a[n-1] and a[n].
        //
        // Specifically, if we choose a[n-1] as the median for one class (say C1)
        // and a[n] as the median for the other class (say C2),
        // we can construct such classes.
        //
        // For C1 to have a[n-1] as its median, it must contain a[n-1] and
        // (S1-1)/2 elements less than or equal to a[n-1] and
        // (S1-1)/2 elements greater than or equal to a[n-1].
        // The smallest possible odd size for C1 is 1, where a[n-1] is the median.
        // The largest possible odd size for C1 is 2n-1.
        //
        // For C2 to have a[n] as its median, it must contain a[n] and
        // (S2-1)/2 elements less than or equal to a[n] and
        // (S2-1)/2 elements greater than or equal to a[n].
        // The smallest possible odd size for C2 is 1, where a[n] is the median.
        // The largest possible odd size for C2 is 2n-1.
        //
        // We need to ensure that all 2n students are assigned and both classes have odd sizes.
        //
        // Consider the partition where:
        // Class 1 (C1) consists of elements a[0], a[1], ..., a[n-1].
        // The size of C1 is n.
        // Class 2 (C2) consists of elements a[n], a[n+1], ..., a[2n-1].
        // The size of C2 is n.
        //
        // This partition is valid if n is odd.
        // If n is odd, then |C1|=n is odd, and |C2|=n is odd.
        // The median of C1 (sorted a[0]...a[n-1]) is a[(n-1)/2].
        // The median of C2 (sorted a[n]...a[2n-1]) is a[n + (n-1)/2].
        // This is not necessarily a[n-1] and a[n].
        //
        // The key insight is that to minimize the difference, the medians should be as close as possible.
        // After sorting the entire array, the two "middle" elements are a[n-1] and a[n].
        // It is always possible to construct two classes of odd sizes such that a[n-1] is the median of one class and a[n] is the median of the other.
        //
        // Let's make C1 contain a[n-1] as its median.
        // Let's make C2 contain a[n] as its median.
        //
        // We can form C1 with elements {a[0], a[1], ..., a[n-1]} and C2 with elements {a[n], a[n+1], ..., a[2n-1]}.
        // This is a partition into two classes of size n each.
        // If n is odd, this is a valid partition.
        // The median of C1 would be a[(n-1)/2].
        // The median of C2 would be a[n + (n-1)/2].
        // The difference would be a[n + (n-1)/2] - a[(n-1)/2].
        //
        // However, the problem states that the number of students in classes may be equal or different.
        // The crucial observation is that if we pick a[n-1] and a[n] as the medians, we can always construct valid classes.
        //
        // For example, let C1 = {a[0], a[1], ..., a[n-1]} and C2 = {a[n], a[n+1], ..., a[2n-1]}.
        // This is a partition of 2n students into two classes of size n.
        // If n is odd, this is a valid partition.
        // The median of C1 is a[(n-1)/2].
        // The median of C2 is a[n + (n-1)/2].
        // The difference is a[n + (n-1)/2] - a[(n-1)/2].
        //
        // What if n is even? Then this partition is not valid because class sizes are even.
        //
        // Consider the elements a[n-1] and a[n].
        // We can always form a class C1 of size 1 with just {a[n-1]} and a class C2 of size 2n-1 with all other elements.
        // The median of C1 is a[n-1].
        // The median of C2 (which contains all elements except a[n-1]) would be the ( (2n-1)+1 )/2 = n-th smallest element among them.
        // If a[n-1] is removed, the elements are a[0]...a[n-2], a[n]...a[2n-1].
        // The n-th smallest element in this set is a[n].
        // So, the median of C2 would be a[n].
        //
        // This construction is always valid:
        // Class 1: {a[n-1]} (size 1, odd)
        // Class 2: {a[0], ..., a[n-2], a[n], ..., a[2n-1]} (size 2n-1, odd)
        // Median of C1 is a[n-1].
        // Median of C2 is a[n].
        // The absolute difference is |a[n] - a[n-1]|.
        //
        // This difference is the minimum possible. Any other choice of medians would result in a difference greater than or equal to this.
        // If we pick a median for C1 as a[i] and for C2 as a[j], where i < n-1 or j > n, the difference |a[j]-a[i]| would be greater than or equal to |a[n]-a[n-1]|.
        // For example, if we pick a[i] and a[j] such that i < n-1 and j > n, then a[j] - a[i] >= a[n] - a[n-1].
        // If we pick a[i] and a[j] such that i < n-1 and j = n, then a[n] - a[i] >= a[n] - a[n-1].
        // If we pick a[i] and a[j] such that i = n-1 and j > n, then a[j] - a[n-1] >= a[n] - a[n-1].
        //
        // Therefore, the minimum possible absolute difference is a[n] - a[n-1].

        long long result = a[n] - a[n-1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, starting from the second to last element
    // For each element a[i], we compare it with the minimum price encountered so far to its right (min_suffix)
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is a new minimum
            // or equal to the current minimum in the suffix.
            // Update min_suffix to be the minimum of a[i] and the current min_suffix.
            // This is equivalent to min_suffix = std::min(a[i], min_suffix);
            min_suffix = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

