        // from cell 0 directly to cell n+1. The distance is (n+1) - 0 + 1 = n+2.
        // If last_R_pos is not -1, the distance is (n+1) - (last_R_pos + 1) + 1.
        max_dist = std::max(max_dist, (int)s.length() + 1 - (last_R_pos + 1) + 1);
