    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // For any range [l, r] where l < r, the number 2 will always be a divisor
        // for at least floor(r/2) - floor((l-1)/2) numbers.
        // This count is maximized when l and r are large enough.
        // Specifically, if r >= 2*l, then 2 will be a divisor for roughly half the numbers.
        // Any number x > r/2 can only have one multiple in [l, r], which is x itself.
        // For example, if l=19, r=29, then 2 is a divisor for {20, 22, 24, 26, 28} (5 times).
        // 3 is a divisor for {21, 24, 27} (3 times).
        // 4 is a divisor for {20, 24, 28} (3 times).
        // 5 is a divisor for {20, 25} (2 times).
        // 6 is a divisor for {24} (1 time).
        // The number 2 is generally the most frequent divisor for larger ranges.
        // The only exception is when l and r are very close, specifically when l is odd and r = l+1.
        // For example, l=3, r=4.
        // Divisors for 3 (except 1): {3}
        // Divisors for 4 (except 1): {2, 4}
        // Count of 2: 1 (from 4)
        // Count of 3: 1 (from 3)
        // Count of 4: 1 (from 4)
