#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle formed by the i-th cut from the apex
        // must be i times the area of a single piece.
        // Total area of carrot = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area of triangle up to i-th cut = i * (h / (2n)).
        //
        // Let x_i be the distance of the i-th cut from the apex.
        // The area of a triangle with height x_i (and base b_i) is (1/2) * b_i * x_i.
        // By similar triangles, b_i / x_i = 1 / h, so b_i = x_i / h.
        // Area = (1/2) * (x_i / h) * x_i = x_i^2 / (2h).
        //
        // Equating the two expressions for area:
        // x_i^2 / (2h) = i * (h / (2n))
        // x_i^2 = i * (h^2 / n)
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

