#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // Only add ')' if it can be matched by an already added '('
            // and we still need closing brackets.
            // The condition `result.length() - (k/2 - open_needed) > 0`
            // checks if the number of open brackets already added
            // is greater than the number of close brackets already added.
            // `result.length()` is the current length of the result string.
            // `(k/2 - open_needed)` is the number of '(' already added.
            // `result.length() - (k/2 - open_needed)` is the number of ')' already added.
            // So, we need `(k/2 - open_needed) > (result.length() - (k/2 - open_needed))`
            // which simplifies to `2 * (k/2 - open_needed) > result.length()`.
            // Or, more simply, `open_brackets_count > close_brackets_count`.
            // `open_brackets_count` is `k/2 - open_needed`.
            // `close_brackets_count` is `result.length() - (k/2 - open_needed)`.
            if ((k / 2 - open_needed) > (result.length() - (k / 2 - open_needed)) && close_needed > 0) {
                result += ')';
                close_needed--;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of multiples of m up to n

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Precompute the sum of last digits for one full cycle (10 multiples)
        // The last digits of (i * m) % 10 repeat every 10 multiples of m.
        // E.g., (1*m)%10, (2*m)%10, ..., (10*m)%10
        // (11*m)%10, (12*m)%10, ..., (20*m)%10 are the same sequence.
        std::vector<long long> cycle_last_digits_sum(10);
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits_sum[i - 1] = (static_cast<long long>(i) * m) % 10;
        }

        long long sum_of_one_cycle = 0;
        for (long long digit : cycle_last_digits_sum) {
            sum_of_one_cycle += digit;
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = k / 10;
        long long total_sum = num_full_cycles * sum_of_one_cycle;

        // Add the sum for the remaining multiples
        long long remaining_multiples = k % 10;
        for (int i = 0; i < remaining_multiples; ++i) {
            total_sum += cycle_last_digits_sum[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'p' such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // We iterate from right to left to find the first violation.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // Now, a[p...n-1] is non-decreasing.
    // We need to find the rightmost index 'q' such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // We iterate from p-1 down to 0 to find the first violation.
    // If p is 0, then the whole array is non-decreasing, so q would be 0.
    int q = p; // Initialize q to p. If p is 0, q remains 0.
    if (p > 0) {
        q = p - 1;
        while (q > 0 && a[q-1] <= a[q]) {
            q--;
        }
    }

    // The prefix to remove has length 'q'.
    // The remaining suffix is a[q...n-1].
    // This suffix has the form: non-increasing part (a[q...p-1]) followed by non-decreasing part (a[p...n-1]).
    // This structure (mountain-like or valley-like, but specifically non-increasing then non-decreasing)
    // is exactly what makes an array "good".
    // The length of the prefix to erase is q.
    std::cout << q << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

