        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining unspecialized: x
            // Total remaining students: (c - mid) + (m - mid) + x
            // Each team needs 3 members. We've already assigned 2 (1 coder, 1 math).
            // So, each team needs 1 more member.
            // Total additional members needed: mid
            // If (c - mid) + (m - mid) + x >= mid, then it's possible to form 'mid' teams.
            if ((c - mid) + (m - mid) + x >= mid) {
