}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm> // For std::min and std::max

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');
    ans[0] = '1'; // m=1 is always beautiful

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 2; m <= n; ++m) {
        // Update the range [current_min_idx, current_max_idx] to include 'm'
        // This range now covers all numbers from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // For 'm' to be beautiful, the subsegment p[current_min_idx ... current_max_idx]
        // must contain exactly numbers 1 to m.
        // This means its length must be exactly 'm'.
        // The length of the subsegment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }

    std::cout << ans << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

