            if (cost_k > (4503599627370495LL - 1) / 4) { // (LLONG_MAX / 4) approx. 2.3 * 10^18 / 4 = 5.7 * 10^17
                                                        // 2^62 - 1 is the largest cost_k that can be multiplied by 4 without overflow.
                                                        // 2^62 - 1 = 4611686018427387903
                                                        // (2^62 - 1) * 4 = 2^64 - 4. This overflows.
                                                        // The largest cost_k that can be multiplied by 4 and then have 1 subtracted without overflow is (LLONG_MAX + 1) / 4 - 1.
                                                        // LLONG_MAX is 2^63 - 1.
                                                        // ( (2^63 - 1) + 1 ) / 4 - 1 = 2^63 / 4 - 1 = 2^61 - 1.
                                                        // So if cost_k is 2^61 - 1, then (cost_k + 1) * 4 - 1 = (2^61) * 4 - 1 = 2^63 - 1. This is LLONG_MAX.
                                                        // If cost_k is 2^61, then (cost_k + 1) * 4 - 1 = (2^61 + 1) * 4 - 1 = 2^63 + 4 - 1 = 2^63 + 3. This overflows.
                                                        // So, if cost_k >= 2^61, the next cost will overflow.
                                                        // 2^61 = 2305843009213693952.
                                                        // If cost_k is 2305843009213693951 (which is 2^61 - 1), the next cost is 2^63 - 1.
                                                        // If cost_k is 2^61 - 1, then cost_k + 1 = 2^61.
                                                        // (cost_k + 1) * 4 = 2^61 * 4 = 2^63.
                                                        // (cost_k + 1) * 4 - 1 = 2^63 - 1. This is LLONG_MAX.
                                                        // So, if cost_k is 2^61 - 1, the next cost is LLONG_MAX.
                                                        // If cost_k is already LLONG_MAX, then cost_k + 1 overflows.
                                                        // The largest possible cost_k is 2^61 - 1.
                                                        // If cost_k is 2^61 - 1, then next_cost = 2^63 - 1.
                                                        // If cost_k is 2^63 - 1, then next_cost would be 2^65 - 1, which overflows.
                                                        // So, we need to check if cost_k is already 2^63 - 1.
                                                        // If cost_k is 2^63 - 1, then (cost_k + 1) would be 2^63, which overflows.
                                                        // So, if cost_k == LLONG_MAX, we must break.
                                                        // Otherwise, if (cost_k + 1) > LLONG_MAX / 4, then (cost_k + 1) * 4 will overflow.
                                                        // LLONG_MAX / 4 is 2305843009213693951.
                                                        // So if cost_k + 1 > 2305843009213693951, then break.
                                                        // This means if cost_k >= 2305843009213693951, break.
                                                        // This is equivalent to cost_k >= (1LL << 61) - 1.
                                                        // The largest cost_k we can handle is 2^61 - 1.
                                                        // The next cost would be 2^63 - 1.
                                                        // If cost_k is 2^63 - 1, then cost_k + 1 overflows.
                                                        // So, if cost_k is already 2^63 - 1, we cannot compute the next cost.
            if (cost_k == 2305843009213693951LL) { // This is 2^61 - 1. The next cost will be 2^63 - 1 (LLONG_MAX).
                cost_k = 9223372036854775807LL; // Set to LLONG_MAX.
            } else if (cost_k == 9223372036854775807LL) { // This is LLONG_MAX. The next cost would overflow.
                break;
            } else {
                cost_k = (cost_k + 1) * 4 - 1;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // ending at index i, such that a[j] >= j for 0 <= j <= i.
    // This is equivalent to checking if a[i] >= i.
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len++;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // starting at index i, such that a[j] >= (n-1)-j for i <= j <= n-1.
    // This is equivalent to checking if a[i] >= (n-1)-i.
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1) - i) {
            right_len++;
        } else {
            break;
        }
    }

    // If the sum of these lengths is greater than or equal to n,
    // it means there's an overlap or they meet, implying a valid peak k exists.
    // Specifically, if left_len + right_len > n, it means there's at least one
    // index i that satisfies both conditions (a[i] >= i AND a[i] >= (n-1)-i).
    // Such an index i can be chosen as the peak k.
    if (left_len + right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

