int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For real solutions, d^2 - 4d >= 0
            // d(d - 4) >= 0
            // Since d >= 0, this means d - 4 >= 0, so d >= 4.
            // If d = 0, d^2 - 4d = 0, which is handled separately.
            // If d > 0 and d < 4, then d - 4 < 0, so d(d - 4) < 0, no real solutions.
            // If d >= 4, then d(d - 4) >= 0, real solutions exist.

            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // Solutions for 'a' are (d +/- sqrt(d^2 - 4d)) / 2
            // We can choose one for 'a' and the other for 'b'.
            // Let's pick the one with '+' for 'a' to ensure a >= b if d >= 4.
            // a = (d + sqrt_discriminant) / 2
            // b = (d - sqrt_discriminant) / 2

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Check non-negativity:
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant is real and non-negative.
            // a = (d + sqrt_discriminant) / 2.0 is clearly non-negative.
            // For b = (d - sqrt_discriminant) / 2.0 to be non-negative, we need d >= sqrt_discriminant.
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since d >= 0, we can square both sides)
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So, both a and b will be non-negative.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
