    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long N;
        std::cin >> N;
        long long chanek_coins = 0;
        long long opponent_coins = 0;
        bool chanek_turn = true;

        while (N > 0) {
            if (N % 2 != 0) { // N is odd
                if (chanek_turn) {
                    chanek_coins += 1;
                } else {
                    opponent_coins += 1;
                }
                N -= 1;
            } else { // N is even
                if (N == 2) { // Special case for N=2, always take 1
                    if (chanek_turn) {
                        chanek_coins += 1;
                    } else {
                        opponent_coins += 1;
                    }
                    N -= 1;
                } else if ((N / 2) % 2 != 0) { // N/2 is odd
                    // If N/2 is odd, taking N/2 leaves an odd number.
                    // Taking 1 leaves an odd number.
                    // Both options lead to an odd number for the opponent.
                    // The opponent will then take 1.
                    // If current player takes N/2, they get N/2. Opponent gets 1.
                    // If current player takes 1, they get 1. Opponent gets N/2.
                    // Current player wants to maximize their own coins.
                    // So, take N/2.
                    if (chanek_turn) {
                        chanek_coins += N / 2;
                    } else {
                        opponent_coins += N / 2;
                    }
                    N /= 2;
                } else { // N/2 is even
                    // If N/2 is even, taking N/2 leaves an even number.
                    // Taking 1 leaves an odd number.
                    // If current player takes N/2, they get N/2. Opponent faces N/2 (even).
                    // If current player takes 1, they get 1. Opponent faces N-1 (odd).
                    // The opponent will try to maximize their score.
                    // If opponent faces N/2 (even), they might take N/4 or 1.
                    // If opponent faces N-1 (odd), they will take 1.
                    // This is the tricky part.
                    // The optimal strategy for the current player is to take 1.
                    // This forces the opponent to face an odd number (N-1),
                    // from which they can only take 1.
                    // If the current player takes N/2, they get N/2.
                    // The opponent then faces N/2 (even).
                    // The opponent might take N/4, which is good for them.
                    // By taking 1, the current player ensures the opponent gets only 1 coin
                    // from this turn, and the current player gets 1 coin.
                    // The remaining N-1 coins are then processed.
                    // This is equivalent to saying that if N is even and N/2 is even,
                    // the current player should take 1.
                    if (chanek_turn) {
                        chanek_coins += 1;
                    } else {
                        opponent_coins += 1;
                    }
                    N -= 1;
                }
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_coins << "\n";
    }
    return 0;
}

