#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items are taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;
        int j = n - i; // Number of items taken from the right

        // Energy for items taken from left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for consecutive actions
        if (i > j) { // More items from left than right
            // The last (i-j) items must have been taken from the left,
            // meaning there were (i-j-1) consecutive left actions before the very last one.
            // Or, more simply, if i > j, there are i-j more left items.
            // These extra left items must have been taken consecutively at some point.
            // The minimum number of times we take an item from the left when the previous was also left
            // is (i - j - 1) if i > j and j > 0.
            // If j=0, all i items are from left, so (i-1) penalties.
            // If j>0, we can alternate until j items are taken from both sides.
            // Then we have i-j items remaining on the left.
            // These i-j items are taken consecutively from the left.
            // This means (i-j-1) penalties for Ql.
            // Example: L R L R L L L (i=5, j=2). After L R L R, we have L L L.
            // The first L L is one penalty, the second L L is another. Total 2 penalties.
            // i-j = 3. i-j-1 = 2.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // Similar logic for Qr
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

