#include <vector>
#include <algorithm>
#include <cmath>

long long get_max_divisor(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    std::vector<long long> q_prime_factors;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            q_prime_factors.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        q_prime_factors.push_back(temp_q);
    }

    long long max_x = 1;

    for (long long factor : q_prime_factors) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= factor;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

