// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 digits long
    // This effectively means padding with '0's from the left in the original number's representation
    // For example, 241 -> 100. Padded to 18 digits: 100000000000000000
    // The problem states "i-th from the right digit".
    // So, 241 (1st from right is 1, 2nd is 4, 3rd is 2)
    // Pattern for 241 is 100.
    // If pattern is s = 010, then 92, 2212, 50, 414 match.
    // 92: 2 (even) -> 0, 9 (odd) -> 1. Pattern: 10.
    // s = 010.
    // 92 (10) vs 010.
    // 1st from right: 0 vs 0 (match)
    // 2nd from right: 1 vs 1 (match)
    // 3rd from right: 0 (from padding 92) vs 0 (match)
    // This means the pattern string should be built from right to left, and then padded from the left.
    // Example: 241 -> 1 (odd), 4 (even), 2 (even) -> "100"
    // Example: 92 -> 2 (even), 9 (odd) -> "01"
    // The pattern string should be built by taking digits from right to left, and then padding with '0's on the left.
    // So, 241 -> "000000000000000100" (18 chars)
    // 92 -> "000000000000000010" (18 chars)

    std::string result = "";
    if (n == 0) { // Special case for 0
        result = "0";
    } else {
        long long temp_n = n;
        while (temp_n > 0) {
            result += ((temp_n % 10) % 2 == 0 ? '0' : '1');
            temp_n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 digits long
    // This string is effectively reversed compared to the problem's "i-th from the right"
    // So, 241 -> "100" (reversed digits' parities)
    // We need to pad this to 18 characters.
    while (result.length() < 18) {
        result += '0';
    }
    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 digits long
            // This means padding with '0's at the beginning of the string.
            // Example: s = "010" -> "000000000000000010" (18 chars)
            // The problem states "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // And "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // This means both the number's parity pattern and the query pattern should be normalized to the same length (18).
            // The `get_parity_pattern` function already produces an 18-char string by padding with '0's on the right (which corresponds to padding the number with '0's on the left).
            // So, for the query pattern `s`, we need to pad it with '0's on the left to match the 18-char length.
            // Example: s = "010". Length 3. Need to pad 15 '0's.
            // The problem's example: s = 010.
            // 92 -> 10. Padded to 18: 0...010. Matches 0...010.
            // 2212 -> 0100. Padded to 18: 0...00100. Matches 0...010.
            // This implies the pattern string should be built from right to left, and then padded from the left.
            // So, if s = "010", it means 1st from right is 0, 2nd is 1, 3rd is 0.
            // The `get_parity_pattern` function generates a string where the first character is the parity of the rightmost digit.
            // So, if s = "010", we need to reverse it to "010" (still "010") and then pad it to 18.
            // If s = "1", we need to reverse it to "1" and then pad it to 18.
            // The problem's example: s = 010.
            // 92: 2 (even) -> 0, 9 (odd) -> 1. Parity string: "01".
            // s = "010".
            // The comparison is "i-th from the right digit".
            // So, for 92, the digits are ...,0,9,2. Parities are ...,0,1,0.
            // For pattern "010", the pattern digits are ...,0,0,1,0.
            // This means the pattern string should be built by taking digits from right to left, and then padding with '0's on the left.
            // So, if s = "010", it means the pattern for comparison is "000000000000000010".
            // The `get_parity_pattern` function already produces this format.
            // So, for the query pattern `s`, we just need to pad it with '0's on the left.

            std::string padded_s = s;
            std::reverse(padded_s.begin(), padded_s.end()); // Reverse to match the internal representation
            while (padded_s.length() < 18) {
                padded_s += '0';
            }

            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

