#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_run(n);
    std::vector<int> right_zero_run(n);

    // Calculate left_zero_run: length of consecutive zeros to the left, including current
    left_zero_run[0] = (a[0] == 0 ? 1 : 0);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
        } else {
            left_zero_run[i] = 0;
        }
    }

    // Calculate right_zero_run: length of consecutive zeros to the right, including current
    right_zero_run[n - 1] = (a[n - 1] == 0 ? 1 : 0);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
        } else {
            right_zero_run[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            // Find the nearest 0 to the left and right
            int l = i - left_zero_run[i]; // Index of the 0 that starts the run of 0s ending at i-1, or -1 if no 0s
            int r = i + right_zero_run[i]; // Index of the 0 that starts the run of 0s starting at i+1, or n if no 0s

            // If a[i] is 1, it can only change if it's part of a 010 pattern.
            // This means it must be surrounded by 0s.
            // The distance to the nearest 1 on the left is `i - (l+1)`.
            // The distance to the nearest 1 on the right is `(r-1) - i`.
            // If l < 0, it means all elements to the left are 1s (or it's the first element).
            // If r >= n, it means all elements to the right are 1s (or it's the last element).

            // The actual distance to the nearest 1 on the left is `i - (l_idx + 1)` where `l_idx` is the index of the 1.
            // The actual distance to the nearest 1 on the right is `(r_idx - 1) - i` where `r_idx` is the index of the 1.

            // For a[i] to change from 1 to 0, it must be 1 and surrounded by 0s.
            // The number of steps for a 1 at index `i` to become 0 is `min(i - l_idx, r_idx - i)`.
            // Here, `l_idx` is the index of the nearest 1 to the left of `i`, and `r_idx` is the nearest 1 to the right.
            // If `a[i]` is 1, and `a[i-1]` is 0, and `a[i+1]` is 0, then `a[i]` becomes 0 in the next step.
            // This is equivalent to `a[i-1] == 0` and `a[i+1] == 0`.
            // The `left_zero_run[i-1]` gives the length of zeros ending at `i-1`.
            // The `right_zero_run[i+1]` gives the length of zeros starting at `i+1`.

            // The number of steps for a 1 at index `i` to become 0 is `min(dist_to_left_1, dist_to_right_1)`.
            // `dist_to_left_1` is `i - (index of nearest 1 to its left)`.
            // `dist_to_right_1` is `(index of nearest 1 to its right) - i`.
            // If `a[i]` is 1, and `a[i-1]` is 0, and `a[i+1]` is 0, then `a[i]` becomes 0.
            // This means `left_zero_run[i-1] >= 1` and `right_zero_run[i+1] >= 1`.
            // The number of steps for `a[i]` to become 0 is `min(left_zero_run[i-1], right_zero_run[i+1])`.
            // This is only if `i-1 >= 0` and `i+1 < n`.
            // If `i=0` or `i=n-1`, it never changes.
            // If `a[i]` is 1, and `a[i-1]` is 0, and `a[i+1]` is 0, then `a[i]` becomes 0.
            // The number of steps for `a[i]` to become 0 is `min(left_zero_run[i-1], right_zero_run[i+1])`.
            // This is only if `i-1 >= 0` and `i+1 < n`.
            // If `i=0` or `i=n-1`, it never changes.

            // The actual logic for a 1 at index `i` to become 0:
            // It needs to be surrounded by 0s.
            // The number of steps for `a[i]` to become 0 is `min(k_left, k_right)` where
            // `k_left` is the number of steps for the 1 to be "eaten" from the left.
            // `k_right` is the number of steps for the 1 to be "eaten" from the right.
            // `k_left` is `i - (index of nearest 1 to its left)`.
            // `k_right` is `(index of nearest 1 to its right) - i`.
            // If there's no 1 to the left, `k_left` is effectively infinity.
            // If there's no 1 to the right, `k_right` is effectively infinity.

            // Let's find the actual nearest 1s.
            int left_one_idx = -1;
            for (int j = i - 1; j >= 0; --j) {
                if (a[j] == 1) {
                    left_one_idx = j;
                    break;
                }
            }

            int right_one_idx = n;
            for (int j = i + 1; j < n; ++j) {
                if (a[j] == 1) {
                    right_one_idx = j;
                    break;
                }
            }

            int k_val = 0;
            if (left_one_idx == -1 && right_one_idx == n) {
                // All 1s, or a single 1. This 1 will never change.
                // This case is only possible if n=1 and a[0]=1, or n=2 and a=[1,1].
                // But we handle n<=2 separately.
                // For n > 2, if all are 1s, it's stable. If a single 1, it's stable.
                // This means a[i] is 1, and all other elements are 0.
                // E.g., 00100. This is stable.
                // So k_val = 0.
            } else if (left_one_idx == -1) { // No 1 to the left, only 0s.
                // Sequence starts with 0s, then 1s, then 0s, then 1s...
                // Example: 0011100. For the first 1, left_one_idx = -1.
                // The 1 at `i` is `a[i]`.
                // The number of steps for `a[i]` to become 0 is `right_one_idx - i`.
                k_val = right_one_idx - i;
            } else if (right_one_idx == n) { // No 1 to the right, only 0s.
                // Example: 0011100. For the last 1, right_one_idx = n.
                // The number of steps for `a[i]` to become 0 is `i - left_one_idx`.
                k_val = i - left_one_idx;
            } else { // 1s on both sides.
                // Example: 01010. For the middle 1, left_one_idx=1, right_one_idx=3.
                // k_val = min(i - left_one_idx, right_one_idx - i).
                k_val = std::min(i - left_one_idx, right_one_idx - i);
            }
            max_k = std::max(max_k, k_val);
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            // A 0 at index `i` becomes 1 if it's part of a 101 pattern.
            // This means `a[i-1] == 1` and `a[i+1] == 1`.
            // The number of steps for `a[i]` to become 1 is `min(i - left_one_idx, right_one_idx - i)`.
            // Here, `left_one_idx` is the index of the nearest 1 to the left of `i`.
            // `right_one_idx` is the index of the nearest 1 to the right of `i`.
            // If `a[i]` is 0, and `a[i-1]` is 1, and `a[i+1]` is 1, then `a[i]` becomes 1 in the next step.
            // This is equivalent to `left_zero_run[i-1] == 0` and `right_zero_run[i+1] == 0`.
            // The number of steps for `a[i]` to become 1 is `min(dist_to_left_1, dist_to_right_1)`.
            // `dist_to_left_1` is `i - (index of nearest 1 to its left)`.
            // `dist_to_right_1` is `(index of nearest 1 to its right) - i`.

            int left_one_idx = -1;
            for (int j = i - 1; j >= 0; --j) {
                if (a[j] == 1) {
                    left_one_idx = j;
                    break;
                }
            }

            int right_one_idx = n;
            for (int j = i + 1; j < n; ++j) {
                if (a[j] == 1) {
                    right_one_idx = j;
                    break;
                }
            }

            if (left_one_idx != -1 && right_one_idx != n) {
                int k_val = std::min(i - left_one_idx, right_one_idx - i);
                if (k_val <= max_k) {
                    b[i] = 1;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int k = 0; k <= 9; ++k) {
        std::string colors(n, ' ');
        bool possible_k = true;

        // Track the last digit placed in S1 and S2
        int last_s1_digit = -1; // Represents -infinity
        int last_s2_digit = -1; // Represents -infinity

        // First pass: assign digits < k to color 1, digits > k to color 2
        // Digits == k are temporarily unassigned.
        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < k) {
                if (digit < last_s1_digit) { // S1 must be non-decreasing
                    possible_k = false;
                    break;
                }
                colors[i] = '1';
                last_s1_digit = digit;
            } else if (digit > k) {
                if (digit < last_s2_digit) { // S2 must be non-decreasing
                    possible_k = false;
                    break;
                }
                colors[i] = '2';
                last_s2_digit = digit;
            }
        }

        if (!possible_k) {
            continue; // Try next k
        }

        // Second pass: assign digits == k
        // Digits equal to k that appear before the first digit > k (in original string)
        // should be colored 1 if possible.
        // Digits equal to k that appear after the first digit > k (in original string)
        // should be colored 2 if possible.
        // This is equivalent to: color '1' as long as it maintains S1 sorted, then switch to '2'.

        // Find the first digit that was assigned '2' (meaning it was > k)
        int first_s2_idx = -1;
        for(int i = 0; i < n; ++i) {
            if (colors[i] == '2') {
                first_s2_idx = i;
                break;
            }
        }

        // If no digit was assigned '2' yet, all remaining 'k's can be '1'
        // or all can be '2'. Let's try to assign '1' first.
        // If all digits are <= k, we can assign all 'k's to '1'.
        // If all digits are >= k, we can assign all 'k's to '2'.
        // The logic below handles this by trying to assign '1' first, then '2'.

        // The actual split point for digits equal to k
        // All d_i = k before this split point go to S1, after go to S2.
        // This split point is determined by the first d_i = k that we assign to S2.
        // We want to find the largest possible `last_s1_digit` and smallest possible `first_s2_digit`.
        // The `k` value itself acts as the boundary.
        // So, all `d_i = k` that are assigned to `1` must be `k`.
        // All `d_i = k` that are assigned to `2` must be `k`.
        // The critical condition is `last_s1_digit <= first_s2_digit`.
        // If `last_s1_digit` is the last digit assigned to S1, and `first_s2_digit` is the first digit assigned to S2.
        // For digits `d_i = k`:
        // We can assign them to '1' as long as `k >= last_s1_digit`.
        // We can assign them to '2' as long as `k >= last_s2_digit`.
        // The overall condition is that the last digit of S1 must be <= the first digit of S2.
        // If we assign `d_i = k` to '1', `last_s1_digit` becomes `k`.
        // If we assign `d_i = k` to '2', `last_s2_digit` becomes `k`.

        // Let's try to assign '1' to all 'k's first, then switch to '2'
        // This means we find a pivot point `p`. All `d_i = k` for `i < p` are '1', for `i >= p` are '2'.
        // The `last_s1_digit` will be `k` (if any `k` is assigned to '1') or the largest `d_j < k`.
        // The `first_s2_digit` will be `k` (if any `k` is assigned to '2') or the smallest `d_j > k`.

        // A simpler approach:
        // Iterate through the string.
        // If digit < k, assign '1'. Check sorted.
        // If digit > k, assign '2'. Check sorted.
        // If digit == k:
        //   If we haven't started assigning '2's yet (i.e., `last_s2_digit` is still -1 or `last_s1_digit` is still -1):
        //     Assign '1'. Update `last_s1_digit`.
        //   Else (we have already assigned some '2's, meaning `last_s2_digit` is not -1):
        //     Assign '2'. Update `last_s2_digit`.
        // This strategy ensures that all 'k's are grouped together, either all '1's then all '2's.
        // The boundary between '1's and '2's for digits equal to `k` is implicitly defined.

