struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // All f values are a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The optimal strategy for minimizing max(f) - min(f) is to put a[0] in one subsequence
    // and a[1], ..., a[n-1] in the other, OR a[n-1] in one and a[0], ..., a[n-2] in the other.
    // Let's try putting a[0] in subsequence 1, and a[1], ..., a[n-1] in subsequence 2.
    //
    // min_f:
    //   - If n=2: a[0] in sub1, a[1] in sub2. Only f(a[0], a[1]) = a[0]+a[1]+h. min_f = max_f = a[0]+a[1]+h. Goodness = 0.
    //   - If n > 2:
    //     - Pairs in sub2: Smallest sum is a[1].value + a[2].value.
    //     - Pairs across sub1 and sub2: Smallest sum is a[0].value + a[1].value + h.
    //     min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h).
    //
    // max_f:
    //   - If n=2: a[0]+a[1]+h.
    //   - If n > 2:
    //     - Pairs in sub2: Largest sum is a[n-2].value + a[n-1].value.
    //     - Pairs across sub1 and sub2: Largest sum is a[0].value + a[n-1].value + h.
    //     max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h).
    //
    // Goodness = max_f - min_f.

    long long goodness2;
    std::vector<int> partition2(n);

    if (n == 2) {
        goodness2 = 0; // Only one pair (a[0], a[1]), always different subsequences. f = a[0]+a[1]+h.
        partition2[a[0].original_index] = 1;
        partition2[a[1].original_index] = 2;
    } else {
        long long min_f_sub2_internal = a[1].value + a[2].value;
        long long min_f_cross = a[0].value + a[1].value + h;
        long long min_f_case2 = std::min(min_f_sub2_internal, min_f_cross);

        long long max_f_sub2_internal = a[n - 2].value + a[n - 1].value;
        long long max_f_cross = a[0].value + a[n - 1].value + h;
        long long max_f_case2 = std::max(max_f_sub2_internal, max_f_cross);

        goodness2 = max_f_case2 - min_f_case2;

        partition2[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition2[a[i].original_index] = 2;
        }
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

