        // This works because `s.substr(0, n/2)` is the reverse of `s.substr(n/2+1)` (due to `s` being a palindrome).
        // So `s.substr(n/2+1)` + `s.substr(n/2, 1)` + `s.substr(0, n/2)`
        // is `reverse(s.substr(0, n/2))` + `s.substr(n/2, 1)` + `s.substr(0, n/2)`.
        // This is a palindrome if `s.substr(n/2, 1)` is the middle character.
        // This new string is `reverse(P) + M + P`. This is a palindrome.
        // Is it different from `s`? `s = P + M + reverse(P)`.
        // If `P` is not a palindrome, then `reverse(P) != P`.
        // If `P` is not a palindrome, then `reverse(P) + M + P` is different from `P + M + reverse(P)`.
        // Example: `s = "abacaba"`. `P = "aba"`. `M = "c"`. `reverse(P) = "aba"`.
        // `s = "aba" + "c" + "aba"`.
        // `s_prime = "aba" + "c" + "aba"`. This is `s`.
        // This strategy only works if `P` is not a palindrome.
        //
        // The condition for k=2 is simply "not all characters are the same".
        // If all characters are the same, it's impossible.
        // Otherwise, it's 1 or 2. Since we already checked 1, if it's not 1, it must be 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            return true;
        }

        long long current_h = h[h_idx];

        // If current head can cover p[p_idx]
        if (std::abs(current_h - p[p_idx]) <= T) {
            // This head can cover p[p_idx] and potentially more tracks to its right.
            // The rightmost track this head can cover is current_h + T.
            long long cover_limit = current_h + T;

            // Advance p_idx past all tracks covered by this head.
            while (p_idx < m && p[p_idx] <= cover_limit) {
                p_idx++;
            }
        }
    }
    return p_idx == m; // True if all tracks are covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10, so 2*10^10 is a safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for sums to prevent overflow
// Using -2 as a sentinel for "not computed yet" and -1 for "infinite loop"
std::vector<long long> dp_y;
std::vector<long long> dp_x_final;
std::vector<bool> visited; // To detect cycles

int N;
std::vector<long long> A_vals; // Stores a_2, ..., a_N. Index 0 is a_2, etc.
                               // So A_vals[k-2] corresponds to a_k for k >= 2.

void solve(int start_x_val) {
    // This function computes dp_y[start_x_val] and dp_x_final[start_x_val]
    // for a given starting x_val (which is a_1).
    // The actual a_1 value is `start_x_val`.

    // If already computed, return.
    if (dp_y[start_x_val] != -2) {
        return;
    }

    // Mark as visited to detect cycles
    visited[start_x_val] = true;

    long long current_a_val = start_x_val; // This is a_1

    // After first step (x increases by a_x, y increases by a_x)
    long long next_x_after_step2 = start_x_val + current_a_val;
    long long current_y_sum = current_a_val;

    // After second step (y increases by a_x, x decreases by a_x)
    long long next_x_after_step3 = next_x_after_step2 - current_a_val; // This is just start_x_val
    // current_y_sum += current_a_val; // This is not needed, as the problem states y increases by a_x while x decreases by a_x.
                                     // The total y increase for one full cycle (step 2 then step 3) is 2 * a_x.
                                     // But the problem description is a bit ambiguous.
                                     // "The program increases both x and y by a value equal to a_x simultaneously."
                                     // "The program now increases y by a_x while decreasing x by a_x."
                                     // This means:
                                     // x_new = x_old + a_x, y_new = y_old + a_x
                                     // x_final = x_new - a_x, y_final = y_new + a_x
                                     // So, x_final = x_old, y_final = y_old + 2*a_x.
                                     // This is for one full cycle.
                                     // The problem states "The program executes steps 2 and 3 (first step 2, then step 3) repeatedly until it terminates".
                                     // This implies that the state (x,y) is updated after each step.
                                     // Let's re-evaluate based on the example:
                                     // For i = 1, a_1 = 1.
                                     // Initial: x=1, y=0.
                                     // Step 2: x = 1+a_1 = 1+1 = 2. y = 0+a_1 = 0+1 = 1.
                                     // Step 3: x = 2-a_2 = 2-2 = 0. y = 1+a_2 = 1+2 = 3.
                                     // x=0, terminates. Final y=3.
                                     // This matches the example.
                                     // So, the state after step 2 is (x_old + a_x, y_old + a_x).
                                     // The state after step 3 is (x_old + a_x - a_{x_old+a_x}, y_old + a_x + a_{x_old+a_x}).
                                     // The next a_x is based on the x value *after* step 2.

    // Let's use the example trace logic.
    // Current state: (x, y)
    // Value a_x is `current_a_val`.
    // After step 2: (x + current_a_val, y + current_a_val)
    // Let new_x = x + current_a_val.
    // If new_x <= 0 or new_x > N, program terminates.
    // Otherwise, get a_new_x.
    // After step 3: (new_x - a_new_x, y + current_a_val + a_new_x)
    // Let final_x_for_this_iteration = new_x - a_new_x.
    // Let final_y_for_this_iteration = y + current_a_val + a_new_x.
    // If final_x_for_this_iteration <= 0 or final_x_for_this_iteration > N, program terminates.
    // Otherwise, the next iteration starts with (final_x_for_this_iteration, final_y_for_this_iteration).

    // The problem statement is "The program increases both x and y by a value equal to a_x simultaneously."
    // This a_x is based on the x at the *start* of step 2.
    // "The program now increases y by a_x while decreasing x by a_x."
    // This a_x is based on the x at the *start* of step 3 (which is the x *after* step 2).

    // Let's define the state as (current_x, current_y_total).
    // Initial call: solve(start_x_val) means a_1 = start_x_val.
    // The first step is always x=1, y=0.
    // The value a_x is a_1 = start_x_val.
    // After step 2: x becomes 1 + start_x_val. y becomes 0 + start_x_val.
    // Let x_prime = 1 + start_x_val.
    // Let y_prime = start_x_val.

    // Check termination after step 2
    if (next_x_after_step2 <= 0 || next_x_after_step2 > N) {
        dp_y[start_x_val] = current_y_sum;
        dp_x_final[start_x_val] = next_x_after_step2;
        visited[start_x_val] = false; // Unmark
        return;
    }

    // Get a_x_prime for step 3
    long long a_x_prime;
    if (next_x_after_step2 == 1) { // This case should not happen if we are computing for a_1
        // This branch is for when the current x is 1, but we are computing for a_1.
        // This means we are in a recursive call where the next x is 1.
        // In this case, a_1 is the original start_x_val.
        a_x_prime = start_x_val;
    } else {
        a_x_prime = A_vals[next_x_after_step2 - 2];
    }

    // After step 3:
    long long final_x_for_this_iteration = next_x_after_step2 - a_x_prime;
    long long final_y_for_this_iteration = current_y_sum + a_x_prime;

    // Check termination after step 3
    if (final_x_for_this_iteration <= 0 || final_x_for_this_iteration > N) {
        dp_y[start_x_val] = final_y_for_this_iteration;
        dp_x_final[start_x_val] = final_x_for_this_iteration;
        visited[start_x_val] = false; // Unmark
        return;
    }

    // If not terminated, recurse
    // The next state is (final_x_for_this_iteration, final_y_for_this_iteration)
    // But the DP state is only based on the starting a_1 value.
    // We need to find the result for the state (final_x_for_this_iteration, 0)
    // and then add final_y_for_this_iteration to it.
    // This is where the problem structure is tricky.
    // The problem states: "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
    // This means a_1 is set to `i`.
    // The simulation is always from x=1, y=0.
    // The recursive structure should be:
    // `solve(current_x, current_y_total)`
    // But the DP state is `dp_y[a_1_val]`. This means we need to find a way to combine results.

    // Let's re-read carefully: "The program increases both x and y by a value equal to a_x simultaneously."
    // "The program now increases y by a_x while decreasing x by a_x."
    // This implies that the `a_x` in the second sentence is based on the `x` *after* the first sentence.
    // Let `x_curr` be the current `x`.
    // Let `y_curr` be the current `y`.
    // `val1 = a[x_curr]`
    // `x_temp = x_curr + val1`
    // `y_temp = y_curr + val1`
    // If `x_temp` terminates, `y_final = y_temp`.
    // Else, `val2 = a[x_temp]`
    // `x_next = x_temp - val2`
    // `y_next = y_temp + val2`
    // If `x_next` terminates, `y_final = y_next`.
    // Else, repeat with `x_next`, `y_next`.

    // This is a standard DP on states.
    // The state is `x`. The `y` value accumulates.
    // `dp_y[x]` stores the total `y` accumulated *from* `x` *until termination*.
    // `dp_x_final[x]` stores the final `x` value *from* `x` *until termination*.

    // Let's define `f(x)` as a pair `(final_x, total_y_added_from_x)`.
    // If `x` is the current position, `y_total` is the current accumulated `y`.
    // `val1 = a[x]`
    // `x_temp = x + val1`
    // `y_temp_added = val1`
    // If `x_temp <= 0` or `x_temp > N`:
    //   `f(x) = (x_temp, y_temp_added)`
    // Else:
    //   `val2 = a[x_temp]`
    //   `x_next = x_temp - val2`
    //   `y_next_added = y_temp_added + val2`
    //   If `x_next <= 0` or `x_next > N`:
    //     `f(x) = (x_next, y_next_added)`
    //   Else:
    //     If `x_next` is currently being visited (cycle detected):
    //       `f(x) = (-1, -1)` (infinite loop)
    //     Else:
    //       `solve(x_next)` (recursive call to compute `f(x_next)`)
    //       If `dp_y[x_next] == -1` (infinite loop from `x_next`):
    //         `f(x) = (-1, -1)`
    //       Else:
    //         `f(x) = (dp_x_final[x_next], y_next_added + dp_y[x_next])`

    // The `start_x_val` in `solve(start_x_val)` is actually `a_1`.
    // The DP state should be `dp_y[current_x]` and `dp_x_final[current_x]`.
    // Let's redefine `dp_y` and `dp_x_final` to be indexed by `x` (1 to N).
    // `dp_y[k]` stores the total `y` added *from* `x=k` until termination.
    // `dp_x_final[k]` stores the final `x` value when starting from `x=k`.
    // `visited[k]` tracks if `x=k` is currently in the recursion stack.

    // The `A_vals` array needs to be `a_1, a_2, ..., a_N`.
    // For each query `i`, `a_1` is `i`.
    // So, `A_vals[0]` will be `i`. `A_vals[k]` will be `a_{k+1}`.
    // This means `A_vals` should be `N+1` size. `A_vals[0]` unused, `A_vals[1]` is `a_1`, `A_vals[k]` is `a_k`.

    // Let's adjust `A_vals` and DP states.
    // `A_vals` will store `a_1, a_2, ..., a_N`.
    // `A_vals[0]` is unused. `A_vals[k]` stores `a_k`.
    // `dp_y` and `dp_x_final` will be size `N+1`, indexed 1 to N.
    // `visited` will be size `N+1`, indexed 1 to N.

    // The `solve` function will compute `dp_y[x_start]` and `dp_x_final[x_start]`.
    // `x_start` is the current `x` position.

    // Re-initialize DP arrays for each query `i` is too slow.
    // The DP should be for the fixed `a_2, ..., a_N` values.
    // For each `i`, `a_1` is `i`.
    // This means `a_1` is dynamic.
    // The DP state `dp_y[x]` and `dp_x_final[x]` should represent the outcome
    // if the program *starts* at `x` with `y=0`, and `a_x` is the value at `x`.
    // But `a_1` changes.

    // The problem is that `a_1` is special.
    // For `x=1`, `a_x` is `i`.
    // For `x > 1`, `a_x` is `A_vals[x-2]` (from input).

    // Let's define a helper function `get_a_val(idx, a1_val)`:
    // `long long get_a_val(int idx, int a1_val)`
    // `  if (idx == 1) return a1_val;`
    // `  return A_vals[idx-2];`

    // The DP state `dp_y[x]` and `dp_x_final[x]` should be independent of `a_1`.
    // This means `dp_y[x]` and `dp_x_final[x]` are for `x > 1`.
    // For `x=1`, we need to compute it for each `a_1 = i`.

    // This suggests that for `x > 1`, the `a_x` values are fixed.
    // We can precompute `dp_y[k]` and `dp_x_final[k]` for `k = 2, ..., N`.
    // Then, for each query `i` (which sets `a_1 = i`):
    // We simulate the first step from `x=1`.
    // `x_curr = 1`, `y_curr = 0`.
    // `val1 = i`.
    // `x_temp = x_curr + val1`.
    // `y_temp = y_curr + val1`.
    // If `x_temp <= 0` or `x_temp > N`:
    //   Output `y_temp`.
    // Else:
    //   `val2 = get_a_val(x_temp, i)`. (This is `A_vals[x_temp-2]`)
    //   `x_next = x_temp - val2`.
    //   `y_next = y_temp + val2`.
    //   If `x_next <= 0` or `x_next > N`:
    //     Output `y_next`.
    //   Else:
    //     // Now we are at `x_next` with `y_next` accumulated.
    //     // We need to find the result from `x_next`.
    //     // This is where `dp_y[x_next]` and `dp_x_final[x_next]` come in.
    //     // But `dp_y[x_next]` and `dp_x_final[x_next]` are computed assuming `a_1` is fixed.
    //     // This is the core issue. `a_1` is not fixed.

    // The problem statement: "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
    // This means `a_1` is `i`.
    // The `a_x` values are fixed for `x >= 2`.
    // The `a_x` value for `x=1` is `i`.

    // Let's define `solve_dp(current_x, a1_val)` which returns `(final_x, total_y_added)`.
    // This would be `N * N` states, too slow. `N` is `2*10^5`.

    // The key observation must be that the `a_x` values for `x > 1` are fixed.
    // The only `a_x` that changes is `a_1`.
    // Let's trace the path:
    // Start: `x=1, y=0`. `a_1 = i`.
    // Step 2: `x_new = 1 + i`, `y_new = i`.
    // If `x_new` terminates, done.
    // Step 3: `a_x_new = a_{1+i}`.
    // `x_final = (1+i) - a_{1+i}`, `y_final = i + a_{1+i}`.
    // If `x_final` terminates, done.
    // Else, we are at `x_final` with `y_final`.
    // Now, the next `a_x` will be `a_{x_final}`.
    // If `x_final = 1`, then `a_{x_final}` is `i`.
    // If `x_final > 1`, then `a_{x_final}` is `A_vals[x_final-2]`.

    // This means the path can only depend on `i` if `x` becomes `1` again.
    // If `x` never becomes `1` again, then the `a_x` values are fixed (for `x > 1`).
    // So, we can compute `dp_y[k]` and `dp_x_final[k]` for `k = 2, ..., N`.
    // These DP values represent the outcome if the program starts at `x=k` (with `y=0`)
    // and `a_x` is always `A_vals[x-2]` for `x >= 2`.
    // If the path from `x=k` ever reaches `x=1`, then this DP state is invalid.
    // Or, we can make `dp_y[k]` and `dp_x_final[k]` store `(final_x, total_y_added, did_it_hit_1)`.

    // Let's define `dp_y[k]` as the total `y` added if starting at `x=k` (with `y=0`)
    // and `a_x` is `A_vals[x-2]` for all `x >= 2`.
    // `dp_x_final[k]` is the final `x` value.
    // `dp_hit_1[k]` is a boolean indicating if the path starting at `x=k` ever hits `x=1`.

    // Initialize `dp_y` with -2 (uncomputed), `dp_x_final` with -2, `visited` with false.
    // `N` is `2*10^5`.
    // `A_vals` stores `a_2, ..., a_N`. Size `N-1`.
    // `dp_y` size `N+1`. `dp_y[0]` unused. `dp_y[1]` is special.
    // `dp_x_final` size `N+1`.
    // `visited` size `N+1`.

    // Function `compute_dp_for_fixed_a(x_start)`:
    // This computes `dp_y[x_start]` and `dp_x_final[x_start]` assuming `a_k = A_vals[k-2]` for all `k >= 2`.
    // If `x_start == 1`, this function is not called.
    // If `x_start` is already computed, return.
    // If `x_start` is visited (cycle), set `dp_y[x_start] = -1`, `dp_x_final[x_start] = -1`, return.
    // Mark `x_start` as visited.

    // `val1 = A_vals[x_start-2]`
    // `x_temp = x_start + val1`
    // `y_temp_added = val1`
    // If `x_temp <= 0` or `x_temp > N`:
    //   `dp_y[x_start] = y_temp_added`
    //   `dp_x_final[x_start] = x_temp`
    // Else:
    //   `val2 = A_vals[x_temp-2]` (This is where `x_temp` could be 1. If `x_temp == 1`, this is wrong.)
    //   This means `compute_dp_for_fixed_a` cannot be used if the path hits `x=1`.

    // This problem is a graph problem. Each `x` is a node.
    // From `x`, we go to `x_temp = x + a_x`, then to `x_next = x_temp - a_{x_temp}`.
    // The `y` value accumulates.
    // The `a_x` values are fixed for `x >= 2`.
    // For `x=1`, `a_1` is `i`.

    // Let's define `dp_y[k]` and `dp_x_final[k]` for `k = 1, ..., N`.
    // These will store the results for the *current* `a_1` value.
    // This means we need to clear/recompute for each `i`. Too slow.

    // The only way this is fast enough is if the `a_1` value only affects the first few steps,
    // and then the path merges into a precomputed path.
    // Or, if the path from `x=1` (with `a_1=i`) never hits `x=1` again.

    // Let's consider the structure of the path:
    // `1 -> x_temp -> x_next -> x_next_temp -> x_next_next -> ...`
    // `x_temp = 1 + i`
    // `x_next = (1+i) - a_{1+i}`
    // `x_next_temp = x_next + a_{x_next}`
    // `x_next_next = x_next_temp - a_{x_next_temp}`

    // If `x_next` is `1`, then `a_{x_next}` is `i`.
    // If `x_next` is `k > 1`, then `a_{x_next}` is `A_vals[k-2]`.

    // This is a standard DP problem on a graph where edges have weights (y-increase) and target nodes.
    // The graph is `N` nodes. Each node `x` has an outgoing edge to `x_next = (x+a_x) - a_{x+a_x}`.
    // The weight of this edge is `a_x + a_{x+a_x}`.
    // The problem is that `a_1` is variable.

    // What if we compute `dp_y[k]` and `dp_x_final[k]` for `k = 2, ..., N`?
    // These values are computed assuming `a_x = A_vals[x-2]` for all `x >= 2`.
    // If during this computation, we encounter `x=1`, we cannot use this DP.
    // So, `dp_y[k]` and `dp_x_final[k]` should store `(final_x, total_y_added, did_hit_1)`.

    // Let's define `dp_y[k]` and `dp_x_final[k]` for `k = 1, ..., N`.
    // `dp_y[k]` stores the total `y` added if starting at `x=k` (with `y=0`)
    // and `a_x` is `A_vals[x-2]` for `x >= 2`.
    // `dp_x_final[k]` stores the final `x` value.
    // `dp_y[1]` and `dp_x_final[1]` are special. They are computed for each `i`.

    // Let's use a recursive function with memoization for `x >= 2`.
    // `pair<long long, long long> compute_path(int current_x)`
    // This function computes the `(final_x, total_y_added)` starting from `current_x`
    // assuming `a_k = A_vals[k-2]` for all `k >= 2`.
    // If `current_x == 1`, it returns `(1, 0)` (special case, means it hit 1).

    // `dp_y` and `dp_x_final` will be for `x >= 2`.
    // `dp_y[k]` stores `y` sum for `x=k`.
    // `dp_x_final[k]` stores final `x` for `x=k`.
    // `visited[k]` for cycle detection.

    // `compute_path_from_x_ge_2(int x_start)`:
    // If `x_start <= 0` or `x_start > N`, return `(x_start, 0)`. (Base case: already terminated)
    // If `x_start == 1`, return `(1, 0)`. (Special case: hit x=1, cannot use this DP further)
    // If `dp_y[x_start]` is not -2, return `(dp_x_final[x_start], dp_y[x_start])`. (Memoized)
    // If `visited[x_start]` is true, return `(-1, -1)`. (Cycle detected)

    // `visited[x_start] = true`.
    // `val1 = A_vals[x_start-2]`.
    // `x_temp = x_start + val1`.
    // `y_temp_added = val1`.

    // If `x_temp <= 0` or `x_temp > N`:
