void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution always exists.
    // A simple solution is to reverse the permutation.
    // The sums of adjacent elements for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The sums of adjacent elements for reversed_p are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These two sets of sums are identical, just in a different order.
    // Since the fingerprint involves sorting these sums, the fingerprints will be identical.
    // The reversed permutation is different from the original permutation unless
    // the original permutation is a palindrome (p_i = p_{n-i+1} for all i).
    // However, for a permutation of distinct elements from 1 to n,
    // a permutation can only be a palindrome if n=1 (which is not allowed, n>=2)
    // or if it's a specific structure like [1,2,1] (not a permutation) or [1,2,3,2,1] (not a permutation).
    // A permutation like [1,2,3,4,5] reversed is [5,4,3,2,1]. These are different.
    // A permutation like [1,3,2] reversed is [2,3,1]. These are different.
    // In general, for n >= 2, a permutation p cannot be equal to its reverse p_rev.
    // If p_i = p_{n-i+1} for all i, then p_1 = p_n, p_2 = p_{n-1}, etc.
    // Since all elements in a permutation must be distinct, this can only happen if n=1.
    // For n >= 2, p_1 must be different from p_n (unless n=1).
    // If p_1 = p_n, then p is not a permutation because elements must be distinct.
    // Therefore, p_1 != p_n for n >= 2.
    // This implies that p is always different from its reverse p_rev.
    // So, reversing the permutation always yields a valid different permutation with the same fingerprint.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << "\n";
}

