        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            long long cost_per_haybale = i; // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 is i days

            if (d >= cost_per_haybale) {
                // Calculate how many haybales can be moved from this pile
                long long haybales_to_move = std::min((long long)a[i], d / cost_per_haybale);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile
                // Since piles are processed in increasing order of cost,
                // we won't be able to move haybales from subsequent piles either.
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

