void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else if (n == 2) {
        std::cout << 57 << "\n"; // Example solution, 57 % 5 != 0, 57 % 7 != 0
    } else if (n == 3) {
        std::cout << 239 << "\n"; // Example solution, 239 % 2 != 0, 239 % 3 != 0, 239 % 9 != 0
    } else {
        // For n >= 4, we can construct a number using 2, 3, and then 7s.
        // The number will be 2377...7.
        // The digits are 2, 3, and 7.
        // A number consisting of 2, 3, and (n-2) sevens.
        // Sum of digits: 2 + 3 + (n-2)*7 = 5 + 7n - 14 = 7n - 9.
        // For n >= 4:
        // 7n - 9 is not divisible by 3 if 7n - 9 is not divisible by 3.
        // 7n - 9 = (6n + n) - 9 = 3*(2n-3) + n.
        // So 7n - 9 is divisible by 3 iff n is divisible by 3.
        // If n is divisible by 3, then the sum of digits is divisible by 3,
        // and thus the number itself is divisible by 3.
        // This would violate the condition that s is not divisible by 3.
        // So, this construction (237...7) works if n is NOT divisible by 3.

        // If n is divisible by 3, we need a different construction.
        // Let's try 239...9.
        // Digits are 2, 3, and (n-2) nines.
        // Sum of digits: 2 + 3 + (n-2)*9 = 5 + 9n - 18 = 9n - 13.
        // 9n - 13 is never divisible by 3 (since 9n is, but 13 is not).
        // So, the number 239...9 is never divisible by 3.
        // It's also not divisible by 2 (ends in 9).
        // It's also not divisible by 9 (sum of digits 9n-13 is not divisible by 9).
        // This construction works for all n >= 2.
        // For n=2: 23. Valid.
        // For n=3: 239. Valid.
        // For n >= 4: 239...9.
        // This seems to be a robust solution for n >= 2.

        std::cout << 2;
        std::cout << 3;
        for (int i = 0; i < n - 2; ++i) {
            std::cout << 9;
        }
        std::cout << "\n";
    }
}

