void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this element,
        // or it can be achieved if either +1 or -1 is available.
        // The crucial part is that if a[i] needs to change, the required
        // sign must be available from an earlier element.
        // The `has_pos_one` and `has_neg_one` flags are updated
        // based on elements up to index `i-1`.
        // This is implicitly handled by checking the flags before `a[i]` is processed.
        // The flags `has_pos_one` and `has_neg_one` correctly reflect
        // if a +1 or -1 exists at an index < current `i`.
    }

    std::cout << "YES\n";
}

