int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from C's stdio and prevents flushing cout before cin.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // For N up to 150000, a vector is efficient.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n <= 1) {
            // If there's only one day or no days, there can't be any later lower price.
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix_price with the last element's price.
        // This variable will store the minimum price encountered so far
        // when iterating from right to left.
        int min_suffix_price = a[n - 1];

        // Iterate from the second-to-last element backwards to the first element.
        // For each element a[i], we compare it with the minimum price found
        // in the suffix a[i+1...n-1].
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                // If the current price a[i] is greater than the minimum price
                // found in any subsequent day, then a[i] is a bad price.
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price, it means
                // a[i] is either equal to or less than the current minimum.
                // In this case, a[i] itself becomes a new candidate for the
                // minimum price in the suffix starting from this position.
                min_suffix_price = a[i];
            }
        }

        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Only consider off-diagonal elements
                if (a[i][j] > max_val_in_row) {
                    max_val_in_row = a[i][j];
                }
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any value in p is missing from 1 to n.
    // If n is not present in p, it means all p[i] are less than n.
    // This implies that for some i, p[i] must be n.
    // If max_val_in_row for all i is less than n, then the actual p[i]
    // for some i must be n.
    // The problem guarantees a solution exists.
    // If n is not present in the current p, it means one of the p[i]
    // that we calculated as max_val_in_row must actually be n.
    // This happens if all other p[j] (for j != i) are smaller than n,
    // and p[i] is the largest value among them.
    // In such a case, max(a[i][j] for j != i) would be p[k] where p[k] is the
    // largest value among p[j] (j != i). If p[i] is n, and all other p[j] < n,
    // then max(a[i][j]) would be max(p[j]) for j != i, which is < n.
    // So, if n is not found in the current p, we must replace one of the
    // p[i] with n. Which one? Any p[i] that is currently max_val_in_row.
    // Since the problem guarantees a solution, and we know that the values
    // in p must be a permutation of 1 to n, if n is not present, it must be
    // that one of the p[i] values we derived (which is max_val_in_row)
    // should actually be n.
    // The simplest way to handle this is to find the maximum value in the
    // derived p, and if it's less than n, replace it with n.
    // This works because if p[i] = n, then for any j != i, a[i][j] = min(n, p[j]) = p[j].
    // So max(a[i][j] for j != i) would be max(p[j] for j != i).
    // This max(p[j] for j != i) would be the second largest value in the permutation.
    // If we set p[i] to this second largest value, and n is not in p,
    // we need to correct it.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found in the derived p, it means one of the p[i]
        // that we calculated as max_val_in_row should actually be n.
        // This happens when the true p[i] is n, and all other p[j] are less than n.
        // In this case, max(a[i][j] for j != i) would be the maximum of all other p[j]'s,
        // which is the second largest value in the permutation.
        // We need to find an index k such that p[k] is currently the maximum value
        // among the derived p, and replace p[k] with n.
        // This ensures that n is present in the permutation.
        int max_p_val = 0;
        int max_p_idx = -1;
        for (int i = 0; i < n; ++i) {
            if (p[i] > max_p_val) {
                max_p_val = p[i];
                max_p_idx = i;
            }
        }
        if (max_p_idx != -1) { // Should always be true for n >= 2
            p[max_p_idx] = n;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

