        int last_r_pos = -1; // Position of the last 'R' encountered, or -1 for cell 0

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1.
                // The distance from the previous 'R' (or cell 0) to this 'R' is (i+1) - (last_r_pos + 1)
                // which simplifies to i - last_r_pos.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' to cell n+1.
        // The last 'R' was at index `last_r_pos`, which corresponds to cell `last_r_pos + 1`.
        // The target is cell `s.length() + 1`.
        // The distance is (s.length() + 1) - (last_r_pos + 1) = s.length() - last_r_pos.
        max_gap = std::max(max_gap, (int)s.length() - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available divided by 3 (each team needs 3 members).
        // 4. The sum of coders and mathematicians, as these are the "critical" roles.
        //    If we have k teams, we need at least k coders and k mathematicians.
        //    The remaining k members can be any type.
        //    So, we need at least k coders and k mathematicians.
        //    The total number of students used is 3k.
        //    The number of coders and mathematicians available is c + m.
        //    The number of students without specialization is x.
        //    The total students available is c + m + x.
        //    The number of "critical" students (coders or mathematicians) needed is 2k (at least one of each).
        //    The number of "flexible" students (any type) needed is k.
        //    So, k teams require k coders, k mathematicians, and k additional students.
        //    The additional k students can be drawn from remaining coders, mathematicians, or x.
        //    The total number of students available for these k additional slots is (c-k) + (m-k) + x.
        //    This must be at least k.
        //    (c-k) + (m-k) + x >= k
        //    c + m + x - 2k >= k
        //    c + m + x >= 3k
        //    k <= (c + m + x) / 3

        // Combining all constraints:
        // k <= c
        // k <= m
        // k <= (c + m + x) / 3

        // The most restrictive constraint will be the minimum of these three.
        // However, the problem can be simplified by realizing that the number of teams
        // cannot exceed the minimum of coders and mathematicians, because each team
        // *must* have at least one of each.
        // So, k <= min(c, m).
        // Also, the total number of students available limits the teams: k <= (c + m + x) / 3.
        // Therefore, the maximum number of teams is min(c, m, (c + m + x) / 3).

        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

