    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number used to generate differences up to k

    // Generate the first k+1 elements to produce k distinct differences
    // The differences will be k, k-1, ..., 1
    // Example: k=2, right=3. Sequence: 1, 3, 2. Differences: |1-3|=2, |3-2|=1.
    // Example: k=3, right=4. Sequence: 1, 4, 2, 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, print from left (increasing)
            std::cout << left++;
        } else { // Odd index, print from right (decreasing)
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k+1) elements, just print them in increasing order.
    // This will produce a difference of 1 for each subsequent pair,
    // which is already one of the k distinct differences generated.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

