int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    double h;
    std::cin >> n >> h;

    // The area of the full carrot is A_total = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // We want to divide it into n pieces of equal area.
    // So, each piece has area A_piece = A_total / n = (h/2) / n = h / (2n).

    // Consider a smaller triangle formed by a cut at distance x from the apex.
    // This smaller triangle is similar to the original carrot.
    // If its height is x, its base will be x/h (by similarity: base/height = 1/h).
    // The area of this smaller triangle is A_x = (1/2) * (x/h) * x = x^2 / (2h).

    // We need to find x_i such that the area of the triangle up to x_i is i * A_piece.
    // A_{x_i} = i * A_piece
    // x_i^2 / (2h) = i * (h / (2n))
    // x_i^2 = i * (h^2 / n)
    // x_i = sqrt(i * h^2 / n)
    // x_i = h * sqrt(i / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

