int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
            }
        } else { // c == ')'
            if (close_needed > 0 && open_needed < k / 2) { // Ensure we have an unmatched '(' to close
                result += ')';
                close_needed--;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long limit = n / m;

        if (limit == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // The last digits of k*m are (k * (m % 10)) % 10.
        // This sequence is periodic with a period of 10.
        // We can precompute the sum of last digits for one full cycle (k=1 to k=10).

        long long sum_of_first_ten_last_digits = 0;
        for (int k = 1; k <= 10; ++k) {
            sum_of_first_ten_last_digits += (static_cast<long long>(k) * (m % 10)) % 10;
        }

        // Calculate how many full cycles of 10 numbers are there up to 'limit'.
        long long num_full_cycles = limit / 10;

        // The sum from full cycles.
        long long total_sum = num_full_cycles * sum_of_first_ten_last_digits;

        // Calculate the sum for the remaining numbers (less than 10).
        long long remaining_numbers = limit % 10;
        for (long long k = 1; k <= remaining_numbers; ++k) {
            total_sum += (k * (m % 10)) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    result.reserve(n);

    // For m=1, the subsegment is just [1]. This is always possible.
    // The initial range for m=1 is [pos[1], pos[1]].
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, we already know it's beautiful.
        // For m > 1, we extend the current range to include 'm'.
        // The current range [current_min_idx, current_max_idx] already covers 1, ..., m-1.
        // To cover 1, ..., m, we need to include 'm' in this range.
        // The position of 'm' is pos[m].
        // We update current_min_idx and current_max_idx to encompass pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, 2, ..., m.
        // This means its length must be exactly 'm'.
        // The length of the subsegment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

