    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // d >= 4, so d^2 - 4d >= 0
            // a^2 - d*a + d = 0
            // a = (d +/- sqrt(d^2 - 4d)) / 2
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a and b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(d^2 - 4d) is clearly positive, so a1 is positive.
            // For b1, we need d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative, we can square them:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // Since d is given as non-negative, and we are in the d >= 4 case,
            // both a1 and b1 will be non-negative.

            // The problem statement implies that a and b can be printed in any order.
            // Let's print the larger one first for consistency with example.
            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Step 1: Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Step 2: Ensure elements to the left of the median are <= s
    // These are elements a[0]...a[median_idx-1]
    // If a[i] > s, we must decrease it to s. Cost is a[i] - s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Step 3: Ensure elements to the right of the median are >= s
    // These are elements a[median_idx+1]...a[n-1]
    // If a[i] < s, we must increase it to s. Cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

