void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-increasing.
    // This is the potential "right part" of the good array.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // If p is 0, the entire array is non-increasing, which is a good array.
    // The prefix to remove is 0.
    if (p == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Now, p is the first index where a[p-1] < a[p].
    // We need to find the rightmost index `q` such that a[q...p-1] is non-decreasing.
    // This is the potential "left part" of the good array.
    // The elements a[q...p-1] must be strictly increasing to form the "peak" part.
    // However, the problem statement implies that the "left part" can be non-decreasing.
    // Let's re-evaluate the structure of a good array.
    // A good array `b` can be split into `b_L` and `b_R` such that `b_L` is non-decreasing
    // and `b_R` is non-increasing.
    // The elements of `c` are picked from `b_L` and `b_R`.
    // The elements picked from `b_L` are `b_1, ..., b_k` in order.
    // The elements picked from `b_R` are `b_m, b_{m-1}, ..., b_{k+1}` in order.
    // The final `c` is `[b_1, ..., b_k, b_m, b_{m-1}, ..., b_{k+1}]` sorted.
    // This means the original array `b` must be of the form:
    // `[x_1, x_2, ..., x_k, y_j, y_{j-1}, ..., y_1]`
    // where `x_1 <= x_2 <= ... <= x_k` and `y_1 <= y_2 <= ... <= y_j`.
    // The combined sequence `[x_1, ..., x_k, y_1, ..., y_j]` must be non-decreasing.
    // This implies `x_k <= y_1`.
    // So, the array `b` must be `[x_1, ..., x_k, y_j, ..., y_1]` where `x_1 <= ... <= x_k <= y_1 <= ... <= y_j`.
    // This is equivalent to saying `b` is non-decreasing up to some point, and then non-increasing.
    // Example: [1, 2, 3, 4, 4, 2, 1]
    // `p` points to the start of the non-increasing suffix.
    // For [1, 2, 3, 4, 4, 2, 1], `p` would be index 4 (value 4).
    // `a[4]=4, a[5]=2, a[6]=1`. This is non-increasing.
    // `a[3]=4, a[4]=4`. This is non-increasing.
    // `a[2]=3, a[3]=4`. This is increasing. So `p` is index 3 (value 4).
    // The suffix `a[3...6]` is `[4, 4, 2, 1]`. This is non-increasing.
    // The prefix `a[0...2]` is `[1, 2, 3]`. This is non-decreasing.
    // So the array `[1, 2, 3, 4, 4, 2, 1]` is good.
    // The structure is `[non-decreasing part] [non-increasing part]`.
    // The "peak" is where the non-decreasing part ends and the non-increasing part begins.
    // The elements `a[0...k]` are non-decreasing, and `a[k...n-1]` are non-increasing.
    // This means `a_0 <= a_1 <= ... <= a_k >= a_{k+1} >= ... >= a_{n-1}`.
    // This is a "bitonic" array, but with non-strict inequalities.

    // Let's re-evaluate the problem's example: b = [1, 2, 3, 4, 4, 2, 1]
    // c = [1, 1, 2, 2, 3, 4, 4]
    // This is formed by taking:
    // b_1=1, b_7=1, b_6=2, b_2=2, b_3=3, b_5=4, b_4=4
    // Original indices: 1, 7, 6, 2, 3, 5, 4
    // This means the elements are picked from the ends.
    // The elements that form `c` are `b_1, ..., b_m`.
    // The crucial observation is that the elements picked from the left form a prefix of `b`,
    // and elements picked from the right form a suffix of `b`.
    // Let `L` be the set of indices of elements picked from the left, and `R` from the right.
    // `L = {1, 2, ..., k}` and `R = {m, m-1, ..., k+1}` for some `k`.
    // The elements `b_1, ..., b_k` are picked in increasing order of index.
    // The elements `b_m, ..., b_{k+1}` are picked in decreasing order of index.
    // The final `c` is a merge of these two sequences, such that `c` is non-decreasing.
    // This means `b_1 <= b_2 <= ... <= b_k` AND `b_m <= b_{m-1} <= ... <= b_{k+1}`.
    // And also, `b_k` must be less than or equal to `b_{k+1}` (if `k+1 <= m`).
    // So, the array `b` must be of the form:
    // `[x_1, x_2, ..., x_k, y_j, y_{j-1}, ..., y_1]`
    // where `x_1 <= x_2 <= ... <= x_k` (left part)
    // and `y_1 <= y_2 <= ... <= y_j` (right part, but reversed in `b`)
    // and `x_k <= y_1` (the "peak" condition).
    // This means the array `b` must look like:
    // `[non-decreasing sequence] [non-increasing sequence]`
    // Example: `[1, 2, 3, 4, 4, 2, 1]`
    // `[1, 2, 3, 4]` is non-decreasing.
    // `[4, 2, 1]` is non-increasing.
    // The peak is `4`.
    // So, we need to find the longest suffix `a[k...n-1]` that has this "mountain" shape.
    // `a[k] <= a[k+1] <= ... <= a[peak_idx] >= a[peak_idx+1] >= ... >= a[n-1]`

    // Let's find the rightmost index `p` such that `a[p...n-1]` is non-increasing.
    // This `p` is the start of the non-increasing part.
    // Example: `[4, 3, 3, 8, 4, 5, 2]`
    // `n-1 = 6`. `a[6]=2`.
    // `p=6`. `a[5]=5 >= a[6]=2`. `p=5`.
    // `a[4]=4 <= a[5]=5`. Stop. `p=5`.
    // So `a[5...6]` is `[5, 2]`, which is non-increasing.
    // The `p` we found is the start of the non-increasing suffix.
    // `p` is the index of the first element of the non-increasing suffix.
    // `a[p-1]` is the element *before* this suffix.
    // If `p=0`, the whole array is non-increasing.
    // If `p > 0`, then `a[p-1] < a[p]`.

    // The current `p` is the start of the non-increasing suffix.
    // We need to find the start of the non-decreasing prefix that precedes it.
    // Let `q` be the index such that `a[q...p-1]` is non-decreasing.
    // We want to find the smallest `q` such that `a[q...n-1]` is good.
    // This means `a[q...p-1]` must be non-decreasing.
    // So we iterate `q` from `p-1` downwards.
    // `q` starts at `p-1`.
    // While `q > 0` and `a[q-1] <= a[q]`, decrement `q`.
    // The final `q` will be the start of the non-decreasing prefix.
    // The length of the prefix to remove is `q`.

    // Example: `a = [4, 3, 3, 8, 4, 5, 2]`
    // `n=7`.
    // Find `p`:
    // `p=6`. `a[5]=5 >= a[6]=2`. `p=5`.
    // `a[4]=4 <= a[5]=5`. Stop. `p=5`.
    // So `a[5...6]` is `[5, 2]`. This is the non-increasing suffix.
    // Now find `q` for `a[...p-1]`. `p-1 = 4`.
    // `q=4`. `a[3]=8 <= a[4]=4` is false. `a[3]=8 > a[4]=4`.
    // So `q` remains `4`.
    // The good suffix is `a[4...6] = [4, 5, 2]`.
    // The prefix to remove is `a[0...3]`, which has length `4`.
    // This matches the example output.

    // Example: `a = [1, 2, 3, 4]`
    // `n=4`.
    // Find `p`:
    // `p=3`. `a[2]=3 <= a[3]=4`. Stop. `p=3`.
    // So `a[3...3]` is `[4]`. This is the non-increasing suffix.
    // Now find `q` for `a[...p-1]`. `p-1 = 2`.
    // `q=2`. `a[1]=2 <= a[2]=3`. `q=1`.
    // `a[0]=1 <= a[1]=2`. `q=0`.
    // `q=0`. Stop.
    // The good suffix is `a[0...3] = [1, 2, 3, 4]`.
    // The prefix to remove is `a[0...-1]`, which has length `0`.
    // This matches the example output.

    // Example: `a = [1, 3, 1, 4, 5, 3, 2]`
    // `n=7`.
    // Find `p`:
    // `p=6`. `a[5]=3 >= a[6]=2`. `p=5`.
    // `a[4]=5 >= a[5]=3`. `p=4`.
    // `a[3]=4 <= a[4]=5`. Stop. `p=4`.
    // So `a[4...6]` is `[5, 3, 2]`. This is the non-increasing suffix.
    // Now find `q` for `a[...p-1]`. `p-1 = 3`.
    // `q=3`. `a[2]=1 <= a[3]=4`. `q=2`.
    // `a[1]=3 >= a[2]=1`. Stop. `q=2`.
    // The good suffix is `a[2...6] = [1, 4, 5, 3, 2]`.
    // The prefix to remove is `a[0...1]`, which has length `2`.
    // This matches the example output.

    // The logic seems correct.
    // `p` is the first index of the non-increasing suffix.
    // `q` is the first index of the non-decreasing prefix that precedes `p`.
    // The resulting good array is `a[q...n-1]`.
    // The length of the prefix to remove is `q`.

    // Step 1: Find the rightmost `p` such that `a[p...n-1]` is non-increasing.
    // `p` will be the index of the "peak" or the start of the non-increasing part.
    // If the array is `[1, 2, 3, 4]`, `p` will be `3`. `a[3]=4`. `a[2]=3 <= a[3]=4`.
    // If the array is `[4, 3, 2, 1]`, `p` will be `0`. `a[0]=4`.
    // Start `p` at `n-1`.
    // While `p > 0` and `a[p-1] >= a[p]`, decrement `p`.
    // After this loop, `p` is the smallest index such that `a[p...n-1]` is non-increasing.
    // If `p=0`, the entire array is non-increasing.

    int current_p = n - 1;
    while (current_p > 0 && a[current_p - 1] >= a[current_p]) {
        current_p--;
    }
    // Now `current_p` is the start of the non-increasing suffix.
    // If `current_p` is 0, the whole array is non-increasing, which is good.
    // The answer is 0.

    // Step 2: Find the rightmost `q` such that `a[q...current_p-1]` is non-decreasing.
    // This `q` will be the start of the non-decreasing prefix.
    // Start `q` at `current_p`.
    // While `q > 0` and `a[q-1] <= a[q]`, decrement `q`.
    // After this loop, `q` is the smallest index such that `a[q...current_p-1]` is non-decreasing.
    // The final answer is `q`.

    int current_q = current_p;
    while (current_q > 0 && a[current_q - 1] <= a[current_q]) {
        current_q--;
    }

    std::cout << current_q << std::endl;
}

