    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops: minimum value a[i] can be reduced to while maintaining a[0] < a[1] < ... < a[i]
    // Specifically, a[i] must be at least i.
    // So, a[i] must be >= i.
    // If a[i] < i, it's impossible to make a[i] >= i.
    // We can achieve a[i] = i if a[i] >= i.
    std::vector<long long> prefix_min_val(n);
    prefix_min_val[0] = 0; // a[0] must be >= 0
    for (int i = 1; i < n; ++i) {
        prefix_min_val[i] = i; // a[i] must be >= i
    }

    // Check if it's possible to satisfy the increasing part up to index i
    // by reducing a[j] to at least prefix_min_val[j]
    // If a[j] < prefix_min_val[j] for any j, then it's impossible to make a[0] < ... < a[j].
    // We can use a boolean array or just check on the fly.
    // Let's use a boolean array `can_reach_prefix[i]` indicating if `a[0] < ... < a[i]` can be formed.
    std::vector<bool> can_reach_prefix(n);
    can_reach_prefix[0] = (a[0] >= prefix_min_val[0]);
    for (int i = 1; i < n; ++i) {
        can_reach_prefix[i] = can_reach_prefix[i-1] && (a[i] >= prefix_min_val[i]);
    }

    // Calculate suffix_min_ops: minimum value a[i] can be reduced to while maintaining a[i] > a[i+1] > ... > a[n-1]
    // Specifically, a[i] must be at least (n-1-i).
    // So, a[i] must be >= (n-1-i).
    // If a[i] < (n-1-i), it's impossible to make a[i] >= (n-1-i).
    // We can achieve a[i] = (n-1-i) if a[i] >= (n-1-i).
    std::vector<long long> suffix_min_val(n);
    suffix_min_val[n-1] = 0; // a[n-1] must be >= 0
    for (int i = n - 2; i >= 0; --i) {
        suffix_min_val[i] = (n - 1 - i); // a[i] must be >= (n-1-i)
    }

    // Check if it's possible to satisfy the decreasing part from index i
    // by reducing a[j] to at least suffix_min_val[j]
    std::vector<bool> can_reach_suffix(n);
    can_reach_suffix[n-1] = (a[n-1] >= suffix_min_val[n-1]);
    for (int i = n - 2; i >= 0; --i) {
        can_reach_suffix[i] = can_reach_suffix[i+1] && (a[i] >= suffix_min_val[i]);
    }

    // A sharpened array exists if there is a peak k (0-indexed) such that:
    // 1. a[0] < ... < a[k] can be formed (can_reach_prefix[k] is true)
    // 2. a[k] > ... > a[n-1] can be formed (can_reach_suffix[k] is true)
    // 3. The value of a[k] can be made large enough to satisfy both conditions.
    //    Specifically, a[k] must be at least k (for the prefix) AND at least (n-1-k) (for the suffix).
    //    So, a[k] must be at least max(k, n-1-k).
    //    Since we can decrease a[k], if a[k] (original) is >= max(k, n-1-k), then it's possible.
    //    The conditions `can_reach_prefix[k]` and `can_reach_suffix[k]` already check this.
    //    `can_reach_prefix[k]` checks `a[k] >= k`.
    //    `can_reach_suffix[k]` checks `a[k] >= (n-1-k)`.
    //    So, if both are true, then `a[k]` is large enough.

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (can_reach_prefix[k] && can_reach_suffix[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

