// Function to check if a state (A, B, C, D) can reach a final state
// where the last toy is in a specific target box.
// This is a recursive function with memoization, but given the constraints
// and the nature of the problem (only parity of B and C matters for sign,
// and total count for magnitude), a simpler approach is possible.
// The problem asks for *any* sequence of operations.

// Let's analyze the properties of the final product:
// 1. Sign:
//    The sign of the final product depends on the number of negative initial toys.
//    Let N_neg = A + B.
//    If N_neg is even, the final product is positive.
//    If N_neg is odd, the final product is negative.
//    This is true regardless of the order of multiplication.
//
// 2. Magnitude relative to 1:
//    Let N_lt1 = B + C (number of toys with magnitude < 1).
//    Let N_ge1 = A + D (number of toys with magnitude >= 1).
//    Total toys = A + B + C + D.
//    Each multiplication reduces the total number of toys by 1.
//    We perform (Total toys - 1) multiplications.
//
//    Consider the effect of multiplications on magnitude:
//    - |x| < 1 * |y| < 1 => |xy| < 1
//    - |x| >= 1 * |y| >= 1 => |xy| >= 1
//    - |x| < 1 * |y| >= 1 => |xy| can be < 1, = 1, or > 1. This is the tricky part.
//
//    The key insight for magnitude is that if there is at least one toy with |x| < 1 (B+C > 0)
//    AND at least one toy with |x| >= 1 (A+D > 0), then it's possible to make the final product
//    have magnitude < 1, = 1, or > 1.
//    This is because we can always pick a very small number (e.g., 0.001) and a very large number (e.g., 1000)
//    and multiply them to get 1. Or 0.001 * 100 to get 0.1. Or 0.001 * 1000000 to get 1000.
//    The problem states "real number" and "randomly", implying we can choose specific values.
//    So, if we have at least one toy from B or C, and at least one toy from A or D,
//    we can achieve any magnitude outcome (relative to 1).
//
//    If all toys have |x| < 1 (A=0, D=0, B+C > 0):
//      The final product will always have magnitude < 1.
//    If all toys have |x| >= 1 (B=0, C=0, A+D > 0):
//      The final product will always have magnitude >= 1.
//    If there's only one toy initially (A+B+C+D = 1):
//      The final product is that toy itself.

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    std::vector<std::string> result(4); // For Box 1, Box 2, Box 3, Box 4

    long long total_toys = A + B + C + D;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1) std::cout << "Ya Tidak Tidak Tidak\n";
        else if (B == 1) std::cout << "Tidak Ya Tidak Tidak\n";
        else if (C == 1) std::cout << "Tidak Tidak Ya Tidak\n";
        else if (D == 1) std::cout << "Tidak Tidak Tidak Ya\n";
        return;
    }

    // Determine possible signs for the final product
    bool can_be_negative;
    bool can_be_positive;

    long long initial_neg_count = A + B;

    // If there are no negative numbers, the product must be positive.
    if (initial_neg_count == 0) {
        can_be_negative = false;
        can_be_positive = true;
    }
    // If there are negative numbers, we can potentially control the final sign.
    // The final sign is determined by the parity of the number of negative factors.
    // If we have at least two negative numbers, we can multiply them to get a positive.
    // If we have at least one negative number and at least one positive number, we can get a negative.
    //
    // The problem is about *any* sequence.
    // If initial_neg_count is even, the final product is positive.
    // If initial_neg_count is odd, the final product is negative.
    // This is fixed.
    can_be_negative = (initial_neg_count % 2 != 0);
    can_be_positive = (initial_neg_count % 2 == 0);

    // However, there's a special case: if we have only one negative number (A+B=1)
    // and all other numbers are positive, then the final product will be negative.
    // If we have only one positive number (C+D=1) and all other numbers are negative,
    // then the final product will be negative if A+B is odd, positive if A+B is even.
    //
    // The crucial part is that we can choose the order of operations.
    // If we have at least one negative number (A+B > 0) AND at least one positive number (C+D > 0),
    // we can make the final product negative or positive.
    // Example: N1, N2, P1.
    // (N1 * N2) * P1 = P * P1 = P (positive)
    // (N1 * P1) * N2 = N * N2 = P (positive)
    //
    // Example: N1, P1, P2.
    // (N1 * P1) * P2 = N * P2 = N (negative)
    // (P1 * P2) * N1 = P * N1 = N (negative)
    //
    // It seems the parity rule is always true for the final product's sign.
    // The only way to change the sign is if we can introduce a negative number
    // from a positive one, which is not possible by multiplication.
    // So, the sign of the final product is fixed by the parity of A+B.

    // Determine possible magnitudes for the final product
    bool can_be_lt1; // magnitude < 1
    bool can_be_ge1; // magnitude >= 1

    long long num_lt1 = B + C; // Toys with magnitude < 1
    long long num_ge1 = A + D; // Toys with magnitude >= 1

    if (num_lt1 == 0) { // All initial toys have magnitude >= 1
        can_be_lt1 = false;
        can_be_ge1 = true;
    } else if (num_ge1 == 0) { // All initial toys have magnitude < 1
        can_be_lt1 = true;
        can_be_ge1 = false;
    } else { // We have at least one toy with magnitude < 1 AND at least one toy with magnitude >= 1
        // In this scenario, we can achieve either magnitude < 1 or magnitude >= 1.
        // Example: 0.5 and 10.
        // If we have 0.5, 10, 20. We can do (0.5 * 10) = 5 (>=1), then 5 * 20 = 100 (>=1).
        // Or we can do (0.5 * 0.01) = 0.005 (if we had another <1 toy).
        // The problem states we can pick *any* two toys.
        // If we have a toy with value 0.1 and a toy with value 100.
        // We can make 0.1 * 100 = 10 (>=1).
        // We can make 0.1 * 0.001 = 0.0001 (if we had another <1 toy).
        //
        // The key is that we can choose the *values* of the toys.
        // If we have B+C > 0 and A+D > 0, we can pick values such that:
        // - Product is < 1: e.g., pick a very small number from B/C and multiply it with everything else.
        //   Or pick a number from A/D that is just slightly > 1 (e.g., 1.00001) and a number from B/C that is very small (e.g., 0.00001).
        //   Then 1.00001 * 0.00001 = 0.0000100001 (<1).
        // - Product is >= 1: e.g., pick a very large number from A/D and multiply it with everything else.
        //   Or pick a number from A/D that is very large (e.g., 100000) and a number from B/C that is just slightly < 1 (e.g., 0.99999).
        //   Then 100000 * 0.99999 = 99999 (>=1).
        // So, if both types of magnitudes exist, both outcomes are possible.
        can_be_lt1 = true;
        can_be_ge1 = true;
    }

    // Now combine sign and magnitude possibilities
    // Box 1: Negative, magnitude >= 1
    result[0] = (can_be_negative && can_be_ge1) ? "Ya" : "Tidak";
    // Box 2: Negative, magnitude < 1
    result[1] = (can_be_negative && can_be_lt1) ? "Ya" : "Tidak";
    // Box 3: Positive, magnitude < 1
    result[2] = (can_be_positive && can_be_lt1) ? "Ya" : "Tidak";
    // Box 4: Positive, magnitude >= 1
    result[3] = (can_be_positive && can_be_ge1) ? "Ya" : "Tidak";

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        solve();
    }
    return 0;
}

