int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Create pairs (B_i, original_index_i) and sort them by B_i in ascending order
    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_indexed[i] = {b[i], i};
    }
    std::sort(b_indexed.begin(), b_indexed.end());

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // Assign A_i' values.
    // The largest A_i values should be paired with the smallest B_i values.
    // This is because F(N, K) = (N+1)/(K+1).
    // To maximize sum (A_i'+1)/(B_i+1), we want to pair large (A_i'+1) with small (B_i+1).
    // This means large A_i' with small B_i.
    // Since A is sorted ascending, a[m-1] is the largest, a[0] is the smallest.
    // Since b_indexed is sorted by B_i ascending, b_indexed[0].first is the smallest B_i.
    // So, a[m-1] should be paired with b_indexed[0].first.
    // a[m-2] should be paired with b_indexed[1].first, and so on.
    // This means a[m-1-j] should be paired with b_indexed[j].first.
    // The original index for b_indexed[j].first is b_indexed[j].second.
    for (int j = 0; j < m; ++j) {
        a_prime[b_indexed[j].second] = a[m - 1 - j];
    }

    // Output the rearranged array A'
    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

