#include <set>

// Function to check if a prefix of length 'len' is a permutation
bool is_permutation_prefix(int len, int n, const std::vector<int>& a, const std::vector<int>& prefix_max_val, const std::vector<bool>& prefix_distinct) {
    if (len == 0 || len > n) {
        return false;
    }
    return prefix_distinct[len] && prefix_max_val[len] == len;
}

// Function to check if a suffix of length 'len' is a permutation
bool is_permutation_suffix(int len, int n, const std::vector<int>& a, const std::vector<int>& suffix_max_val, const std::vector<bool>& suffix_distinct) {
    if (len == 0 || len > n) {
        return false;
    }
    return suffix_distinct[n - len] && suffix_max_val[n - len] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix properties
    std::vector<int> prefix_max_val(n + 1, 0);
    std::vector<bool> prefix_distinct(n + 1, true);
    std::vector<bool> seen_prefix(n + 1, false); // Using n+1 for 1-based indexing up to n
    for (int i = 0; i < n; ++i) {
        prefix_max_val[i + 1] = std::max(prefix_max_val[i], a[i]);
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max value is n-1
            prefix_distinct[i + 1] = false;
        } else {
            seen_prefix[a[i]] = true;
            prefix_distinct[i + 1] = prefix_distinct[i];
        }
    }

    // Precompute suffix properties
    std::vector<int> suffix_max_val(n + 1, 0); // suffix_max_val[i] stores max of a[i...n-1]
    std::vector<bool> suffix_distinct(n + 1, true); // suffix_distinct[i] stores distinctness of a[i...n-1]
    std::vector<bool> seen_suffix(n + 1, false);
    for (int i = n - 1; i >= 0; --i) {
        suffix_max_val[i] = std::max(suffix_max_val[i + 1], a[i]);
        if (a[i] > n || seen_suffix[a[i]]) {
            suffix_distinct[i] = false;
        } else {
            seen_suffix[a[i]] = true;
            suffix_distinct[i] = suffix_distinct[i + 1];
        }
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_permutation_prefix(l1, n, a, prefix_max_val, prefix_distinct) &&
            is_permutation_suffix(l2, n, a, suffix_max_val, suffix_distinct)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

