void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, ... such that (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor(b_i))
    // Let S = current_sum, X = current_xor_sum
    // We want S' = 2 * X'
    // S' = S + b1 + b2 + ...
    // X' = X ^ b1 ^ b2 ^ ...

    // Strategy: Append at most 3 elements.
    // A simple strategy that always works is to append two elements.
    // Let's try to append two elements, b1 and b2.
    // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2)

    // Consider b1 = X.
    // Then X ^ b1 = X ^ X = 0.
    // The equation becomes S + X + b2 = 2 * (0 ^ b2) = 2 * b2.
    // S + X = 2 * b2 - b2
    // S + X = b2.
    // So, if we append b1 = X and b2 = S + X, the condition becomes:
    // Sum: S + X + (S + X) = 2S + 2X
    // XOR: X ^ X ^ (S + X) = 0 ^ (S + X) = S + X
    // Check condition: 2S + 2X = 2 * (S + X). This is true.

    // The elements to append are X and S + X.
    // Both X and S + X are non-negative.
    // X is the XOR sum of initial elements, so it's non-negative.
    // S is the sum of initial elements, so it's non-negative.
    // Thus S + X is non-negative.

    // Output 2 elements:
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

