// Function to convert a number to its parity pattern string
// For example, 241 -> "001" (2 is even, 4 is even, 1 is odd)
// Since numbers can be up to 10^18, they can have at most 18 digits.
// We'll always generate a pattern of length 18, padding with '0's (even) from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's (even) from the left to a fixed length (e.g., 18)
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left.
    // Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we can normalize both numbers and patterns to a fixed length.
    // Max digits for 10^18 is 18.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get correct order (most significant digit first)
    return pattern;
}

// Function to normalize a query pattern string
// Pad with '0's from the left to a fixed length (18)
std::string normalize_query_pattern(const std::string& s) {
    std::string normalized_s = s;
    while (normalized_s.length() < 18) {
        normalized_s = '0' + normalized_s;
    }
    return normalized_s;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string.
    // The key will be the 18-character parity pattern string.
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            std::string normalized_s = normalize_query_pattern(s);
            std::cout << counts[normalized_s] << "\n";
        }
    }

    return 0;
}

