    int n = s.length();

    // prefix_counts[0][i] stores count of 'x' in s[0...i-1]
    // prefix_counts[1][i] stores count of 'y' in s[0...i-1]
    // prefix_counts[2][i] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[0][i + 1] = prefix_counts[0][i];
        prefix_counts[1][i + 1] = prefix_counts[1][i];
        prefix_counts[2][i + 1] = prefix_counts[2][i];

        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Adjust to 0-based indexing for prefix sums
        // Substring is s[l-1 ... r-1]
        // Count of 'x' in s[l-1 ... r-1] is prefix_counts[0][r] - prefix_counts[0][l-1]
        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

