int main() {
    // Optimize C++ standard streams for faster input/output.
    // This is a common practice in competitive programming.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Declare a 2D vector to store the matrix b.
    // Using long long for matrix elements to be safe, though int is sufficient
    // given the problem constraints (0 <= b_ij <= 10^9).
    std::vector<std::vector<int>> b(n, std::vector<int>(n));

    // Read the matrix b from standard input.
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> b[i][j];
        }
    }

    // Declare a vector to store the restored sequence a.
    // The problem guarantees 0 <= a_i <= 10^9, so int is appropriate.
    std::vector<int> a(n);

    // Iterate through each element a_i that needs to be restored.
    for (int i = 0; i < n; ++i) {
        // Initialize a_i to 0.
        // The bitwise OR operation will set bits in a_i.
        // Since a_i is guaranteed to be non-negative, 0 is a safe starting point.
        a[i] = 0;

        // Iterate through all other elements b_ij in the i-th row (where j != i).
        for (int j = 0; j < n; ++j) {
            if (i == j) {
                // Skip the diagonal elements as they are -1 and not part of the AND operation.
                continue;
            }
            // The key insight: a_i must have all bits set that are set in any b_ij (for j != i).
            // This is because b_ij = a_i & a_j. If a bit is set in b_ij, it must be set in a_i.
            // Therefore, a_i is the bitwise OR of all b_ij for j != i.
            a[i] |= b[i][j];
        }
    }

    // Print the restored sequence a.
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

