// Function to find prime factors of a number
// Returns a vector of unique prime factors
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, then p itself is not a valid x.
        // We need to find the largest divisor of p that is not divisible by q.
        // This means we must remove some prime factors from p such that
        // the resulting number is no longer divisible by q.

        // Find prime factors of q.
        // We only care about the prime factors that q introduces to p.
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 0;

        // For each prime factor f of q, we try to divide p by f until
        // p is no longer divisible by q, or until p is no longer divisible by f.
        // The goal is to find the largest such resulting number.
        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q.
            // This means we remove all factors of f from current_p that contribute
            // to its divisibility by q.
            while (current_p % f == 0 && (current_p / f) % q == 0) {
                current_p /= f;
            }
            // After the loop, current_p is either not divisible by q,
            // or current_p is not divisible by f anymore.
            // If current_p is still divisible by q, it means we removed all factors of f
            // but it's still divisible by q due to other prime factors of q.
            // In this case, current_p is not a candidate for max_x.
            // However, the problem statement guarantees that an x always exists.
            // The logic here is to find the largest divisor of p that is NOT divisible by q.
            // If current_p is not divisible by q, it's a candidate.
            // If current_p is divisible by q, it means we removed all factors of f,
            // but it's still divisible by q. This implies that current_p is not the answer.
            // The condition (current_p / f) % q == 0 ensures that we stop dividing by f
            // as soon as current_p / f is no longer divisible by q.
            // So, current_p itself will be the largest divisor of p that is not divisible by q
            // by removing factors of f.

            // The correct logic is:
            // We want to find the largest x such that p % x == 0 and x % q != 0.
            // If p % q == 0, we must reduce p.
            // Consider a prime factor `f` of `q`.
            // We can try to remove all occurrences of `f` from `p` until `p` is no longer divisible by `q`.
            // Let `temp_p = p`.
            // While `temp_p` is divisible by `f` AND `temp_p` is divisible by `q`:
            //   `temp_p /= f`.
            // After this loop, `temp_p` is a divisor of `p`.
            // If `temp_p` is not divisible by `q`, then `temp_p` is a candidate for `max_x`.
            // We do this for all prime factors of `q` and take the maximum.

            long long temp_p = p;
            while (temp_p % f == 0) {
                if ((temp_p / f) % q != 0) { // If dividing by f makes it not divisible by q
                    max_x = std::max(max_x, temp_p / f);
                    break; // Found the largest such divisor by removing factors of f
                }
                temp_p /= f;
            }
            // If after the loop, temp_p is not divisible by q, it means we removed all factors of f
            // and it became not divisible by q. This temp_p is a candidate.
            // The above logic `if ((temp_p / f) % q != 0)` already handles this by taking `temp_p / f`.
            // If `temp_p` itself is not divisible by `q` (after all divisions by `f`),
            // it means `p` was reduced by all factors of `f` and became `temp_p`.
            // This `temp_p` is a candidate.
            // Example: p=12, q=6. f=2.
            // temp_p=12. (12/2)%6 == 0.
            // temp_p=6. (6/2)%6 != 0. max_x = max(0, 6/2=3).
            // Example: p=12, q=6. f=3.
            // temp_p=12. (12/3)%6 != 0. max_x = max(3, 12/3=4).
            // Final max_x = 4. This is correct.
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

