int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;

        // Initialize the bounding box for reachable points
        // min_x_target: smallest possible X coordinate for the target
        // max_x_target: largest possible X coordinate for the target
        // min_y_target: smallest possible Y coordinate for the target
        // max_y_target: largest possible Y coordinate for the target
        // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
        // So, we can initialize with these bounds.
        int min_x_target = -100000;
        int max_x_target = 100000;
        int min_y_target = -100000;
        int max_y_target = 100000;

        for (int i = 0; i < n; ++i) {
            int x, y, f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x-1)
            // f2: can move up (y+1)
            // f3: can move right (x+1)
            // f4: can move down (y-1)

            // If robot cannot move left (f1=0), it means it can only reach points
            // with X >= its current x-coordinate.
            // So, the target X must be >= x.
            if (f1 == 0) {
                min_x_target = std::max(min_x_target, x);
            }

            // If robot cannot move up (f2=0), it means it can only reach points
            // with Y <= its current y-coordinate.
            // So, the target Y must be <= y.
            if (f2 == 0) {
                max_y_target = std::min(max_y_target, y);
            }

            // If robot cannot move right (f3=0), it means it can only reach points
            // with X <= its current x-coordinate.
            // So, the target X must be <= x.
            if (f3 == 0) {
                max_x_target = std::min(max_x_target, x);
            }

            // If robot cannot move down (f4=0), it means it can only reach points
            // with Y >= its current y-coordinate.
            // So, the target Y must be >= y.
            if (f4 == 0) {
                min_y_target = std::max(min_y_target, y);
            }
        }

        // Check if there is any valid intersection for the target coordinates
        if (min_x_target <= max_x_target && min_y_target <= max_y_target) {
            // If an intersection exists, any point within [min_x_target, max_x_target]
            // and [min_y_target, max_y_target] is a valid target.
            // We can pick the smallest valid coordinates, e.g., (min_x_target, min_y_target).
            std::cout << 1 << " " << min_x_target << " " << min_y_target << "\n";
        } else {
            // No common reachable point exists
            std::cout << 0 << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot = 0; pivot <= 9; ++pivot) {
        std::string current_coloring(n, ' ');
        char last1 = '0'; // Last digit colored 1
        char first2 = '9' + 1; // First digit colored 2 (conceptually larger than any digit)
        bool possible_for_pivot = true;

        // First pass: assign digits < pivot to color 1, digits > pivot to color 2
        // Digits == pivot are temporarily unassigned (' ')
        for (int i = 0; i < n; ++i) {
            if (s[i] < (pivot + '0')) {
                current_coloring[i] = '1';
            } else if (s[i] > (pivot + '0')) {
                current_coloring[i] = '2';
            } else {
                current_coloring[i] = ' '; // Mark as unassigned for now
            }
        }

        // Second pass: assign digits == pivot.
        // Those appearing before the first '2' (if any) can be '1'.
        // Those appearing after the last '1' (if any) can be '2'.
        // This is equivalent to finding the "split point" for digits equal to pivot.
        // We want to find the largest index `k` such that `s[k] == pivot` and `s[k]` is colored '1'.
        // All `s[i] == pivot` for `i < k` are also '1'.
        // All `s[i] == pivot` for `i > k` are '2'.
        // If no `s[i] == pivot` is colored '1', then all `s[i] == pivot` are '2'.
        // If no `s[i] == pivot` is colored '2', then all `s[i] == pivot` are '1'.

        // Strategy: Try to color as many 'pivot' digits as '1' as possible,
        // while maintaining non-decreasing order for color 1.
        // Then color the rest of 'pivot' digits as '2', maintaining non-decreasing order for color 2.

        // Find the first digit that must be '2' (i.e., s[i] > pivot)
        int first_must_be_2_idx = n;
        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '2') {
                first_must_be_2_idx = i;
                break;
            }
        }

        // Assign 'pivot' digits:
        // If s[i] == pivot and i < first_must_be_2_idx, assign '1'.
        // If s[i] == pivot and i >= first_must_be_2_idx, assign '2'.
        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == ' ') { // This means s[i] == pivot
                if (i < first_must_be_2_idx) {
                    current_coloring[i] = '1';
                } else {
                    current_coloring[i] = '2';
                }
            }
        }

        // Now verify the coloring
        std::string s1_str = "";
        std::string s2_str = "";

        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '1') {
                s1_str += s[i];
            } else {
                s2_str += s[i];
            }
        }

        // Check if s1_str is non-decreasing
        for (size_t i = 0; i + 1 < s1_str.length(); ++i) {
            if (s1_str[i] > s1_str[i+1]) {
                possible_for_pivot = false;
                break;
            }
        }
        if (!possible_for_pivot) continue;

        // Check if s2_str is non-decreasing
        for (size_t i = 0; i + 1 < s2_str.length(); ++i) {
            if (s2_str[i] > s2_str[i+1]) {
                possible_for_pivot = false;
                break;
            }
        }
        if (!possible_for_pivot) continue;

        // Check if last of s1_str <= first of s2_str
        if (!s1_str.empty() && !s2_str.empty()) {
            if (s1_str.back() > s2_str.front()) {
                possible_for_pivot = false;
            }
        }

        if (possible_for_pivot) {
            result = current_coloring;
            found_solution = true;
            break; 
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

