    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: sum_r = (b-1) * b / 2
    // If b=1, then b-1=0, sum_r = 0.
    // This is correct as there are no r such that 1 <= r < 1.
    long long sum_r_term = (b - 1);
    long long sum_r_val = (sum_r_term % MOD * (b % MOD)) % MOD;

    // We need to divide by 2. Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004.
    long long inv2 = 500000004; // (MOD + 1) / 2
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Sum of (k*b + 1) for k from 1 to a:
    // sum_k = sum_{k=1}^{a} (k*b + 1)
    // sum_k = b * sum_{k=1}^{a} k + sum_{k=1}^{a} 1
    // sum_k = b * (a * (a+1) / 2) + a

    long long sum_k_term_1 = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_term_1 = (sum_k_term_1 * inv2) % MOD; // (a * (a+1) / 2)

    long long sum_k_val = (b % MOD * sum_k_term_1) % MOD; // b * (a * (a+1) / 2)
    sum_k_val = (sum_k_val + (a % MOD)) % MOD; // + a

    // Total sum = (sum_r) * (sum_k)
    long long total_sum = (sum_r_val * sum_k_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

