    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char first_char_t = s[k_actual];

        // Find all possible k' values that could produce this first_char_t.
        std::vector<int> possible_k_values;
        for (int k_prime = 0; k_prime < L; ++k_prime) {
            if (s[k_prime] == first_char_t) {
                possible_k_values.push_back(k_prime);
            }
        }

        // If there's only one possible k' value, Vasya wins immediately.
        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // Otherwise, Vasya needs to choose an optimal second position j.
        // Iterate through all possible second positions j (from 1 to L-1).
        double max_win_prob_for_k_actual = 0.0;

        for (int j = 1; j < L; ++j) {
            char second_char_t = s[(j + k_actual) % L];
            int count_unique_k_prime = 0;

            // Check how many k' values from possible_k_values match both t[0] and t[j].
            // We need to count how many k_prime satisfy:
            // s[k_prime] == first_char_t (already filtered by possible_k_values)
            // s[(j + k_prime) % L] == second_char_t

            // Also, we need to check if the entire string matches for these k_prime values.
            // If s[k_prime] == s[k_actual] and s[(j+k_prime)%L] == s[(j+k_actual)%L],
            // then we need to compare the full strings.
            // The condition for winning is that only ONE k_prime results in the same (t[0], t[j]) pair AND
            // the full string t generated by k_prime is identical to the full string t generated by k_actual.
            // This means s shifted by k_prime must be identical to s shifted by k_actual.
            // This happens if and only if k_prime == k_actual, or if s is periodic and k_prime is a multiple of the period length away from k_actual.
            // The problem states "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
            // This means if there are multiple k' values such that s[k'] == t[0] AND s[(j+k')%L] == t[j],
            // AND for at least two of these k', the full shifted string s_shifted_by_k' is identical to s_shifted_by_k_actual,
            // then Vasya loses.
            // However, the problem is simpler: Vasya wins if there is EXACTLY ONE k' that satisfies the conditions.
            // The conditions are: s[k'] == t[0] AND s[(j+k')%L] == t[j].
            // We are looking for the number of k' values that satisfy these two character conditions.
            // If this count is 1, Vasya wins. Otherwise, he loses.

            int matching_k_prime_count = 0;
            for (int k_prime : possible_k_values) {
                if (s[(j + k_prime) % L] == second_char_t) {
                    matching_k_prime_count++;
                }
            }

            if (matching_k_prime_count == 1) {
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 1.0);
            } else {
                // If multiple k' values match, Vasya loses for this j.
                // If zero k' values match, Vasya loses for this j.
                // So, max_win_prob_for_k_actual remains 0.0 or is updated by other j.
            }
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we need to know what happens to an input bit 0 and an input bit 1.
    // state_0[bit_pos] = final value of bit_pos if initial bit was 0
    // state_1[bit_pos] = final value of bit_pos if initial bit was 1
    // Initially, if input bit is 0, it remains 0. If input bit is 1, it remains 1.
    std::vector<int> state_0(10); // All zeros
    std::vector<int> state_1(10); // All ones
    std::iota(state_1.begin(), state_1.end(), 0); // Fill with 0, 1, ..., 9 (not actual values, just to indicate initial state)
                                                  // This is a conceptual representation.
                                                  // More accurately: state_0[b] = 0, state_1[b] = 1 for all b.

    // We can represent the current transformation for each bit position.
    // For each bit `b`, we track two values:
    // `val_if_0[b]` = the value of bit `b` if the original input bit `b` was 0.
    // `val_if_1[b]` = the value of bit `b` if the original input bit `b` was 1.
    // Initially:
    // `val_if_0[b]` = 0
    // `val_if_1[b]` = 1
    int current_val_if_0 = 0; // Represents the result if the initial input was 0
    int current_val_if_1 = 1023; // Represents the result if the initial input was 1023 (all bits 1)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_if_0 &= x;
            current_val_if_1 &= x;
        } else if (op_char == '|') {
            current_val_if_0 |= x;
            current_val_if_1 |= x;
        } else if (op_char == '^') {
            current_val_if_0 ^= x;
            current_val_if_1 ^= x;
        }
    }

    // Now, `current_val_if_0` holds the final state for an input of 0.
    // `current_val_if_1` holds the final state for an input of 1023.

    // We need to find three operations (AND, OR, XOR) that achieve this transformation.
    // Let the final operations be `& A`, `| B`, `^ C`.
    // For each bit `b`:
    // Let `x_b` be the original bit.
    // The final bit `res_b` will be `((x_b & A_b) | B_b) ^ C_b`.

    // Let's determine A, B, C bit by bit.
    int final_A = 1023; // Initialize A to all ones (no effect on AND)
    int final_B = 0;    // Initialize B to all zeros (no effect on OR)
    int final_C = 0;    // Initialize C to all zeros (no effect on XOR)

    for (int b = 0; b < 10; ++b) {
        int bit_0_result = (current_val_if_0 >> b) & 1; // What 0 becomes
        int bit_1_result = (current_val_if_1 >> b) & 1; // What 1 becomes

        // We are looking for A_b, B_b, C_b such that:
        // ((0 & A_b) | B_b) ^ C_b = bit_0_result
        // ((1 & A_b) | B_b) ^ C_b = bit_1_result

        // Case 1: A_b = 0
        // (0 | B_b) ^ C_b = bit_0_result  => B_b ^ C_b = bit_0_result
        // (0 | B_b) ^ C_b = bit_1_result  => B_b ^ C_b = bit_1_result
        // This implies bit_0_result must be equal to bit_1_result.
        // If they are equal, we can set A_b = 0.
        // Then B_b ^ C_b = bit_0_result.
        // We can choose B_b = 0, C_b = bit_0_result.
        // Or B_b = 1, C_b = 1 - bit_0_result.
        // Let's try to keep A_b = 1 if possible, as it's more general.

        // Let's analyze the four possible (bit_0_result, bit_1_result) pairs:
        if (bit_0_result == 0 && bit_1_result == 0) {
            // Input 0 -> 0, Input 1 -> 0
            // This means the bit must become 0 regardless of input.
            // This can be achieved by `& 0`.
            final_A &= ~(1 << b); // Set A_b to 0
            // B_b and C_b can remain 0 for this bit.
        } else if (bit_0_result == 0 && bit_1_result == 1) {
            // Input 0 -> 0, Input 1 -> 1
            // This means the bit passes through unchanged.
            // This can be achieved by `& 1`, `| 0`, `^ 0`.
            // A_b remains 1, B_b remains 0, C_b remains 0 for this bit.
        } else if (bit_0_result == 1 && bit_1_result == 0) {
            // Input 0 -> 1, Input 1 -> 0
            // This means the bit is flipped.
            // This can be achieved by `^ 1`.
            final_C |= (1 << b); // Set C_b to 1
            // A_b remains 1, B_b remains 0 for this bit.
        } else if (bit_0_result == 1 && bit_1_result == 1) {
            // Input 0 -> 1, Input 1 -> 1
            // This means the bit must become 1 regardless of input.
            // This can be achieved by `| 1`.
            final_B |= (1 << b); // Set B_b to 1
            // A_b remains 1, C_b remains 0 for this bit.
        }
    }

    // The operations are applied in order: AND, then OR, then XOR.
    // This sequence `& final_A`, `| final_B`, `^ final_C` will produce the correct result.
    // We need to output only the operations that are not identity operations.
    // `& 1023` is identity.
    // `| 0` is identity.
    // `^ 0` is identity.

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) {
        result_ops.push_back({'&', final_A});
    }
    if (final_B != 0) {
        result_ops.push_back({'|', final_B});
    }
    if (final_C != 0) {
        result_ops.push_back({'^', final_C});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial counts for the left half (jars 0 to n-1)
    // and right half (jars n to 2n-1)
    int initial_s_left = 0;
    int initial_b_left = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            initial_s_left++;
        } else {
            initial_b_left++;
        }
    }

    int initial_s_right = 0;
    int initial_b_right = 0;
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            initial_s_right++;
        } else {
            initial_b_right++;
        }
    }

    // Calculate initial total difference
    int initial_diff = (initial_s_left + initial_s_right) - (initial_b_left + initial_b_right);

    // Map to store the minimum number of jars removed from the left (k_L)
    // to achieve a certain difference in (S-B) count for the remaining left jars.
    // Key: (S-B) difference, Value: k_L
    std::map<int, int> left_diff_to_kL;
    left_diff_to_kL[0] = 0; // If 0 jars are removed from left, diff is 0, k_L = 0

    int current_s_left = initial_s_left;
    int current_b_left = initial_b_left;

    // Iterate k_L from 1 to n (removing jars from the left side)
    for (int k_L = 1; k_L <= n; ++k_L) {
        // When removing jar (n - k_L) from the left
        int removed_jar_idx = n - k_L;
        if (a[removed_jar_idx] == 1) {
            current_s_left--;
        } else {
            current_b_left--;
        }
        int diff_after_kL_removed = current_s_left - current_b_left;
        if (left_diff_to_kL.find(diff_after_kL_removed) == left_diff_to_kL.end()) {
            left_diff_to_kL[diff_after_kL_removed] = k_L;
        }
    }

    int min_total_removed = 2 * n; // Initialize with max possible removal

    // Case 1: No jars removed from the right (k_R = 0)
    // We need the remaining left jars to have a difference such that
    // (S_left_rem - B_left_rem) + (S_right_initial - B_right_initial) = 0
    // (S_left_rem - B_left_rem) = -(S_right_initial - B_right_initial)
    int target_diff_for_left_if_kR_is_0 = -(initial_s_right - initial_b_right);
    if (left_diff_to_kL.count(target_diff_for_left_if_kR_is_0)) {
        min_total_removed = std::min(min_total_removed, left_diff_to_kL[target_diff_for_left_if_kR_is_0]);
    }

    // Iterate k_R from 1 to n (removing jars from the right side)
    current_s_right = initial_s_right;
    current_b_right = initial_b_right;

    for (int k_R = 1; k_R <= n; ++k_R) {
        // When removing jar (n + k_R - 1) from the right
        int removed_jar_idx = n + k_R - 1;
        if (a[removed_jar_idx] == 1) {
            current_s_right--;
        } else {
            current_b_right--;
        }

        // The difference for the remaining right jars is (current_s_right - current_b_right)
        // We need (S_left_rem - B_left_rem) + (S_right_rem - B_right_rem) = 0
        // So, (S_left_rem - B_left_rem) = -(current_s_right - current_b_right)
        int target_diff_for_left = -(current_s_right - current_b_right);

        if (left_diff_to_kL.count(target_diff_for_left)) {
            min_total_removed = std::min(min_total_removed, left_diff_to_kL[target_diff_for_left] + k_R);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply median smoothing once
// Returns true if the sequence changed, false otherwise (stable)
bool apply_median_smoothing(const std::vector<int>& a, std::vector<int>& b) {
    int n = a.size();
    if (n == 0) return false;

    b.resize(n);
    bool changed = false;

    b[0] = a[0];
    if (n > 1) {
        b[n - 1] = a[n - 1];
    }

    if (b[0] != a[0]) changed = true; // Should not happen for b[0] = a[0]
    if (n > 1 && b[n - 1] != a[n - 1]) changed = true; // Should not happen for b[n-1] = a[n-1]

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        // Median of three 0s/1s is 1 if sum >= 2, else 0
        b[i] = (sum >= 2) ? 1 : 0;
        if (b[i] != a[i]) {
            changed = true;
        }
    }
    return changed;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> current_seq = a;
    std::vector<int> next_seq(n);
    int steps = 0;

    // Find the first 01 or 10 pattern
    int first_diff = -1;
    for (int i = 0; i < n - 1; ++i) {
        if (current_seq[i] != current_seq[i+1]) {
            first_diff = i;
            break;
        }
    }

    if (first_diff == -1) { // Sequence is already all 0s or all 1s, hence stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Find the last 01 or 10 pattern
    int last_diff = -1;
    for (int i = n - 2; i >= 0; --i) {
        if (current_seq[i] != current_seq[i+1]) {
            last_diff = i;
            break;
        }
    }

    // Calculate max_steps based on the first and last differing pairs
    // The number of steps is determined by the maximum distance from an end to a differing pair.
    // For a 01...10 pattern, the 0 at index `first_diff` and 1 at `first_diff+1`
    // The 1 at index `last_diff` and 0 at `last_diff+1`
    // The "middle" part `first_diff+1` to `last_diff` will eventually become uniform.
    // The number of steps is ceil( (last_diff - first_diff) / 2.0 )
    // This is equivalent to (last_diff - first_diff + 1) / 2 using integer division.
    int max_steps = (last_diff - first_diff + 1) / 2;

    // Apply smoothing max_steps times
    for (int k = 0; k < max_steps; ++k) {
        apply_median_smoothing(current_seq, next_seq);
        current_seq = next_seq;
        steps++;
    }

    std::cout << steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[j] to a very large value (effectively positive infinity)
    // This is because a_0[j] + current_delta[j] <= m_i for all type 2 operations.
    // So a_0[j] <= m_i - current_delta[j]. We want the tightest upper bound.
    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());

    std::vector<long long> current_delta(n, 0);

    // Iterate through operations in reverse to determine initial_a bounds
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's an increase operation, it means d was added to a[l...r].
            // When going backwards, this means we should subtract d from current_delta[l...r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // If it's a max query, it means max(a_j) for j in [l,r] was m_i.
            // This implies that for all j in [l,r], a_0[j] + current_delta[j] <= m_i.
            // So, a_0[j] <= m_i - current_delta[j].
            // We update initial_a[j] with the minimum of its current value and this new upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If any initial_a[j] is still max_long_long, it means it was never constrained by a type 2 operation.
    // We can set it to 0 (or any value within bounds, 0 is simplest and valid).
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] == std::numeric_limits<long long>::max()) {
            initial_a[j] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> a = initial_a;
    current_delta.assign(n, 0); // Reset current_delta for forward pass

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // ops[i].type == 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, initial_a[j] + current_delta[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be 10^9 and y accumulates.
// x is an index, so it fits in int, but intermediate x values can be large.
// However, we only care if x is within [1, n] or outside.
// The values a[x] can be large, so x can jump by large amounts.
// Let's use long long for x as well to be safe, though it's primarily an index.
// The problem statement implies x is an integer variable, not necessarily an index.

// We need to store results to avoid recomputing for states already visited.
// This is a dynamic programming approach or memoization.
// dp[i][0] will store the result for (x=i, parity=0)
// dp[i][1] will store the result for (x=i, parity=1)
// The parity refers to whether the next step is 'add a[x]' or 'subtract a[x]'.
// In our simulation, we always start with 'add a[x]'.
// So, dp[i] will store the result if we start at x=i and the next operation is 'add a[x]'.

// dp_val[x] stores the final y value if starting at x with 'add' operation.
// dp_state[x] stores the state: 0 = unvisited, 1 = visiting (cycle detected), 2 = visited (result in dp_val[x])
std::vector<long long> dp_val;
std::vector<int> dp_state; // 0: unvisited, 1: visiting (in current path), 2: visited (result computed)
std::vector<long long> a_arr; // a_arr[0] is unused, a_arr[1] is variable, a_arr[2...n] are fixed.
int N_global;

long long solve(int current_x) {
    if (current_x <= 0 || current_x > N_global) {
        return 0; // Base case: program terminates, y doesn't increase further.
    }

    if (dp_state[current_x] == 1) {
        return -1; // Cycle detected
    }
    if (dp_state[current_x] == 2) {
        return dp_val[current_x]; // Already computed
    }

    dp_state[current_x] = 1; // Mark as visiting

    long long val_ax = a_arr[current_x];

    // Step 2: x += a[x], y += a[x]
    // New x becomes current_x + val_ax
    // New y becomes val_ax (relative to current y)

    // Step 3: y += a[x_new], x -= a[x_new]
    // The x_new from step 2 is the current_x for the next call to solve.
    // The value a[x_new] is a_arr[current_x + val_ax].
    // The y increase from this step is a_arr[current_x + val_ax].
    // The x change from this step is -(a_arr[current_x + val_ax]).
    // So, the next state is (current_x + val_ax - a_arr[current_x + val_ax])
    // and the y accumulated so far is val_ax + a_arr[current_x + val_ax].

    long long next_x_after_step2 = current_x + val_ax;
    long long y_accum_step2_and_3 = val_ax; // y from step 2

    if (next_x_after_step2 <= 0 || next_x_after_step2 > N_global) {
        // Program terminates after step 2, before step 3.
        // The problem states "If, after any step, x <= 0 or x > n, the program immediately terminates."
        // So, if x becomes invalid after step 2, it terminates.
        // The y accumulated is just val_ax.
        dp_state[current_x] = 2;
        dp_val[current_x] = val_ax;
        return val_ax;
    }

    long long val_ax_after_step2 = a_arr[next_x_after_step2];
    y_accum_step2_and_3 += val_ax_after_step2; // y from step 3

    long long next_x_after_step3 = next_x_after_step2 - val_ax_after_step2;

    long long res_from_next_state = solve(next_x_after_step3);

    if (res_from_next_state == -1) {
        dp_state[current_x] = 2; // Mark as visited, but result is -1
        dp_val[current_x] = -1;
        return -1;
    } else {
        dp_state[current_x] = 2;
        dp_val[current_x] = y_accum_step2_and_3 + res_from_next_state;
        return dp_val[current_x];
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    N_global = n;

    a_arr.resize(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_arr[i];
    }

    // dp_val and dp_state need to be sized for N_global + 1
    // They will be reset for each outer loop iteration (for each i from 1 to n-1)
    // No, they should be initialized once and then used across all calls to solve for a given a_arr[1].
    // The problem asks to run the program for each i (1 <= i <= n-1)
    // This means a_arr[1] changes for each i.
    // So, dp_val and dp_state must be cleared/reset for each i.

    for (int i = 1; i < n; ++i) {
        a_arr[1] = i; // Set a_1 for the current run

        dp_val.assign(n + 1, 0);
        dp_state.assign(n + 1, 0);

        long long result = solve(1); // Start simulation from x=1

        std::cout << result << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_index;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_index);
        children[i].in_line = false; // Child i leaves the line to be cured

        long long current_v_effect = children[i].v;
        long long total_d_effect_from_runners = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effects from child i's cry
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Apply accumulated d_effect from previous runners
            children[j].p -= total_d_effect_from_runners;
        }

        // Check for children running away due to low confidence
        // This loop might need to run multiple times if a chain reaction occurs
        bool new_runners_found;
        do {
            new_runners_found = false;
            long long current_d_effect_from_new_runners = 0;

            for (int j = i + 1; j < n; ++j) {
                if (children[j].in_line && children[j].p < 0) {
                    children[j].in_line = false; // Child j runs away
                    current_d_effect_from_new_runners += children[j].d;
                    new_runners_found = true;
                }
            }

            if (new_runners_found) {
                for (int j = i + 1; j < n; ++j) {
                    if (children[j].in_line) {
                        children[j].p -= current_d_effect_from_new_runners;
                    }
                }
            }
        } while (new_runners_found);
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The target value for a[0] must be at least 0.
                            // For subsequent elements, a[i] must be >= a[i-1].

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a[i] is not incremented (or incremented by a multiple of m, effectively 0)
        // The final value is current_a.
        // This is valid if current_a >= prev_val.

        // Case 2: a[i] is incremented.
        // The final value is (current_a + d) % m, where 1 <= d <= x.
        // We want this final value to be >= prev_val.
        // The smallest possible final value is (current_a + 1) % m.
        // The largest possible final value is (current_a + x) % m.

        // If current_a >= prev_val, we can potentially keep current_a as is.
        // This requires 0 increments for a[i] relative to x.
        // The effective increment needed is 0.
        // This is possible if 0 <= x.
        // So, if current_a >= prev_val, we can set the target for a[i] to current_a.
        // We don't need to increment it.

        // If current_a < prev_val, we *must* increment current_a.
        // We need to find a `d` such that `(current_a + d) % m >= prev_val`.
        // The smallest `d` that makes `(current_a + d) % m >= prev_val` is:
        // If current_a <= prev_val:
        //   If current_a + x >= prev_val:
        //     We can achieve prev_val by incrementing current_a by (prev_val - current_a).
        //     This requires (prev_val - current_a) increments.
        //     This is valid if (prev_val - current_a) <= x.
        //     In this case, we can set the target for a[i] to prev_val.
        //   Else (current_a + x < prev_val):
        //     We cannot reach prev_val by incrementing current_a up to x times.
        //     So, we must wrap around.
        //     The smallest value we can achieve that is >= prev_val is (current_a + d) % m.
        //     This happens when current_a + d >= m + prev_val (if prev_val is small)
        //     or current_a + d >= prev_val (if prev_val is large).
        //     The smallest value we can achieve that is >= prev_val is `prev_val` itself,
        //     if `prev_val` can be formed by `(current_a + d) % m` for some `d <= x`.
        //     This means `d = (prev_val - current_a + m) % m`.
        //     If this `d <= x`, then we can achieve `prev_val`.
        //     If `d > x`, we cannot achieve `prev_val`.
        //     In this case, we must take the smallest possible value for a[i] that is >= prev_val.
        //     This is `(current_a + d) % m` where `d` is the smallest increment such that
        //     `(current_a + d) % m >= prev_val`.
        //     This is equivalent to `prev_val`.
        //     The number of increments needed is `(prev_val - current_a + m) % m`.
        //     If this is `0`, it means `current_a >= prev_val`.
        //     If this is `> 0`, it means `current_a < prev_val`.
        //     Let `diff = (prev_val - current_a + m) % m`.
        //     If `diff <= x`, we can achieve `prev_val`.
        //     If `diff > x`, we cannot achieve `prev_val` by incrementing `current_a` `diff` times.
        //     In this case, we must take `current_a` as is, or increment it by `x`.
        //     If we increment `current_a` by `x`, the value becomes `(current_a + x) % m`.
        //     If `(current_a + x) % m < prev_val`, then it's impossible.
        //     If `(current_a + x) % m >= prev_val`, then we can set the target to `(current_a + x) % m`.
        //     But this is not right. We want to make it non-decreasing.
        //     We want to find the smallest `y` such that `y >= prev_val` and `y` can be formed from `current_a`
        //     by `d` increments, where `d <= x`.
        //     This means `y = (current_a + d) % m` for some `d <= x`.

        // Let's simplify. We need to find a target value `b_i` for `a_i` such that:
        // 1. `b_i >= prev_val`
        // 2. `b_i = (a_i + d) % m` for some `0 <= d <= x`.

        // If `a_i >= prev_val`:
        //   We have two choices for `b_i`:
        //   a) `b_i = a_i`. This requires `d=0` increments. This is valid if `0 <= x`.
        //   b) `b_i = (a_i + d) % m` where `d > 0`.
        //      We want `b_i >= prev_val`.
        //      If `a_i + x < m + prev_val` (i.e., `a_i + x` doesn't wrap around to be less than `prev_val`
        //      when considering `m` as a cycle), then we can potentially increment `a_i`
        //      to `a_i + d` such that `a_i + d >= prev_val`.
        //      The smallest `d` to make `(a_i + d) % m >= prev_val` is `0` if `a_i >= prev_val`.
        //      If `a_i >= prev_val`, we can just set `b_i = a_i`.
        //      This is always the best choice if possible, as it keeps `b_i` small.
        //      So, if `a_i >= prev_val`, we can set `b_i = a_i`.
        //      The only exception is if `a_i` is too large and we need to wrap it around to make it smaller.
        //      But we want `b_i >= prev_val`. So we prefer `a_i` if `a_i >= prev_val`.
        //      The only time we *must* increment `a_i` when `a_i >= prev_val` is if `a_i` is so large
        //      that `a_i` itself is not achievable with `x` operations (which is not the case, `d=0` is always possible).
        //      Or if `a_i` is too large and we want to make it smaller by wrapping around.
        //      Example: `m=10`, `prev_val=2`, `a_i=8`, `x=3`.
        //      If we don't increment, `b_i=8`. `8 >= 2`. Valid.
        //      If we increment by `d=1`, `b_i=9`. `9 >= 2`. Valid.
        //      If we increment by `d=2`, `b_i=0`. `0 < 2`. Invalid.
        //      If we increment by `d=3`, `b_i=1`. `1 < 2`. Invalid.
        //      So if `a_i >= prev_val`, we can set `b_i = a_i`. This is always valid.
        //      However, we might be able to achieve a smaller `b_i` by incrementing `a_i` and wrapping around.
        //      Example: `m=10`, `prev_val=2`, `a_i=8`, `x=5`.
        //      `a_i=8`. `prev_val=2`.
        //      Option 1: `b_i = a_i = 8`. Valid. `prev_val` for next is `8`.
        //      Option 2: Increment `a_i`.
        //          `d=1`: `b_i=9`. Valid.
        //          `d=2`: `b_i=0`. Invalid (`0 < prev_val`).
        //          `d=3`: `b_i=1`. Invalid.
        //          `d=4`: `b_i=2`. Valid! `2 >= prev_val`. This is better than `8`.
        //          `d=5`: `b_i=3`. Valid.
        //      So if `a_i >= prev_val`, we should check if `(a_i + d) % m` can be `prev_val` for some `d <= x`.
        //      This means `(prev_val - a_i + m) % m` increments. Let this be `d_needed`.
        //      If `d_needed <= x`, then we can achieve `prev_val`.
        //      In this case, we set `prev_val = prev_val`.
        //      Otherwise, we must set `prev_val = a_i`.

        // Let's re-evaluate. We need to find `b_i` such that `b_i >= prev_val` and `b_i = (a_i + d) % m` for some `0 <= d <= x`.
        // We want to choose the smallest such `b_i`.
        //
        // Consider the range of values `a_i` can become: `[a_i, (a_i+x)%m]` if no wrap-around,
        // or `[a_i, m-1] U [0, (a_i+x)%m]` if wrap-around.
        //
        // Let `target_val = prev_val`.
        //
        // If `a_i >= target_val`:
        //   We can potentially keep `a_i` as `a_i`. This requires `d=0` increments. This is always possible.
        //   So, `b_i = a_i` is a candidate.
        //   Can we achieve `target_val` by incrementing `a_i` and wrapping around?
        //   This means `(a_i + d) % m = target_val` for some `d > 0`.
        //   The number of increments `d` would be `(target_val - a_i + m) % m`.
        //   If this `d <= x`, then we can achieve `target_val`.
        //   In this case, we prefer `target_val` because it's smaller. So `prev_val` for next iteration becomes `target_val`.
        //   Otherwise (`d > x`), we cannot achieve `target_val` by wrapping around.
        //   So we must use `a_i` itself. `prev_val` for next iteration becomes `a_i`.
        //
        // If `a_i < target_val`:
        //   We *must* increment `a_i`.
        //   We need `(a_i + d) % m >= target_val`.
        //   The smallest `d` to achieve `target_val` is `target_val - a_i`.
        //   If `target_val - a_i <= x`:
        //     We can achieve `target_val`. So `prev_val` for next iteration becomes `target_val`.
        //   Else (`target_val - a_i > x`):
        //     We cannot reach `target_val` without wrapping around.
        //     Can we reach *any* value `y >= target_val`?
        //     The maximum value we can reach is `(a_i + x) % m`.
        //     If `(a_i + x) % m < target_val` (and `a_i + x` did not wrap around to be >= target_val),
        //     then it's impossible.
        //     This means `a_i + x < target_val` (no wrap-around) OR
        //     `a_i + x >= m` AND `(a_i + x) % m < target_val`.
        //     In this case, it's impossible to satisfy `b_i >= target_val`.
        //     So, `check` should return `false`.
        //     Otherwise, we can achieve some value `y >= target_val`.
        //     The smallest such `y` is `target_val` itself if `target_val - a_i <= x`.
        //     If `target_val - a_i > x`, then we cannot reach `target_val` directly.
        //     We must increment `a_i` by `x`. The new value is `(a_i + x) % m`.
        //     If `(a_i + x) % m < target_val`, then it's impossible.
        //     This happens if `a_i + x < m` and `a_i + x < target_val`.
        //     Or if `a_i + x >= m` and `(a_i + x) % m < target_val`.
        //     In this case, `check` should return `false`.
        //     Otherwise, `(a_i + x) % m >= target_val`.
        //     So, `prev_val` for next iteration becomes `(a_i + x) % m`.

        // Let's combine these conditions.
        // `a_i` is the current element. `prev_val` is the minimum value `a_i` must take.
        //
        // Option 1: Don't increment `a_i` (or increment by `m`, `2m`, etc.).
        //   The value remains `a_i`. This is valid if `a_i >= prev_val`.
        //   If this is chosen, `prev_val` for the next element becomes `a_i`.
        //
        // Option 2: Increment `a_i` by `d` times, where `1 <= d <= x`.
        //   The value becomes `(a_i + d) % m`.
        //   We want to find the smallest `d` such that `(a_i + d) % m >= prev_val`.
        //   Let `d_needed = (prev_val - a_i + m) % m`.
        //   If `d_needed == 0`, it means `a_i >= prev_val`.
        //     In this case, we can achieve `prev_val` by `0` increments.
        //     We can also achieve `prev_val` by `m` increments, `2m` increments, etc.
        //     But we are limited by `x` operations.
        //     If `d_needed <= x`, we can achieve `prev_val`.
        //     So, if `a_i >= prev_val` AND `(prev_val - a_i + m) % m <= x`,
        //     we can choose `prev_val` as the new `prev_val`.
        //     This is the preferred choice because it's smaller.
        //   Else (`d_needed > x` OR `a_i < prev_val`):
        //     We cannot achieve `prev_val` by `d_needed` increments because `d_needed > x`.
        //     We must increment `a_i` by some `d` such that `d <= x`.
        //     The smallest value `a_i` can take that is `>= prev_val` is `prev_val` itself.
        //     If `a_i < prev_val`:
        //       We need to increment `a_i` by at least `prev_val - a_i`.
        //       If `prev_val - a_i > x`, then we cannot reach `prev_val` directly.
        //       We must increment `a_i` by `x`. The new value is `(a_i + x) % m`.
        //       If `(a_i + x) % m < prev_val`, then it's impossible. Return `false`.
        //       Otherwise, `prev_val` for next iteration becomes `(a_i + x) % m`.
        //     If `a_i >= prev_val` but `(prev_val - a_i + m) % m > x`:
        //       We cannot wrap around to `prev_val`. So we must use `a_i`.
        //       `prev_val` for next iteration becomes `a_i`.

        // Let's try a simpler logic:
        // We need to find `b_i` such that `b_i >= prev_val` and `b_i = (a_i + d) % m` for some `0 <= d <= x`.
        // We want to choose the smallest such `b_i`.
        //
        // Candidate 1: `a_i` (if `a_i >= prev_val`). This corresponds to `d=0`.
        // Candidate 2: `prev_val` (if `prev_val` can be reached from `a_i` with `d <= x` increments).
        //   The number of increments needed to reach `prev_val` from `a_i` is `d_to_prev = (prev_val - current_a + m) % m`.
        //   If `d_to_prev <= x`, then `prev_val` is a possible target.
        //
        // If `current_a >= prev_val`:
        //   We have two options for the next `prev_val`:
        //   1. Keep `current_a` as is. Next `prev_val` becomes `current_a`. (This is always possible, `d=0 <= x`).
        //   2. Increment `current_a` to `prev_val` by wrapping around.
        //      This requires `d = (prev_val - current_a + m) % m` increments.
        //      If `d <= x`, then `prev_val` is achievable.
        //      In this case, we prefer `prev_val` over `current_a` because it's smaller.
        //      So, if `d <= x`, next `prev_val` becomes `prev_val`.
        //      Else (`d > x`), we cannot wrap around to `prev_val`. So we must use `current_a`.
        //      Next `prev_val` becomes `current_a`.
        //
        // If `current_a < prev_val`:
        //   We *must* increment `current_a`.
        //   We need to reach at least `prev_val`.
        //   The number of increments needed to reach `prev_val` is `d = prev_val - current_a`.
        //   If `d <= x`:
        //     We can achieve `prev_val`. Next `prev_val` becomes `prev_val`.
        //   Else (`d > x`):
        //     We cannot reach `prev_val` directly.
        //     We must increment `current_a` by `x`. The new value is `(current_a + x) % m`.
        //     If this new value `(current_a + x) % m < prev_val`, then it's impossible. Return `false`.
        //     (This check covers both cases: `current_a + x < m` and `(current_a + x) < prev_val`,
        //     OR `current_a + x >= m` and `(current_a + x) % m < prev_val`).
        //     Otherwise, `(current_a + x) % m >= prev_val`.
        //     Next `prev_val` becomes `(current_a + x) % m`.

        // Let's implement this refined logic:
        if (current_a >= prev_val) {
            // Option 1: Keep current_a as is. This is always possible (0 increments).
            // Option 2: Try to make current_a equal to prev_val by wrapping around.
            // This requires (prev_val - current_a + m) % m increments.
            long long diff_to_prev = (prev_val - current_a + m) % m;
            if (diff_to_prev <= x) {
                // We can achieve prev_val by wrapping around. This is the smaller option.
                // So, prev_val remains prev_val.
            } else {
                // We cannot achieve prev_val by wrapping around with <= x increments.
                // So, we must keep current_a as is.
                prev_val = current_a;
            }
        } else { // current_a < prev_val
            // We must increment current_a.
            // The minimum increments needed to reach prev_val is prev_val - current_a.
            long long diff_needed = prev_val - current_a;
            if (diff_needed > x) {
                // We cannot reach prev_val directly.
                // We must increment by x. The new value is (current_a + x) % m.
                // If this new value is still less than prev_val, it's impossible.
                if ((current_a + x) % m < prev_val) {
                    return false;
                }
                // Otherwise, the new value is (current_a + x) % m.
                // This becomes the new prev_val.
                prev_val = (current_a + x) % m;
            }
            // Else (diff_needed <= x), we can reach prev_val.
            // So, prev_val remains prev_val.
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1; // x can be from 0 to m-1
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // For any range [l, r] where l < r, the number 2 will always be a divisor
        // for at least floor(r/2) - ceil(l/2) + 1 numbers.
        // This count is (r/2) - ((l+1)/2) + 1.
        // For example, if l=3, r=6:
        // Numbers are 3, 4, 5, 6.
        // Divisors (excluding 1):
        // 3: {3}
        // 4: {2, 4}
        // 5: {5}
        // 6: {2, 3, 6}
        // Counts: 2 -> 2 times (from 4, 6), 3 -> 2 times (from 3, 6), 4 -> 1 time, 5 -> 1 time, 6 -> 1 time.
        // In this case, 2 and 3 both appear 2 times. Any is fine.
        // The problem asks for *any* integer that appears the maximum number of times.
        //
        // If l=2, r=2: output 2.
        // If l=2, r=3: numbers are 2, 3. Divisors: 2:{2}, 3:{3}. Max count is 1. Both 2 and 3 are valid.
        // If l=2, r=4: numbers are 2, 3, 4. Divisors: 2:{2}, 3:{3}, 4:{2,4}. Max count is 2 (for 2). Output 2.
        //
        // The number 2 is the smallest prime. It divides roughly half the numbers in any sufficiently large range.
        // For any other number 'd' (d > 2), the number of multiples of 'd' in [l, r] will be less than or equal to
        // the number of multiples of 2 in [l, r].
        // Specifically, count(d) = floor(r/d) - ceil(l/d) + 1.
        // Since d >= 3, r/d <= r/2 and l/d <= l/2.
        // So, count(d) <= count(2).
        //
        // The only exception is when l is odd and r is small, such that l itself is the most frequent divisor.
        // Example: l=3, r=6.
        // Multiples of 2: {4, 6}. Count = 2.
        // Multiples of 3: {3, 6}. Count = 2.
        // Here, 2 and 3 are tied. Outputting 2 is correct.
        //
        // The problem states "If there are multiple answers, print any of them."
        // The number 2 will always be a candidate for the maximum count, and often the unique maximum.
        // For any l < r, the number 2 will always be a divisor for at least one number (if r >= 2).
        // If l=2, r=2, output 2.
        // If l=3, r=3, output 3.
        // If l=19, r=29, output 2.
        // If l=3, r=6, output 3 (example output). My logic would output 2. Both are valid.
        //
        // The simplest answer that satisfies the condition "print any of them" is 2,
        // unless l == r, in which case the only divisor (other than 1) is l itself.
        //
        // Let's re-evaluate the example l=3, r=6.
        // Numbers: 3, 4, 5, 6
        // Divisors (excluding 1):
        // 3: {3}
        // 4: {2, 4}
        // 5: {5}
        // 6: {2, 3, 6}
        //
        // Counts:
        // 2: appears for 4, 6 (2 times)
        // 3: appears for 3, 6 (2 times)
        // 4: appears for 4 (1 time)
        // 5: appears for 5 (1 time)
        // 6: appears for 6 (1 time)
        //
        // Max count is 2. Both 2 and 3 are valid answers. The example output is 3.
        // My logic of always printing 2 (if l < r) is also valid.
        //
        // The problem is asking for *any* integer. The integer 2 is always a strong candidate.
        // If l=2, r=10^9, 2 is clearly the answer.
        // If l=10^9-1, r=10^9, 2 is still the answer if 10^9 is even.
        // If l=10^9-1, r=10^9+1 (hypothetical), 2 is still the answer.
        //
        // The only case where 2 might not be the answer is if l is odd and l is the only number in the range
        // that is a multiple of l, and there are fewer multiples of 2 than multiples of l.
        // This can only happen if l is very large and r is very close to l.
        // E.g., l=99, r=100.
        // Numbers: 99, 100
        // Divisors:
        // 99: {3, 9, 11, 33, 99}
        // 100: {2, 4, 5, 10, 20, 25, 50, 100}
        // Count for 2: 1 (from 100)
        // Count for 3: 1 (from 99)
        // Max count is 1. Any of {2, 3, 4, 5, ...} is valid. Outputting 2 is fine.
        //
        // The simplest solution is to always output 2 if l < r.
        // This is because 2 is the smallest prime, and thus has the highest density of multiples.
        // The number of multiples of k in [L, R] is floor(R/k) - ceil(L/k) + 1.
        // This count is maximized when k is minimized. Since we need k > 1, the minimum k is 2.
        // So, 2 will always have the maximum count or tie for the maximum count.
        //
        // The only edge case is l=r, where the answer is l itself.
        // For l < r, 2 is always a valid answer.

        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one partition (e.g., all 1s).
    // min_f = A[0] + A[1]
    // max_f = A[n-2] + A[n-1]
    // goodness = (A[n-2] + A[n-1]) - (A[0] + A[1])
    long long goodness1 = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The optimal strategy for this case is to put A[0] in one subsequence
    // and A[1]...A[n-1] in the other, or A[n-1] in one and A[0]...A[n-2] in the other.
    // Or, more generally, A[0] and A[n-1] in different subsequences.
    //
    // Let's try to put A[0] in S1 and A[1]...A[n-1] in S2.
    // min_f: A[0] + A[1] + h (A[0] in S1, A[1] in S2)
    // max_f: A[n-2] + A[n-1] (A[n-2], A[n-1] in S2)
    //
    // Let's try to put A[0] in S1 and A[n-1] in S2. All others can be in S1 or S2.
    // To minimize max_f and maximize min_f, we want to make the range of sums as small as possible.
    //
    // Consider the partition where A[0] is in S1, and all other elements A[1]...A[n-1] are in S2.
    // min_f = min(A[0]+A[1]+h, A[1]+A[2])
    // max_f = max(A[0]+A[n-1]+h, A[n-2]+A[n-1])
    //
    // The crucial observation is that if A[0] and A[n-1] are in different partitions,
    // then A[0] + A[n-1] + h will be a value of f.
    // If A[0] and A[1] are in different partitions, then A[0] + A[1] + h will be a value of f.
    // If A[n-2] and A[n-1] are in different partitions, then A[n-2] + A[n-1] + h will be a value of f.
    //
    // The minimum possible sum of two elements is A[0] + A[1].
    // The maximum possible sum of two elements is A[n-2] + A[n-1].
    //
    // If A[0] and A[1] are in the same partition, and A[n-2] and A[n-1] are in the same partition,
    // and A[0] and A[n-1] are in different partitions.
    // Then min_f = A[0] + A[1]
    // max_f = A[n-2] + A[n-1] + h
    // goodness = (A[n-2] + A[n-1] + h) - (A[0] + A[1])
    // This is the partition where A[0] is in S1, and A[1]...A[n-1] are in S2.
    // Or A[n-1] is in S1, and A[0]...A[n-2] are in S2.
    //
    // Let's consider the partition where elements[0] is in partition 1, and all others are in partition 2.
    // min_f = elements[0].value + elements[1].value + h (since elements[0] is in S1, elements[1] in S2)
    // max_f = elements[n-2].value + elements[n-1].value (since elements[n-2], elements[n-1] in S2)
    // This is only if n >= 2. If n=2, then S2 only has one element, so no sum within S2.
    // If n=2, elements[0] in S1, elements[1] in S2. Only f(elements[0], elements[1]) = elements[0]+elements[1]+h.
    // min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    //
    // For n > 2:
    // min_f_val = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    // max_f_val = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    //
    // This is the partition where elements[0] is in S1, and elements[1]...elements[n-1] are in S2.
    // The values of f are:
    // 1. elements[0].value + elements[j].value + h for j=1...n-1
    // 2. elements[i].value + elements[j].value for i,j=1...n-1, i!=j
    //
    // min_f_val = elements[0].value + elements[1].value + h
    // max_f_val = elements[n-2].value + elements[n-1].value
    //
    // This is incorrect. The minimum value of f could be A[1]+A[2] if n > 2.
    // The maximum value of f could be A[0]+A[n-1]+h.
    //
    // Let's consider the partition where elements[0] is in S1, and elements[1]...elements[n-1] are in S2.
    // The minimum possible f value is `min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)`.
    // The maximum possible f value is `max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)`.
    //
    // Let's call this partition strategy "split_min".
    // S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
    long long min_f_split_min;
    long long max_f_split_min;
    if (n == 2) {
        min_f_split_min = elements[0].value + elements[1].value + h;
        max_f_split_min = elements[0].value + elements[1].value + h;
    } else {
        min_f_split_min = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
        max_f_split_min = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    }
    long long goodness_split_min = max_f_split_min - min_f_split_min;
    std::vector<int> partition_split_min(n);
    partition_split_min[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_split_min[elements[i].original_index] = 2;
    }

    // Let's consider the partition where elements[n-1] is in S1, and elements[0]...elements[n-2] are in S2.
    // This is symmetric to the previous case.
    // min_f_val = std::min(elements[n-2].value + elements[n-1].value + h, elements[0].value + elements[1].value);
    // max_f_val = std::max(elements[0].value + elements[n-1].value + h, elements[n-3].value + elements[n-2].value);
    //
    // S1 = {elements[n-1]}, S2 = {elements[0], ..., elements[n-2]}
    long long min_f_split_max;
    long long max_f_split_max;
    if (n == 2) {
        min_f_split_max = elements[0].value + elements[1].value + h;
        max_f_split_max = elements[0].value + elements[1].value + h;
    } else {
        min_f_split_max = std::min(elements[n-2].value + elements[n-1].value + h, elements[0].value + elements[1].value);
        max_f_split_max = std::max(elements[0].value + elements[n-1].value + h, elements[n-3].value + elements[n-2].value);
    }
    long long goodness_split_max = max_f_split_max - min_f_split_max;
    std::vector<int> partition_split_max(n);
    partition_split_max[elements[n-1].original_index] = 1;
    for (int i = 0; i < n - 1; ++i) {
        partition_split_max[elements[i].original_index] = 2;
    }

    // Compare the goodness values
    long long min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    if (goodness_split_min < min_goodness) {
        min_goodness = goodness_split_min;
        best_partition = partition_split_min;
    }
    if (goodness_split_max < min_goodness) {
        min_goodness = goodness_split_max;
        best_partition = partition_split_max;
    }

    // A special case for n=2:
    // If n=2, elements[0] and elements[1].
    // Case 1: Both in partition 1. No f values. This is not allowed by problem statement (distinct elements).
    // The problem states "pairs of distinct elements (that is i != j)".
    // If all elements are in one subsequence, and there are only two elements, say A and B,
    // then f(A,B) = A+B. min_f = max_f = A+B. Goodness = 0.
    // If A in S1, B in S2, then f(A,B) = A+B+h. min_f = max_f = A+B+h. Goodness = 0.
    // So for n=2, goodness is always 0.
    if (n == 2) {
        min_goodness = 0;
        // Any partition is fine, e.g., 1 1
        best_partition[elements[0].original_index] = 1;
        best_partition[elements[1].original_index] = 1;
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

