// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: One cut, two pieces.
    // We can form s_suffix + s_prefix.
    // Iterate through all possible cut points (i from 1 to n-1).
    // s_prefix = s.substr(0, i)
    // s_suffix = s.substr(i)
    // New string = s.substr(i) + s.substr(0, i)
    for (int i = 1; i < n; ++i) {
        std::string s_suffix = s.substr(i);
        std::string s_prefix = s.substr(0, i);
        std::string new_s = s_suffix + s_prefix;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts, three pieces.
    // This is always possible unless all characters in s are the same.
    // If all characters are the same (e.g., "aaaa"), then any rearrangement
    // of pieces will result in the same string "aaaa".
    // In this case, it's impossible to form a new string s' != s.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, we can always achieve k=2.
        // Example: s = "nolon"
        // Cut: no | l | on
        // Rearrange: on | l | no -> "onlno" (palindrome, != "nolon")
        // This works by taking s[0]...s[N/2-1] and s[N/2+1]...s[N-1]
        // and swapping them around s[N/2].
        // More generally, if s is not all same chars, then s.substr(0, N-1)
        // is not a palindrome, or s.substr(1, N-1) is not a palindrome.
        // Consider s = "abacaba".
        // s.substr(0, N-1) = "abacab". This is not a palindrome.
        // If s is not all same chars, then s.substr(0, N-1) is not a palindrome.
        // If s.substr(0, N-1) is not a palindrome, then we can cut s into
        // s[0] and s.substr(1, N-1).
        // The string s.substr(0, N-1) is a prefix of s.
        // If s is not all same characters, then there must be at least two distinct characters.
        // Since s is a palindrome, if s[0] != s[1], then s[N-1] != s[N-2].
        // If s is not all same characters, then s.substr(0, N-1) is not a palindrome.
        // For example, if s = "abacaba", s.substr(0, N-1) = "abacab".
        // If s = "otto", s.substr(0, N-1) = "ott".
        // If s = "kinnikkinnik", s.substr(0, N-1) = "kinnikkinnik".
        // The problem statement guarantees that s is a palindrome.
        // If s is not composed of all identical characters, then it's always possible to find a new palindrome with 2 cuts.
        // Consider the string s' = s.substr(1) + s[0]. This is a rotation.
        // If s is not all same characters, then s.substr(0, N-1) is not a palindrome.
        // This implies that s.substr(0, N-1) != s.substr(0, N-1) reversed.
        // If s is not all same characters, then there exists some i such that s[i] != s[0].
        // This means that s is not of the form "aaaaa...".
        // If s is not of the form "aaaaa...", then s.substr(0, n-1) is not a palindrome.
        // For example, "abacaba". s.substr(0, 6) = "abacab". Not a palindrome.
        // "nolon". s.substr(0, 4) = "nolo". Not a palindrome.
        // "otto". s.substr(0, 3) = "ott". Not a palindrome.
        // If s.substr(0, n-1) is not a palindrome, then we can cut s into s[0] and s.substr(1, n-1).
        // Then we can rearrange them to form s.substr(1, n-1) + s[0].
        // This is a rotation.
        // The problem states that if s is not all same characters, then k=2 is always possible.
        // This is because we can always find a cut that results in a non-palindrome prefix.
        // For example, take s = "abacaba".
        // Cut into "a" | "bacab" | "a". Rearrange to "a" | "bacab" | "a" (same).
        // Cut into "aba" | "c" | "aba". Rearrange to "aba" | "c" | "aba" (same).
        // The logic for k=2 is that if not all characters are the same, we can always find a way.
        // For example, take s = "nolon".
        // Cut: "no" | "l" | "on". Rearrange: "on" | "l" | "no" -> "onlno". This is a palindrome and != "nolon".
        // This requires 2 cuts.
        // The only case where k=2 is not possible is if all characters are the same.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for tracks to read
    int h_idx = 0; // Current index for heads

    while (p_idx < m) {
        if (h_idx >= n) {
            // No more heads available, but there are still tracks to read
            return false;
        }

        // Find the first head that can reach p[p_idx]
        // A head at h[h_idx] can reach p[p_idx] if p[p_idx] is within [h[h_idx] - T, h[h_idx] + T]
        // This means h[h_idx] - T <= p[p_idx] <= h[h_idx] + T
        // Or, equivalently, abs(h[h_idx] - p[p_idx]) <= T

        // We need to find a head h[h_idx] such that h[h_idx] + T >= p[p_idx]
        // And also, this head must be able to reach p[p_idx] from its left side, i.e., h[h_idx] - T <= p[p_idx]
        // The first condition is more restrictive for finding a suitable head.
        // If h[h_idx] is too far to the left, it cannot reach p[p_idx] even with T seconds.
        // So, we advance h_idx until h[h_idx] + T >= p[p_idx].
        // This ensures that h[h_idx] is at least "close enough" to p[p_idx] from its right side.
        while (h_idx < n && h[h_idx] + T < p[p_idx]) {
            h_idx++;
        }

        if (h_idx >= n) {
            // No head can reach p[p_idx] from its right side
            return false;
        }

        // Now, h[h_idx] is the first head such that h[h_idx] + T >= p[p_idx].
        // This head can potentially cover p[p_idx].
        // We must also check if it can reach p[p_idx] from its left side: h[h_idx] - T <= p[p_idx].
        if (h[h_idx] - T > p[p_idx]) {
            // This head is too far to the right to reach p[p_idx]
            // And any subsequent head h[h_idx+1], h[h_idx+2]... will be even further right,
            // so they also won't be able to reach p[p_idx].
            return false;
        }

        // If we reach here, h[h_idx] can cover p[p_idx].
        // This head can cover all tracks in the range [p[p_idx], h[h_idx] + T].
        // We greedily cover as many tracks as possible with this head.
        long long current_head_coverage_limit = h[h_idx] + T;
        while (p_idx < m && p[p_idx] <= current_head_coverage_limit) {
            p_idx++;
        }

        // Move to the next head for the remaining tracks
        h_idx++;
    }

    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max coord) - 1 (min coord) + 10^10 (max coord) - 1 (min coord)
                                    // A safer upper bound is max(p_m - h_1, h_n - p_1) which can be up to 10^10.
                                    // Or simply 2 * 10^10, as a head might need to move from 1 to 10^10.
                                    // The difference between max p and min h can be 10^10.
                                    // The difference between max h and min p can be 10^10.
                                    // So 10^10 is a good upper bound. Let's use 2 * 10^10 to be safe.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <numeric> // For std::accumulate

// Function to calculate the parity of a 01-string
// Returns 1 if there's an odd number of '1's, 0 otherwise.
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate the initial parity of string a
    int parity_a = calculate_parity(a);

    // The maximum possible number of '1's in a string derived from 'a'
    // that has length |b| is:
    // (initial '1's in 'a') + (number of parity bits appended)
    // The number of parity bits appended can be at most |b| - |a|
    // if |b| > |a|, or 0 if |b| <= |a|.
    // So, the maximum number of '1's is parity_a + (max_length - current_length)
    // where max_length is the length of the string we are considering.

    // We need to find if 'b' can be a suffix of some string 'a_prime'
    // where 'a_prime' is formed by 'a' followed by some parity bits.
    // The length of 'a_prime' must be at least |b|.

    // Let's count the '1's in 'a' and 'b'.
    int ones_in_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a++;
        }
    }

    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // The maximum number of '1's we can have in a string of length L
    // that is derived from 'a' by appending parity bits.
    // If we append a '0', the count of '1's doesn't change.
    // If we append a '1', the count of '1's increases by 1.
    // The parity of the string 'a' is `ones_in_a % 2`.
    // If `ones_in_a % 2 == 1`, we append '1', increasing `ones_in_a` by 1.
    // If `ones_in_a % 2 == 0`, we append '0', `ones_in_a` stays the same.
    // So, `ones_in_a` can only increase if its current parity is 1.
    // The maximum number of '1's we can achieve in a string of length `len`
    // starting from `a` is `ones_in_a + (len - a.length())` if we assume
    // we always append '1's. This is not quite right.

    // A simpler approach:
    // The number of '1's in 'a' can be increased by at most 1 for every 2 characters appended.
    // More precisely, if current_ones is the count of '1's in the current string,
    // and current_len is its length:
    // If current_ones % 2 == 1, we append '1'. New ones_count = current_ones + 1.
    // If current_ones % 2 == 0, we append '0'. New ones_count = current_ones.
    // So, the number of '1's can increase by at most 1 for each appended character
    // if the parity is always 1.
    // The maximum number of '1's we can have in a string of length `L`
    // that is derived from `a` is `ones_in_a + (L - a.length())` if we could always append '1'.
    // However, we can only append '1' if the current parity is 1.
    // If the current parity is 0, we append '0', and the number of '1's doesn't change.
    // The number of '1's can increase by at most 1 for every two characters appended.
    // Example: 00 -> 000 (parity 0) -> 0000 (parity 0)
    // Example: 01 -> 011 (parity 1) -> 0110 (parity 0) -> 01100 (parity 0)
    // The maximum number of '1's we can have in a string of length `L`
    // is `ones_in_a + ceil((L - a.length()) / 2.0)` if `ones_in_a` is odd,
    // or `ones_in_a + floor((L - a.length()) / 2.0)` if `ones_in_a` is even.
    // This is equivalent to `ones_in_a + (L - a.length() + (ones_in_a % 2)) / 2`.
    // No, this is not quite right either.

    // Let's re-evaluate the maximum number of ones.
    // If we have `k` ones, and `k` is odd, we append '1', new ones = `k+1`.
    // If we have `k` ones, and `k` is even, we append '0', new ones = `k`.
    // So, the number of ones can increase by at most 1 for each operation,
    // but only if the current count of ones is odd.
    // The maximum number of ones in a string of length `L` derived from `a`
    // is `ones_in_a + (L - a.length())` if `ones_in_a` is odd,
    // and `ones_in_a + (L - a.length() - 1)` if `ones_in_a` is even and `L - a.length() > 0`.
    // This is equivalent to `ones_in_a + (L - a.length())` if `ones_in_a` is odd.
    // If `ones_in_a` is even, we append '0', so `ones_in_a` remains even.
