    // `min_r_with_pattern[i]` = `min(min_r_with_pattern[i+1], first_bad_r[i-1])`.
    // `first_bad_r[i-1]` is the smallest `r` (1-indexed) for a pattern starting at `i-1`.
    // `min_r_with_pattern[i+1]` propagates the minimum `r` from patterns starting at `i` or later.

    std::vector<int> min_r_with_pattern(n + 2, n + 1); // n+2 size for 1-indexed l up to n, and l=n+1 for base case

    for (int l = n; l >= 1; --l) {
        min_r_with_pattern[l] = std::min(min_r_with_pattern[l + 1], first_bad_r[l - 1]);
        // For a given l, any r from l to min_r_with_pattern[l]-1 is a "bad" pair.
        // The number of such r's is (min_r_with_pattern[l]-1) - l + 1.
        // If min_r_with_pattern[l]-1 < l, then this is 0.
        bad_pairs += std::max(0, min_r_with_pattern[l] - 1 - l + 1);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

