    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then there is some p[j] > p[i], so min(p[i], p[j]) = p[i].
        // If p[i] is n, then for all j != i, p[j] < p[i], so min(p[i], p[j]) = p[j].
        // In this case, the maximum value in row i (excluding a[i][i]) would be n-1.
        // So, if max_val_in_row is n-1, p[i] must be n.
        // Otherwise, p[i] is the maximum value found in its row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

