    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut
        // should be i times the area of one piece.
        // Total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area from apex to i-th cut = i * (h / (2n)).
        // Let x_i be the height of the triangle formed by the apex and the i-th cut.
        // By similar triangles, the base of this smaller triangle is x_i / h.
        // Area of this smaller triangle = (1/2) * (x_i / h) * x_i = x_i^2 / (2h).
        // So, x_i^2 / (2h) = i * (h / (2n)).
        // x_i^2 = i * h^2 / n.
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix = a[n - 1]; // Initialize with the last element

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is
            // either equal to or less than min_suffix.
            // In this case, a[i] becomes the new minimum for elements
            // to its left.
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

