    int open_needed = k / 2;
    int close_needed = k / 2;
    int current_open_count = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
                current_open_count++;
            }
        } else { // c == ')'
            if (close_needed > 0 && current_open_count > 0) {
                result += ')';
                close_needed--;
                current_open_count--;
            }
        }
