#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // such that a_i >= i for i=0...L-1
    int L = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            L++;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // such that a_i >= (n-1)-i for i=R...n-1
    int R = n - 1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1) - i) {
            R--;
        } else {
            break;
        }
    }
    R++; // R is now the 0-indexed start of the valid suffix

    // If L > R, it means there is at least one index k (0-indexed)
    // such that a[0...k] can be made strictly increasing (0,1,...,k)
    // AND a[k...n-1] can be made strictly decreasing (k,k-1,...,0)
    // This k would be any index from R to L-1.
    // For example, if L=3, R=1, then k can be 1 or 2.
    // If k=1, a[0] can be 0, a[1] can be 1. a[1] can be 1, a[2] can be 0.
    // The condition is L > R (0-indexed) or L-1 >= R (0-indexed)
    // which means the valid prefix indices [0, L-1] and valid suffix indices [R, n-1]
    // have an overlap. The overlap is [R, L-1]. If R <= L-1, there's an overlap.
    if (L > R) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

