int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // First, make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // If a[median_idx] is less than s, we need to increase it.
    // All elements to its right (a[median_idx+1] to a[n-1]) must be >= s.
    // If any of them are < s, we must increase them to s.
    if (a[median_idx] < s) {
        for (int i = median_idx + 1; i < n; ++i) {
            if (a[i] < s) {
                operations += (s - a[i]);
            } else {
                // Since the array is sorted, all subsequent elements will also be >= s.
                break;
            }
        }
    }
    // If a[median_idx] is greater than s, we need to decrease it.
    // All elements to its left (a[0] to a[median_idx-1]) must be <= s.
    // If any of them are > s, we must decrease them to s.
    else if (a[median_idx] > s) {
        for (int i = median_idx - 1; i >= 0; --i) {
            if (a[i] > s) {
                operations += (a[i] - s);
            } else {
                // Since the array is sorted, all previous elements will also be <= s.
                break;
            }
        }
    }
    // If a[median_idx] == s, no additional operations are needed for elements
    // to its left or right to satisfy the median property, as long as they
    // are already in their correct relative positions (which they are due to sorting).
    // The elements to the left are <= s, and to the right are >= s.

    std::cout << operations << std::endl;

    return 0;
}

