        // The i-th smallest A value should be paired with the i-th largest B value.
        // The original index of this B value is b_elements[i].original_index.
        // So, result_a[b_elements[i].original_index] should be a_elements[i].value.
        result_a[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

