int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long N;
        std::cin >> N;
        long long chanek_coins = 0;
        bool chanek_turn = true;
        while (N > 0) {
            if (N % 2 == 1) { // N is odd
                if (chanek_turn) {
                    chanek_coins += 1;
                }
                N -= 1;
            } else { // N is even
                if (N == 2) { // Special case for N=2, always take 1
                    if (chanek_turn) {
                        chanek_coins += 1;
                    }
                    N -= 1;
                } else if ((N / 2) % 2 == 1) { // N/2 is odd
                    // If N/2 is odd, taking N/2 leaves an odd number of coins (N/2).
                    // Taking 1 leaves an odd number of coins (N-1).
                    // Both lead to an odd number of coins for the next player.
                    // Taking N/2 is better for current player.
                    if (chanek_turn) {
                        chanek_coins += N / 2;
                    }
                    N /= 2;
                } else { // N/2 is even
                    // If N/2 is even, taking N/2 leaves an even number of coins (N/2).
                    // Taking 1 leaves an odd number of coins (N-1).
                    // To maximize own score, current player wants to leave an odd number of coins for opponent.
                    // Taking 1 leaves N-1 (odd) for opponent.
                    if (chanek_turn) {
                        chanek_coins += 1;
                    }
                    N -= 1;
                }
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_coins << "\n";
    }
    return 0;
}

