void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need sum' = 2 * xor_sum'
    // Let's append two elements: current_xor_sum and current_sum + current_xor_sum
    // New sum: S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // New XOR sum: X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X' = 0 ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum
    // S' = 2 * (current_sum + current_xor_sum)
    // So, S' = 2 * X' holds.

    // The problem statement guarantees that a solution always exists by appending at most 3 elements.
    // The strategy of appending `X` and `S+X` always works.
    // This strategy appends 2 elements.
    // The values can be large, up to 10^18, so use long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

