#include <numeric>
#include <algorithm>

// Function to check if a subarray is a permutation of length `len`
// `arr` is the array, `start_idx` is the starting index (0-based), `len` is the length
// `max_val_expected` is the expected maximum value in the permutation (which is `len`)
bool is_permutation(const std::vector<int>& arr, int start_idx, int len, int max_val_expected) {
    if (len == 0) return false; // Permutations must have non-zero length
    if (max_val_expected != len) return false; // Max value must be equal to length

    std::vector<bool> seen(len + 1, false); // Use 1-based indexing for values
    int current_max = 0;

    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > current_max) {
            current_max = val;
        }
    }
    return current_max == len; // Check if max value is indeed len
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        std::vector<int> prefix_max(n);
        std::vector<bool> prefix_is_perm(n, false);
        std::vector<bool> seen_prefix(n + 1, false);
        int current_max_prefix = 0;
        bool distinct_prefix = true;

        for (int i = 0; i < n; ++i) {
            int val = a[i];
            if (val <= 0 || val > n || seen_prefix[val]) { // val > n is an optimization, max can't be > n
                distinct_prefix = false;
            } else {
                seen_prefix[val] = true;
            }
            if (val > current_max_prefix) {
                current_max_prefix = val;
            }
            prefix_max[i] = current_max_prefix;
            if (distinct_prefix && current_max_prefix == (i + 1)) {
                prefix_is_perm[i] = true;
            }
        }

        std::vector<int> suffix_max(n);
        std::vector<bool> suffix_is_perm(n, false);
        std::vector<bool> seen_suffix(n + 1, false);
        int current_max_suffix = 0;
        bool distinct_suffix = true;

        for (int i = n - 1; i >= 0; --i) {
            int val = a[i];
            if (val <= 0 || val > n || seen_suffix[val]) { // val > n is an optimization, max can't be > n
                distinct_suffix = false;
            } else {
                seen_suffix[val] = true;
            }
            if (val > current_max_suffix) {
                current_max_suffix = val;
            }
            suffix_max[i] = current_max_suffix;
            if (distinct_suffix && current_max_suffix == (n - i)) {
                suffix_is_perm[i] = true;
            }
        }

        std::vector<std::pair<int, int>> solutions;
        for (int l1 = 1; l1 < n; ++l1) { // l1 from 1 to n-1
            int l2 = n - l1;
            if (prefix_is_perm[l1 - 1] && suffix_is_perm[l1]) {
                solutions.push_back({l1, l2});
            }
        }

        std::cout << solutions.size() << "\n";
        for (const auto& p : solutions) {
            std::cout << p.first << " " << p.second << "\n";
        }
    }
    return 0;
}

