// Function to convert a number to its parity pattern string
// The pattern will always be 18 characters long, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern += '0';
            } else { // Odd digit
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 characters long
    // The pattern is built from right to left, so we need to reverse it
    // and then pad. Or, more simply, pad and then reverse.
    // Let's just pad to 18 characters.
    // Example: 241 -> "100". If max_len=18, it becomes "000000000000000100"
    // The problem statement implies padding from the left of the *number's decimal representation*.
    // So, 241 -> 00...00241. Parity pattern for 241 is 001.
    // If we want a fixed length pattern, say 18, then 241 becomes 00...00241.
    // The parity pattern would be 00...00001.
    // My current `pattern` string is built from right to left.
    // For 241: 1 (odd) -> '1', 4 (even) -> '0', 2 (even) -> '0'. `pattern` is "100".
    // This is the reverse of the "001" pattern.
    // So, we need to pad this reversed string with '0's until it's 18 chars long.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string
    // The key is the 18-character parity pattern string, value is its count.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string p = get_parity_pattern(a);
            pattern_counts[p]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string p = get_parity_pattern(a);
            pattern_counts[p]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 characters long
            // The problem states: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // And "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we should always compare fixed-length patterns.
            // The `get_parity_pattern` function already produces an 18-char string.
            // So, we need to convert the query pattern `s` to an 18-char string as well.
            // The pattern `s` is given from left to right.
            // Example: s = "010". This means 0 for 1st digit, 1 for 2nd, 0 for 3rd (from right).
            // So, "010" corresponds to "010" when read from right to left.
            // If s = "010", and max_len = 18, it becomes "000000000000000010".
            // The `get_parity_pattern` function for 241 gives "100" (reversed).
            // So, if query is "010", we need to reverse it to "010" and then pad.
            // No, the problem says "i-th from the right digit of the pattern".
            // So, if s = "010", s[0] is 0, s[1] is 1, s[2] is 0.
            // The rightmost digit of the pattern is s[s.length()-1].
            // The pattern string `s` is given in standard order (most significant digit first).
            // But the matching rule is "i-th from the right digit".
            // So, if s = "010", rightmost is '0', next is '1', next is '0'.
            // This means the pattern string `s` should be interpreted as if it's already reversed
            // when comparing to the `get_parity_pattern` output.
            // Example: s = "010".
            // Integer 92: 2 (even) -> '0', 9 (odd) -> '1'. Parity pattern for 92 is "01".
            // Padded to 18: "00...0010".
            // Query pattern "010". Padded to 18: "00...00010".
            // These match.
            // So, the `get_parity_pattern` function produces a string where index 0 is the rightmost digit's parity.
            // The query pattern `s` is given in standard order.
            // We need to reverse `s` and then pad it to 18 characters.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

