// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest divisor x of p such that x is not divisible by q.
        // This means we must remove some factors from p such that the resulting number is no longer divisible by q.
        // To maximize x, we should remove the minimum necessary factors.
        // This implies we should remove factors related to q.
        // Let q = q1^a1 * q2^a2 * ... * qk^ak be the prime factorization of q.
        // If x is divisible by q, then x must have at least q1^a1 * ... * qk^ak as factors.
        // To make x not divisible by q, we must reduce the power of at least one prime factor qi in x
        // to be less than its power ai in q.
        // To maximize x, we should try reducing the power of only one prime factor qi, and only by one unit
        // (i.e., divide p by qi until it's no longer divisible by q, but keep as many qi factors as possible).

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long q_factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by q_factor until it's no longer divisible by q_factor
            // or until current_p is no longer divisible by q.
            // The goal is to find the largest divisor of p that is not divisible by q.
            // We iterate through each prime factor of q. For each prime factor `f` of `q`,
            // we try to construct a candidate `x` by dividing `p` by `f` repeatedly
            // until `p` is no longer divisible by `q`.
            // This `x` will be `p / (f^k)` for some `k`.
            // We want to find the largest such `x`.

            // Calculate the highest power of q_factor that divides p
            long long temp_p = p;
            while (temp_p % q_factor == 0) {
                temp_p /= q_factor;
            }
            // Now temp_p is p with all factors of q_factor removed.
            // We need to find the largest multiple of temp_p that is a divisor of p
            // and is not divisible by q.
            // This means we can re-introduce factors of q_factor up to a certain point.
            // The number of factors of q_factor in p is (p / temp_p) / q_factor.
            // Let p = temp_p * (q_factor^k).
            // We want to find x = temp_p * (q_factor^j) such that x % q != 0 and j is maximized.
            // The largest such j would be k-1 if (temp_p * (q_factor^(k-1))) % q != 0.
            // More generally, we want to find the largest divisor of p that is not divisible by q.
            // Consider p / (q_factor^k) where q_factor^k is the highest power of q_factor that divides q.
            // No, this is not quite right.

            // Let's re-think:
            // We have p. We know p % q == 0.
            // We want to find max x such that p % x == 0 and x % q != 0.
            // Consider a prime factor `f` of `q`.
            // We can form a candidate `x` by dividing `p` by `f` repeatedly until `x` is no longer divisible by `q`.
            // Example: p=12, q=6. Prime factors of q=6 are 2, 3.
            // For f=2:
            // p=12. 12%6==0. Divide by 2: 6. 6%6==0. Divide by 2: 3. 3%6!=0. Candidate x=3.
            // For f=3:
            // p=12. 12%6==0. Divide by 3: 4. 4%6!=0. Candidate x=4.
            // Max of (3, 4) is 4.

            long long current_candidate_x = p;
            while (current_candidate_x % q_factor == 0 && current_candidate_x % q == 0) {
                current_candidate_x /= q_factor;
            }
            max_x = std::max(max_x, current_candidate_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

