            // If f1 (move left) is 0, robot cannot move left.
            // So, its final X coordinate must be >= its current X coordinate.
            // This means X >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // If f2 (move up) is 0, robot cannot move up.
            // So, its final Y coordinate must be <= its current Y coordinate.
            // This means Y <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
            // If f3 (move right) is 0, robot cannot move right.
            // So, its final X coordinate must be <= its current X coordinate.
            // This means X <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If f4 (move down) is 0, robot cannot move down.
            // So, its final Y coordinate must be >= its current Y coordinate.
            // This means Y >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. The problem guarantees that if a solution exists,
