#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: Not enough moves to reach the target
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        long long ans;
        long long parity_diff = (abs_n % 2) - (abs_m % 2);

        if (parity_diff == 0) { // abs_n and abs_m have the same parity
            // If k has the same parity as abs_n (and abs_m), we can reach it.
            // The maximum diagonal moves is k.
            // If k has different parity, we need to make an even number of "wasted" moves.
            // Each wasted move reduces diagonal count by 1.
            // A wasted move (e.g., (0,0)->(1,0)->(0,0)) takes 2 steps and changes parity of current position.
            // If k and abs_n have different parity, we need to make at least one pair of moves
            // that effectively cancels out, like (x,y) -> (x+1,y) -> (x,y).
            // This costs 2 moves and changes the parity of the total moves used.
            // So, if (k - abs_n) is odd, we must reduce k by 2.
            if ((k - abs_n) % 2 == 0) {
                ans = k;
            } else {
                ans = k - 2;
            }
        } else { // abs_n and abs_m have different parity
            // If abs_n and abs_m have different parity, the target (abs_n, abs_m)
            // is on a square of different color than (0,0) if we consider a chessboard pattern.
            // A diagonal move always changes the parity of both coordinates, so it preserves the color.
            // A non-diagonal move changes the parity of exactly one coordinate, so it flips the color.
            // To reach a different colored square, we must make an odd number of non-diagonal moves.
            // This means the total number of moves k must have a different parity than abs_n (and abs_m).
            // If k has the same parity as abs_n, it's impossible.
            // Example: (0,0) to (1,0). abs_n=1, abs_m=0. Parity diff.
            // If k=1, (0,0)->(1,0) is 1 move, 0 diagonal.
            // If k=2, impossible to reach (1,0) in 2 moves. (0,0)->(1,1)->(1,0) is 2 moves, 1 diagonal.
            // (0,0)->(1,0)->(0,0) is 2 moves, 0 diagonal.
            // The key is that if abs_n and abs_m have different parity, then (abs_n + abs_m) is odd.
            // The minimum number of moves to reach (abs_n, abs_m) is abs_n.
            // The parity of the sum of coordinates (x+y) changes with each move.
            // (x+y) -> (x+dx+y+dy). (dx+dy) can be 0, 1, 2, -1, -2.
            // If (dx,dy) is (1,0), (0,1), (-1,0), (0,-1), then dx+dy is 1 or -1 (odd).
            // If (dx,dy) is (1,1), (1,-1), (-1,1), (-1,-1), then dx+dy is 0, 2, -2 (even).
            // So, non-diagonal moves flip the parity of (x+y). Diagonal moves preserve it.
            // (0,0) has sum 0 (even). (abs_n, abs_m) has sum (abs_n+abs_m).
            // If (abs_n+abs_m) is odd, we need an odd number of non-diagonal moves.
            // If (abs_n+abs_m) is even, we need an even number of non-diagonal moves.
            //
            // The number of non-diagonal moves is (k - num_diagonal_moves).
            // So, (k - num_diagonal_moves) must have the same parity as (abs_n + abs_m).
            //
            // If abs_n and abs_m have different parity, then (abs_n + abs_m) is odd.
            // We need (k - num_diagonal_moves) to be odd.
            // This means k and num_diagonal_moves must have different parities.
            //
            // The maximum possible diagonal moves is k.
            // If k and abs_n have different parities, then k and abs_m also have different parities.
            // This means k and (abs_n + abs_m) have different parities.
            // So, (k - num_diagonal_moves) must be odd.
            // If we try to maximize num_diagonal_moves to k, then (k - k) = 0 (even).
            // This doesn't work. We need to reduce num_diagonal_moves by 1 to make (k - (k-1)) = 1 (odd).
            // So, the maximum diagonal moves would be k-1.
            ans = k - 1;
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            std::cout << "NO\n";
            return;
        }
        if (adj[c].size() == 1) {
            start_char = c;
        }
    }

    std::string layout = "";
    std::set<char> visited;

    if (s.length() == 1) {
        start_char = s[0];
    } else if (start_char == '\0') { // All characters in s have degree 2, implies a cycle or a single path that uses all chars
        // If all chars in s have degree 2, it means they form a cycle or a path where endpoints are not in s.
        // Since we need to form a linear layout, we must pick one character from s to be an endpoint.
        // Any character from s can be chosen as a starting point.
        // Let's pick the first character of s.
        start_char = s[0];
    }

    if (start_char != '\0') {
        char current = start_char;
        while (current != '\0') {
            layout += current;
            visited.insert(current);
            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (visited.find(neighbor) == visited.end()) {
                    next_char = neighbor;
                    break;
                }
            }
            current = next_char;
        }
    }

    // Check if all characters from s are included in the layout and form a valid path
    for (char c : s) {
        if (visited.find(c) == visited.end()) {
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining unvisited characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

