int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_true = 0; k_true < n; ++k_true) {
        char first_char_t = s[k_true];
        int first_char_idx = first_char_t - 'a';

        // Find all possible k' values that would result in the same t[0]
        const std::vector<int>& possible_k_values = char_indices[first_char_idx];

        if (possible_k_values.size() == 1) {
            // If only one k' results in this t[0], Vasya wins immediately.
            // This k_true is uniquely determined.
            total_win_prob += 1.0;
            continue;
        }

        // If multiple k' values are possible, Vasya needs to choose p.
        // Vasya wants to maximize his win probability for this specific k_true.
        // This means choosing p such that the number of k' values that are
        // consistent with t[0] and t[p] is minimized, ideally 1.

        int max_unique_count = 0; // Max number of k' values that become unique for some p

        // Iterate over all possible positions p (1 to N-1)
        for (int p = 1; p < n; ++p) {
            char second_char_t = s[(k_true + p) % n];

            // Count how many k' values from possible_k_values
            // would also produce this second_char_t at position p.
            int current_unique_count = 0;
            for (int k_prime : possible_k_values) {
                if (s[(k_prime + p) % n] == second_char_t) {
                    current_unique_count++;
                }
            }
            // Vasya wins if current_unique_count is 1.
            // We want to find a p that maximizes the number of k_true for which this happens.
            // Or, more simply, for a given k_true, we want to find a p that makes k_true unique.
            // If current_unique_count is 1, then this k_true is uniquely determined by (t[0], t[p]).
            // We are counting how many k_true values can be uniquely determined.
            // The problem asks for the probability of winning if Vasya plays optimally.
            // For a given k_true, Vasya chooses p to maximize his chance of winning.
            // If there exists a p such that current_unique_count is 1, Vasya wins for this k_true.
            // So, we just need to check if such a p exists.
            if (current_unique_count == 1) {
                max_unique_count = 1; // Found a p that makes k_true unique
                break; // No need to check other p's for this k_true
            }
        }
        total_win_prob += max_unique_count;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
