int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val0 = 0;    // What 0 becomes after all operations
    int current_val1 = 1023; // What 1023 (all 10 bits set) becomes after all operations

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val0 &= x;
            current_val1 &= x;
        } else if (op_char == '|') {
            current_val0 |= x;
            current_val1 |= x;
        } else if (op_char == '^') {
            current_val0 ^= x;
            current_val1 ^= x;
        }
    }

    // Now we have current_val0 and current_val1.
    // For each bit position j (0 to 9):
    // If input bit is 0, output bit is (current_val0 >> j) & 1
    // If input bit is 1, output bit is (current_val1 >> j) & 1

    // We want to find A, B, C such that for any input x:
    // (((x & A) | B) ^ C) == final_result_for_x
    //
    // Let's determine A, B, C bit by bit.
    // For each bit j:
    // Let v0_j = (current_val0 >> j) & 1
    // Let v1_j = (current_val1 >> j) & 1
    //
    // If input bit x_j is 0, output bit must be v0_j.
    // If input bit x_j is 1, output bit must be v1_j.

    int A = 1023; // Initialize A to all 1s (no AND restriction)
    int B = 0;    // Initialize B to all 0s (no OR addition)
    int C = 0;    // Initialize C to all 0s (no XOR flip)

    for (int j = 0; j < 10; ++j) {
        int v0_j = (current_val0 >> j) & 1;
        int v1_j = (current_val1 >> j) & 1;

        if (v0_j == 0 && v1_j == 0) {
            // Input 0 -> 0, Input 1 -> 0
            // This means the bit must always be 0.
            // To achieve this:
            // (x_j & A_j) | B_j must be 0.
            // If x_j is 0: (0 & A_j) | B_j = B_j. So B_j must be 0.
            // If x_j is 1: (1 & A_j) | B_j = A_j | B_j. So A_j | B_j must be 0.
            // This implies A_j = 0 and B_j = 0.
            // C_j must be 0 to not flip the 0.
            A &= ~(1 << j); // Set A_j to 0
            B &= ~(1 << j); // Set B_j to 0
            C &= ~(1 << j); // Set C_j to 0
        } else if (v0_j == 0 && v1_j == 1) {
            // Input 0 -> 0, Input 1 -> 1
            // This means the bit should be the same as the input bit.
            // To achieve this:
            // (x_j & A_j) | B_j must be x_j.
            // If x_j is 0: (0 & A_j) | B_j = B_j. So B_j must be 0.
            // If x_j is 1: (1 & A_j) | B_j = A_j | B_j. So A_j | B_j must be 1.
            // With B_j = 0, this means A_j must be 1.
            // C_j must be 0 to not flip the bit.
            A |= (1 << j);  // Set A_j to 1
            B &= ~(1 << j); // Set B_j to 0
            C &= ~(1 << j); // Set C_j to 0
        } else if (v0_j == 1 && v1_j == 0) {
            // Input 0 -> 1, Input 1 -> 0
            // This means the bit should be the inverse of the input bit.
            // To achieve this:
            // (x_j & A_j) | B_j must be !x_j.
            // If x_j is 0: (0 & A_j) | B_j = B_j. So B_j must be 1.
            // If x_j is 1: (1 & A_j) | B_j = A_j | B_j. So A_j | B_j must be 0.
            // This is a contradiction if B_j is 1.
            //
            // Alternative: (x_j & A_j) | B_j should be 0, and then C_j flips it to 1.
            // Or (x_j & A_j) | B_j should be 1, and then C_j flips it to 0.
            //
            // Let's try to make (x_j & A_j) | B_j = x_j, and then C_j flips it.
            // So A_j = 1, B_j = 0. Then C_j must be 1.
            A |= (1 << j);  // Set A_j to 1
            B &= ~(1 << j); // Set B_j to 0
            C |= (1 << j);  // Set C_j to 1
        } else { // v0_j == 1 && v1_j == 1
            // Input 0 -> 1, Input 1 -> 1
            // This means the bit must always be 1.
            // To achieve this:
            // (x_j & A_j) | B_j must be 1.
            // If x_j is 0: (0 & A_j) | B_j = B_j. So B_j must be 1.
            // If x_j is 1: (1 & A_j) | B_j = A_j | B_j. So A_j | B_j must be 1.
            // This is satisfied if B_j = 1. A_j can be anything (0 or 1).
            // We can keep A_j = 1 (default).
            // C_j must be 0 to not flip the 1.
            A |= (1 << j);  // Set A_j to 1 (default, or can be 0)
            B |= (1 << j);  // Set B_j to 1
            C &= ~(1 << j); // Set C_j to 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', A});
    }
    if (B != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', B});
    }
    if (C != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', C});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // balance[i] = (count of 1s) - (count of 2s) for jars 1 to i
    // We are interested in jars 1 to n-L.
    // The balance for jars 1 to k is prefix_balance_left[k].
    // The balance for jars 1 to 0 is 0.
    std::vector<int> prefix_balance_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_balance_left[i + 1] = prefix_balance_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // balance[i] = (count of 1s) - (count of 2s) for jars i to 2n
    // We are interested in jars n+R+1 to 2n.
    // The balance for jars k to 2n is suffix_balance_right[k].
    // The balance for jars 2n+1 to 2n is 0.
    std::vector<int> suffix_balance_right(2 * n + 1, 0);
    for (int i = 2 * n - 1; i >= n; --i) {
        suffix_balance_right[i + 1] = suffix_balance_right[i + 2] + (a[i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the right side (R)
    // for each possible balance value from the right side.
    // map: balance_value -> min_R
    std::map<int, int> right_balance_to_min_R;
    for (int R = 0; R <= n; ++R) {
        // The jars remaining on the right are from index n+R to 2n-1 (0-indexed)
        // which corresponds to jars n+R+1 to 2n (1-indexed).
        // The balance for these jars is suffix_balance_right[n+R+1].
        int current_right_balance = suffix_balance_right[n + R + 1];
        if (right_balance_to_min_R.find(current_right_balance) == right_balance_to_min_R.end()) {
            right_balance_to_min_R[current_right_balance] = R;
        } else {
            right_balance_to_min_R[current_right_balance] = std::min(right_balance_to_min_R[current_right_balance], R);
        }
    }

    int min_total_removed = 2 * n; // Initialize with maximum possible removals

    // Iterate through all possible numbers of jars removed from the left side (L)
    for (int L = 0; L <= n; ++L) {
        // The jars remaining on the left are from index 0 to n-L-1 (0-indexed)
        // which corresponds to jars 1 to n-L (1-indexed).
        // The balance for these jars is prefix_balance_left[n-L].
        int current_left_balance = prefix_balance_left[n - L];

        // We need the total balance to be 0.
        // So, current_left_balance + current_right_balance = 0
        // This means current_right_balance must be -current_left_balance.
        int target_right_balance = -current_left_balance;

        if (right_balance_to_min_R.count(target_right_balance)) {
            int R = right_balance_to_min_R[target_right_balance];
            min_total_removed = std::min(min_total_removed, L + R);
        }
    }

    std::cout << min_total_removed << std::endl;
}

