    // If length is L, max value is 2^L - 1.
    // If L = 20, 2^20 - 1 = 1048575.
    // If L = 19, 2^19 - 1 = 524287.
    // If L = 18, 2^18 - 1 = 262143.
    // If L = 17, 2^17 - 1 = 131071.
