    // The maximum length of a substring we need to consider for its value to be equal to its length
    // is relatively small. For example, if length is 20, the value can be at most 2^20-1.
    // If the first character is '1', then value >= 2^(len-1).
    // We need len >= 2^(len-1). This only holds for len=1 (1 >= 2^0=1).
    // If the first character is '0', then value < 2^(len-1).
    // The maximum length of a substring whose value can be equal to its length is around 20.
    // For example, if len = 20, max value is 2^20-1.
    // If len = 20, and the first char is '1', then value >= 2^19. 2^19 is much larger than 20.
    // So, if s[l] == '1', we only need to check small lengths.
    // If s[l] == '0', the value grows slower.
    // The maximum length of a substring we need to check for its value to be equal to its length
    // is bounded. For example, if length is 20, the maximum value is 2^20-1.
    // If the length is L, and the value is V, we need L=V.
    // If L >= 20, then 2^L-1 is much larger than L.
    // The maximum length of a substring we need to consider is about 20.
    // Let's pick a safe upper bound, say 25.
    const int MAX_CHECK_LEN = 25; 

    for (int l = 0; l < n; ++l) {
        long long current_val = 0;
        for (int r = l; r < n; ++r) {
            int len = r - l + 1;

            // Optimization: If current_val exceeds MAX_CHECK_LEN,
            // and s[l] is '1', then current_val will grow exponentially.
            // It will quickly exceed len.
            // If s[l] is '0', current_val grows slower, but still exponentially.
            // The maximum possible value for a length `len` is `2^len - 1`.
            // If `len` is large, `2^len - 1` is much larger than `len`.
            // For example, if `len = 20`, `2^20 - 1 = 1048575`.
            // If `len = 25`, `2^25 - 1 = 33554431`.
            // So, if `len` is already greater than `MAX_CHECK_LEN`,
            // it's highly unlikely that `current_val` will be equal to `len`.
            // We can break early if `len` is too large.
            // Also, if `current_val` itself becomes too large, we can break.
            // `current_val` can exceed `len` very quickly.
            // If `current_val` is already greater than `len`, and `s[r]` is '1',
            // then `current_val` will only increase further, making it even less likely to be equal to `len`.
            // If `s[r]` is '0', `current_val` doubles, still making it larger.
            // So, if `current_val > len` and `s[l]` is '1', we can break.
            // If `s[l]` is '0', `current_val` can be small even for large `len`.
            // Example: 000000000000000000001 (len=21, val=1).
            // The condition `len > MAX_CHECK_LEN` is a good heuristic.

            if (len > MAX_CHECK_LEN && s[l] == '1') {
                // If the first character is '1', the value grows very fast.
                // If len > MAX_CHECK_LEN, current_val will be much larger than len.
                break;
            }

            current_val = current_val * 2 + (s[r] - '0');

            if (current_val > n + MAX_CHECK_LEN) { // current_val can't be equal to len if it's too big
                break;
            }

            if (current_val == len) {
                good_substring_count++;
            }
        }
    }

    // Handle substrings starting with '0' more carefully for larger lengths.
    // For a substring s[l...r] starting with '0', its value is f(s[l...r]).
    // We need r - l + 1 = f(s[l...r]).
    // Let k be the number of leading zeros. s[l...l+k-1] are '0', s[l+k] is '1'.
    // Then f(s[l...r]) = f(s[l+k...r]).
    // The length is r - l + 1.
    // We need r - l + 1 = f(s[l+k...r]).
    // Let actual_len = r - (l+k) + 1 be the length of the non-zero part.
    // Let actual_val = f(s[l+k...r]).
    // We need (k + actual_len) = actual_val.
    // Since actual_val >= 2^(actual_len-1), we need k + actual_len >= 2^(actual_len-1).
    // This inequality holds for small actual_len.
    // For actual_len = 1, k+1 >= 2^0 = 1. (k >= 0)
    // For actual_len = 2, k+2 >= 2^1 = 2. (k >= 0)
    // For actual_len = 3, k+3 >= 2^2 = 4. (k >= 1)
    // For actual_len = 4, k+4 >= 2^3 = 8. (k >= 4)
    // For actual_len = 5, k+5 >= 2^4 = 16. (k >= 11)
    // For actual_len = 6, k+6 >= 2^5 = 32. (k >= 26)
    // For actual_len = 7, k+7 >= 2^6 = 64. (k >= 57)
    // For actual_len = 8, k+8 >= 2^7 = 128. (k >= 120)
    // For actual_len = 9, k+9 >= 2^8 = 256. (k >= 247)
    // For actual_len = 10, k+10 >= 2^9 = 512. (k >= 502)
    // For actual_len = 11, k+11 >= 2^10 = 1024. (k >= 1013)
    // For actual_len = 12, k+12 >= 2^11 = 2048. (k >= 2036)
    // For actual_len = 13, k+13 >= 2^12 = 4096. (k >= 4083)
    // For actual_len = 14, k+14 >= 2^13 = 8192. (k >= 8178)
    // For actual_len = 15, k+15 >= 2^14 = 16384. (k >= 16369)
    // For actual_len = 16, k+16 >= 2^15 = 32768. (k >= 32752)
    // For actual_len = 17, k+17 >= 2^16 = 65536. (k >= 65519)
    // For actual_len = 18, k+18 >= 2^17 = 131072. (k >= 131054)
    // For actual_len = 19, k+19 >= 2^18 = 262144. (k >= 262125)
    // For actual_len = 20, k+20 >= 2^19 = 524288. (k >= 524268)
    // The maximum possible value for k is n-1.
    // If actual_len is around 20, k needs to be very large, which is impossible for n <= 2e5.
    // So, actual_len can't be too large.
    // The maximum actual_len we need to check is around 19.
    // If actual_len = 19, k >= 262125. But k <= n-1 <= 2e5-1. So actual_len cannot be 19.
    // If actual_len = 18, k >= 131054. k <= n-1 <= 2e5-1. This is possible.
    // If actual_len = 17, k >= 65519. This is possible.
    // If actual_len = 16, k >= 32752. This is possible.
    // If actual_len = 15, k >= 16369. This is possible.
    // If actual_len = 14, k >= 8178. This is possible.
    // If actual_len = 13, k >= 4083. This is possible.
