    // If actual_len = 8, k >= 120. This is possible.
    // If actual_len = 7, k >= 57. This is possible.
    // If actual_len = 6, k >= 26. This is possible.
    // If actual_len = 5, k >= 11. This is possible.
    // If actual_len = 4, k >= 4. This is possible.
    // If actual_len = 3, k >= 1. This is possible.
    // If actual_len = 2, k >= 0. This is possible.
    // If actual_len = 1, k >= 0. This is possible.

    // The previous loop already covers all substrings starting with '1'.
    // It also covers substrings starting with '0' up to length MAX_CHECK_LEN.
    // We need to handle substrings starting with '0' and having length > MAX_CHECK_LEN.
    // For these, s[l] must be '0'.
    // Let's iterate through all possible starting positions `l`.
    // If s[l] is '1', it's already handled.
    // If s[l] is '0', we need to find the first '1' at index `first_one_idx`.
    // The substring is s[l ... r].
    // The number of leading zeros is `k = first_one_idx - l`.
    // The value of the substring is `val = f(s[first_one_idx ... r])`.
    // The length of the substring is `len = r - l + 1`.
    // We need `len = val`.
    // So, `(first_one_idx - l) + (r - first_one_idx + 1) = f(s[first_one_idx ... r])`.
    // `k + actual_len = actual_val`.
    // We can precompute the index of the next '1' for each position.
    std::vector<int> next_one(n + 1);
    next_one[n] = n; // Sentinel value
    for (int i = n - 1; i >= 0; --i) {
        if (s[i] == '1') {
            next_one[i] = i;
        } else {
            next_one[i] = next_one[i+1];
        }
    }

    // Iterate through all possible starting positions `l`.
    // If s[l] is '1', it's handled by the first loop.
    // If s[l] is '0':
    for (int l = 0; l < n; ++l) {
        if (s[l] == '1') continue; // Already handled by the first loop

        int first_one_idx = next_one[l];
        if (first_one_idx == n) { // All zeros from l to n-1
            // Substring s[l...r] consists only of '0's.
            // f(s[l...r]) = 0.
            // Length = r - l + 1.
            // We need r - l + 1 = 0, which is impossible for non-empty string.
            continue;
        }

        // Now we have s[l...first_one_idx-1] are '0's, and s[first_one_idx] is '1'.
        // We are looking for substrings s[l...r] where r >= first_one_idx.
        // The number of leading zeros is k = first_one_idx - l.
        // The value is f(s[first_one_idx ... r]).
        // The length is r - l + 1.
        // We need r - l + 1 = f(s[first_one_idx ... r]).
        // Let actual_len = r - first_one_idx + 1.
        // Let actual_val = f(s[first_one_idx ... r]).
        // We need k + actual_len = actual_val.

        long long actual_val = 0;
        for (int r = first_one_idx; r < n; ++r) {
            int actual_len = r - first_one_idx + 1;
            int k = first_one_idx - l; // Number of leading zeros

            // If actual_len is too large, actual_val will be much larger than k + actual_len.
            // From our analysis, actual_len can be at most around 18-19.
            // If actual_len > MAX_CHECK_LEN, we can break.
            // The first loop already covers up to MAX_CHECK_LEN.
            // So we only need to check for actual_len > MAX_CHECK_LEN - k.
            // A simpler bound: if actual_len > 20, actual_val will be too large.
            if (actual_len > 20) { // 2^19 is already > 2e5.
                break;
            }

            actual_val = actual_val * 2 + (s[r] - '0');

            // Check if actual_val is too large to be equal to k + actual_len.
            // k + actual_len <= (n-1) + (n-1) + 1 = 2n-1.
            // If actual_val > 2n, it's too large.
            if (actual_val > 2 * n + 100) { // A safe upper bound
                break;
            }

            if (k + actual_len == actual_val) {
                good_substring_count++;
            }
        }
    }

    std::cout << good_substring_count << std::endl;
}

