    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_run(n);
    std::vector<int> right_zero_run(n);

    // Calculate left_zero_run: length of consecutive zeros to the left, including current
    left_zero_run[0] = (a[0] == 0 ? 1 : 0);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
        } else {
            left_zero_run[i] = 0;
        }
    }

    // Calculate right_zero_run: length of consecutive zeros to the right, including current
    right_zero_run[n - 1] = (a[n - 1] == 0 ? 1 : 0);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
        } else {
            right_zero_run[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            // Find the nearest 0 to the left and right
            int l = i - left_zero_run[i]; // Index of the 0 that starts the run of 0s ending at i-1, or -1 if no 0s
            int r = i + right_zero_run[i]; // Index of the 0 that starts the run of 0s starting at i+1, or n if no 0s

            // If a[i] is 1, it can only change if it's part of a 010 pattern.
            // This means it must be surrounded by 0s.
            // The distance to the nearest 1 on the left is `i - (l+1)`.
            // The distance to the nearest 1 on the right is `(r-1) - i`.
            // If l < 0, it means all elements to the left are 1s (or it's the first element).
            // If r >= n, it means all elements to the right are 1s (or it's the last element).

            // The actual distance to the nearest 1 on the left is `i - (l_idx + 1)` where `l_idx` is the index of the 1.
            // The actual distance to the nearest 1 on the right is `(r_idx - 1) - i` where `r_idx` is the index of the 1.

            // For a[i] to change from 1 to 0, it must be 1 and surrounded by 0s.
            // The number of steps for a 1 at index `i` to become 0 is `min(i - l_idx, r_idx - i)`.
            // Here, `l_idx` is the index of the nearest 1 to the left of `i`, and `r_idx` is the nearest 1 to the right.
            // If `a[i]` is 1, and `a[i-1]` is 0, and `a[i+1]` is 0, then `a[i]` becomes 0 in the next step.
            // This is equivalent to `a[i-1] == 0` and `a[i+1] == 0`.
            // The `left_zero_run[i-1]` gives the length of zeros ending at `i-1`.
            // The `right_zero_run[i+1]` gives the length of zeros starting at `i+1`.

            // The number of steps for a 1 at index `i` to become 0 is `min(dist_to_left_1, dist_to_right_1)`.
            // `dist_to_left_1` is `i - (index of nearest 1 to its left)`.
            // `dist_to_right_1` is `(index of nearest 1 to its right) - i`.
            // If `a[i]` is 1, and `a[i-1]` is 0, and `a[i+1]` is 0, then `a[i]` becomes 0.
            // This means `left_zero_run[i-1] >= 1` and `right_zero_run[i+1] >= 1`.
            // The number of steps for `a[i]` to become 0 is `min(left_zero_run[i-1], right_zero_run[i+1])`.
            // This is only if `i-1 >= 0` and `i+1 < n`.
            // If `i=0` or `i=n-1`, it never changes.
            // If `a[i]` is 1, and `a[i-1]` is 0, and `a[i+1]` is 0, then `a[i]` becomes 0.
            // The number of steps for `a[i]` to become 0 is `min(left_zero_run[i-1], right_zero_run[i+1])`.
            // This is only if `i-1 >= 0` and `i+1 < n`.
            // If `i=0` or `i=n-1`, it never changes.

            // The actual logic for a 1 at index `i` to become 0:
            // It needs to be surrounded by 0s.
            // The number of steps for `a[i]` to become 0 is `min(k_left, k_right)` where
            // `k_left` is the number of steps for the 1 to be "eaten" from the left.
            // `k_right` is the number of steps for the 1 to be "eaten" from the right.
            // `k_left` is `i - (index of nearest 1 to its left)`.
            // `k_right` is `(index of nearest 1 to its right) - i`.
            // If there's no 1 to the left, `k_left` is effectively infinity.
            // If there's no 1 to the right, `k_right` is effectively infinity.

            // Let's find the actual nearest 1s.
            int left_one_idx = -1;
            for (int j = i - 1; j >= 0; --j) {
                if (a[j] == 1) {
                    left_one_idx = j;
                    break;
                }
            }

            int right_one_idx = n;
            for (int j = i + 1; j < n; ++j) {
                if (a[j] == 1) {
                    right_one_idx = j;
                    break;
                }
            }

            int k_val = 0;
            if (left_one_idx == -1 && right_one_idx == n) {
                // All 1s, or a single 1. This 1 will never change.
                // This case is only possible if n=1 and a[0]=1, or n=2 and a=[1,1].
                // But we handle n<=2 separately.
                // For n > 2, if all are 1s, it's stable. If a single 1, it's stable.
                // This means a[i] is 1, and all other elements are 0.
                // E.g., 00100. This is stable.
                // So k_val = 0.
            } else if (left_one_idx == -1) { // No 1 to the left, only 0s.
                // Sequence starts with 0s, then 1s, then 0s, then 1s...
                // Example: 0011100. For the first 1, left_one_idx = -1.
                // The 1 at `i` is `a[i]`.
                // The number of steps for `a[i]` to become 0 is `right_one_idx - i`.
                k_val = right_one_idx - i;
            } else if (right_one_idx == n) { // No 1 to the right, only 0s.
                // Example: 0011100. For the last 1, right_one_idx = n.
                // The number of steps for `a[i]` to become 0 is `i - left_one_idx`.
                k_val = i - left_one_idx;
            } else { // 1s on both sides.
                // Example: 01010. For the middle 1, left_one_idx=1, right_one_idx=3.
                // k_val = min(i - left_one_idx, right_one_idx - i).
                k_val = std::min(i - left_one_idx, right_one_idx - i);
            }
            max_k = std::max(max_k, k_val);
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            // A 0 at index `i` becomes 1 if it's part of a 101 pattern.
            // This means `a[i-1] == 1` and `a[i+1] == 1`.
            // The number of steps for `a[i]` to become 1 is `min(i - left_one_idx, right_one_idx - i)`.
            // Here, `left_one_idx` is the index of the nearest 1 to the left of `i`.
            // `right_one_idx` is the index of the nearest 1 to the right of `i`.
            // If `a[i]` is 0, and `a[i-1]` is 1, and `a[i+1]` is 1, then `a[i]` becomes 1 in the next step.
            // This is equivalent to `left_zero_run[i-1] == 0` and `right_zero_run[i+1] == 0`.
            // The number of steps for `a[i]` to become 1 is `min(dist_to_left_1, dist_to_right_1)`.
            // `dist_to_left_1` is `i - (index of nearest 1 to its left)`.
            // `dist_to_right_1` is `(index of nearest 1 to its right) - i`.

            int left_one_idx = -1;
            for (int j = i - 1; j >= 0; --j) {
                if (a[j] == 1) {
                    left_one_idx = j;
                    break;
                }
            }

            int right_one_idx = n;
            for (int j = i + 1; j < n; ++j) {
                if (a[j] == 1) {
                    right_one_idx = j;
                    break;
                }
            }

            if (left_one_idx != -1 && right_one_idx != n) {
                int k_val = std::min(i - left_one_idx, right_one_idx - i);
                if (k_val <= max_k) {
                    b[i] = 1;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] stores the maximum possible initial value for a[i]

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            // Subtract all previous type 1 operations that affect this range
            for (int j = 0; j < i; ++j) {
                if (ops[j].type == 1) {
                    if (std::max(ops[i].l, ops[j].l) <= std::min(ops[i].r, ops[j].r)) {
                        current_max_val -= ops[j].val;
                    }
                }
            }
            // Update b[k] for k in [ops[i].l, ops[i].r]
            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                b[k] = std::min(b[k], current_max_val);
            }
        }
    }

    // If b[i] is still LLONG_MAX, it means no type 2 operation constrained it.
    // We can set it to 0, as 0 satisfies |a_i| <= 10^9.
    for (int i = 0; i < n; ++i) {
        if (b[i] == LLONG_MAX) {
            b[i] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> a_current = b; // Start with the constructed initial array

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                a_current[k] += ops[i].val;
            }
        } else { // type 2
            long long max_in_range = LLONG_MIN;
            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                max_in_range = std::max(max_in_range, a_current[k]);
            }
            if (max_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The target value for a[0] must be at least 0.
                            // For a[i], its target value must be at least prev_val.

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a[i] is already >= prev_val.
        // We need to ensure (a[i] + c_i) % m >= prev_val.
        // The minimum c_i is 0. So if a[i] >= prev_val, we can potentially use c_i = 0.
        // The maximum c_i is x. So (a[i] + x) % m is the largest possible value.

        // If a[i] >= prev_val, we can potentially keep a[i] as is (c_i=0).
        // The condition is (a[i] + c_i) % m >= prev_val.
        // If a[i] >= prev_val, then c_i=0 works.
        // If a[i] < prev_val, then we must increment a[i] enough times to make it >= prev_val.
        // This means (a[i] + c_i) % m must be >= prev_val.
        // The smallest c_i that satisfies this is (prev_val - a[i] + m) % m.
        // Let's call this required_c.

        // If a[i] >= prev_val:
        // We can choose c_i = 0. The value becomes a[i]. This is >= prev_val.
        // We can choose c_i = (m - a[i] + prev_val) % m. This value is prev_val.
        // This c_i is valid if (m - a[i] + prev_val) % m <= x.
        // If a[i] >= prev_val, then (m - a[i] + prev_val) % m is the number of increments
        // needed to wrap around and reach prev_val.
        // For example, if m=10, a[i]=8, prev_val=2. Then (10-8+2)%10 = 4.
        // 8 -> 9 -> 0 -> 1 -> 2. This takes 4 increments.
        // If a[i] >= prev_val, we can choose c_i = 0.
        // The value becomes a[i]. This is >= prev_val.
        // So, if a[i] >= prev_val, we can always satisfy the condition with c_i=0,
        // as long as a[i] is not too large such that it would be better to wrap around.
        // The next prev_val will be a[i].

        // If a[i] < prev_val:
        // We must increment a[i] such that (a[i] + c_i) % m >= prev_val.
        // The minimum c_i required is (prev_val - a[i]).
        // If this required_c > x, then it's impossible.
        // If this required_c <= x, then we can achieve prev_val.
        // The next prev_val will be prev_val.

        // Let's simplify:
        // We need to find c_i such that 0 <= c_i <= x and (a[i] + c_i) % m >= prev_val.
        // If such c_i exists, we set prev_val to (a[i] + c_i) % m.
        // To minimize the next prev_val, we should choose the smallest possible (a[i] + c_i) % m.
        // This smallest possible value is prev_val itself.
        // So, if we can make (a[i] + c_i) % m = prev_val, we do that.
        // Otherwise, we must make (a[i] + c_i) % m = a[i] (if a[i] >= prev_val).

        // Option 1: Don't wrap around. Target value is a[i] + c_i.
        // We need a[i] + c_i >= prev_val.
        // Smallest c_i is max(0LL, prev_val - a[i]).
        // If this c_i <= x, then we can achieve a value of max(a[i], prev_val).
        // The value would be a[i] + max(0LL, prev_val - a[i]).
        // This is max(a[i], prev_val).
        // Let's call this `val_no_wrap`.

        // Option 2: Wrap around. Target value is (a[i] + c_i) % m.
        // We need (a[i] + c_i) % m >= prev_val.
        // This means a[i] + c_i must be in the range [k*m + prev_val, k*m + m-1] for some k.
        // The smallest c_i to achieve a value >= prev_val after wrapping is:
        // If a[i] >= prev_val, we can use c_i = 0. Value is a[i].
        // If a[i] < prev_val, we need to increment by at least (prev_val - a[i]).
        // This is the `required_c` from before.
        // If a[i] >= prev_val, we can use c_i = 0. The value is a[i].
        // If a[i] < prev_val, we need to increment by at least `prev_val - a[i]`.
        // If `prev_val - a[i]` is <= x, then we can achieve `prev_val`.
        // So, if `a[i] < prev_val` and `prev_val - a[i] > x`, it's impossible.
        // In this case, we must increment `a[i]` by at most `x`.
        // The maximum value we can reach is `(a[i] + x) % m`.
        // If `(a[i] + x) % m < prev_val`, it's impossible.

        // Let's re-evaluate.
        // We need to find c_i such that 0 <= c_i <= x and (a[i] + c_i) % m >= prev_val.
        // If multiple such c_i exist, we want to choose one that minimizes (a[i] + c_i) % m.
        // The smallest possible value for (a[i] + c_i) % m is `prev_val`.
        // Can we achieve `prev_val`?
        // If `a[i] <= prev_val`:
        //   We need `c_i = prev_val - a[i]`. If `prev_val - a[i] <= x`, then we can achieve `prev_val`.
        //   If `prev_val - a[i] > x`, we cannot reach `prev_val` without wrapping.
        //   In this case, the smallest value we can achieve is `(a[i] + c_i) % m` where `c_i` is minimal.
        //   The minimal `c_i` is `0`. The value is `a[i]`. But `a[i] < prev_val`, so this doesn't work.
        //   The maximal `c_i` is `x`. The value is `(a[i] + x) % m`.
        //   If `(a[i] + x) % m < prev_val`, then it's impossible.
        //   Otherwise, we can achieve `(a[i] + x) % m`.
        //   So, if `a[i] <= prev_val`:
        //     If `prev_val - a[i] <= x`: we can set `prev_val` for the next iteration to `prev_val`.
        //     Else (`prev_val - a[i] > x`): we cannot reach `prev_val` directly.
        //       We must increment `a[i]` by at most `x`. The largest value we can get is `(a[i] + x) % m`.
        //       If `(a[i] + x) % m < prev_val`, then it's impossible to satisfy the condition. Return false.
        //       Otherwise, we can achieve `(a[i] + x) % m`. This is the smallest possible value >= prev_val.
        //       So, set `prev_val` for the next iteration to `(a[i] + x) % m`.
        // If `a[i] > prev_val`:
        //   We can choose `c_i = 0`. The value is `a[i]`. This is `>= prev_val`.
        //   Or we can choose `c_i` such that `(a[i] + c_i) % m = prev_val`.
        //   This `c_i` would be `(m - a[i] + prev_val) % m`.
        //   If this `c_i <= x`, then we can achieve `prev_val`.
        //   We want to minimize the next `prev_val`. So we prefer `prev_val` over `a[i]`.
        //   So, if `(m - a[i] + prev_val) % m <= x`: set `prev_val` for next iteration to `prev_val`.
        //   Else (`(m - a[i] + prev_val) % m > x`): we cannot wrap around to `prev_val`.
        //     We must use `c_i = 0`. The value is `a[i]`. This is `>= prev_val`.
        //     Set `prev_val` for next iteration to `a[i]`.

        // Combining these:
        // If a[i] >= prev_val:
        //   Check if we can wrap around to prev_val.
        //   Cost to wrap to prev_val is `c_wrap = (m - a[i] + prev_val) % m`.
        //   If `c_wrap <= x`, we can achieve `prev_val`. So we set `prev_val` for next iteration to `prev_val`.
        //   Else, we cannot wrap to `prev_val`. We must use `c_i = 0`. The value is `a[i]`.
        //   So, set `prev_val` for next iteration to `a[i]`.
        // Else (a[i] < prev_val):
        //   Check if we can reach prev_val without wrapping.
        //   Cost to reach prev_val is `c_direct = prev_val - a[i]`.
        //   If `c_direct <= x`, we can achieve `prev_val`. So we set `prev_val` for next iteration to `prev_val`.
        //   Else, we cannot reach `prev_val` directly.
        //   We must increment `a[i]` by at most `x`. The largest value we can get is `(a[i] + x) % m`.
        //   If `(a[i] + x) % m < prev_val`, then it's impossible. Return false.
        //   Otherwise, we can achieve `(a[i] + x) % m`. This is the smallest possible value >= prev_val.
        //   So, set `prev_val` for next iteration to `(a[i] + x) % m`.

        if (current_a >= prev_val) {
            // Option 1: Don't increment, value is current_a. This is >= prev_val.
            // Option 2: Increment to wrap around to prev_val.
            // Cost for Option 2: (m - current_a + prev_val) % m.
            // If this cost is <= x, we can achieve prev_val.
            // We prefer prev_val because it's smaller or equal to current_a,
            // which makes it easier for the next element.
            if ((m - current_a + prev_val) % m <= x) {
                // We can achieve prev_val. Keep prev_val.
            } else {
                // Cannot achieve prev_val by wrapping. Must use current_a.
                prev_val = current_a;
            }
        } else { // current_a < prev_val
            // We must increment current_a.
            // Option 1: Increment current_a to prev_val.
            // Cost for Option 1: prev_val - current_a.
            // If this cost is <= x, we can achieve prev_val. Keep prev_val.
            if (prev_val - current_a <= x) {
                // We can achieve prev_val. Keep prev_val.
            } else {
                // Cannot achieve prev_val.
                // The maximum value we can reach is (current_a + x) % m.
                // If this maximum value is still less than prev_val, it's impossible.
                if ((current_a + x) % m < prev_val) {
                    return false;
                }
                // Otherwise, we can achieve (current_a + x) % m.
                // This is the smallest value >= prev_val we can achieve.
                prev_val = (current_a + x) % m;
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_index;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_index);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_chain = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated d_cry from chain reactions
            children[j].p -= total_d_cry_from_chain;

            // Check for chain reaction
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_chain += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

