int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;
    long long second_min_a = elements[1].value;
    long long second_max_a = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // min_f = min_a + second_min_a
    // max_f = max_a + second_max_a
    // Goodness = (max_a + second_max_a) - (min_a + second_min_a)
    long long goodness1 = (max_a + second_max_a) - (min_a + second_min_a);
    std::vector<int> partition1(n, 1);

    // Case 2: At least one element in each subsequence.
    // The minimum possible f value is min_a + second_min_a.
    // The maximum possible f value is max_a + second_max_a + h.
    // This occurs if min_a and second_min_a are in the same subsequence,
    // and max_a and second_max_a are in different subsequences.
    // Or if min_a and second_min_a are in different subsequences,
    // and max_a and second_max_a are in the same subsequence.
    //
    // The crucial observation is that if we have elements in both subsequences,
    // then min_f will be at least min_a + second_min_a (if they are together)
    // or min_a + second_min_a + h (if they are separated).
    // And max_f will be at most max_a + second_max_a + h (if they are separated)
    // or max_a + second_max_a (if they are together).
    //
    // Consider the partition where min_a is in subseq 1, and all other elements are in subseq 2.
    // min_f:
    //   - If n=2: min_a and max_a are separated. f(min_a, max_a) = min_a + max_a + h. This is the only f value.
    //   - If n>2:
    //     - Pairs within subseq 2: min_a_in_subseq2 + second_min_a_in_subseq2 = second_min_a + elements[2].value
    //     - Pairs across subseqs: min_a + second_min_a + h
    //     So, min_f = std::min(second_min_a + elements[2].value, min_a + second_min_a + h) if n > 2.
    //     If n=2, min_f = min_a + max_a + h.
    //
    // max_f:
    //   - Pairs within subseq 2: max_a + second_max_a
    //   - Pairs across subseqs: min_a + max_a + h
    //   So, max_f = std::max(max_a + second_max_a, min_a + max_a + h).
    //
    // This specific partition (min_a in subseq 1, rest in subseq 2) is often optimal for Case 2.
    // Let's calculate its goodness.
    //
    // min_f_val:
    //   - If n=2: min_a + max_a + h
    //   - If n>2: min( (second_min_a + elements[2].value), (min_a + second_min_a + h) )
    // max_f_val:
    //   - max( (max_a + second_max_a), (min_a + max_a + h) )

    long long min_f_val_case2;
    if (n == 2) {
        min_f_val_case2 = min_a + max_a + h;
    } else {
        min_f_val_case2 = std::min(second_min_a + elements[2].value, min_a + second_min_a + h);
    }
    long long max_f_val_case2 = std::max(max_a + second_max_a, min_a + max_a + h);
    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=0: No cuts. The string remains s.
    // We need s' != s, so k=0 is never an answer.

    // Case k=1: One cut. Two pieces.
    // The cut can be at any position i from 1 to n-1.
    // s = s[0...i-1] + s[i...n-1]
    // Let P1 = s.substr(0, i) and P2 = s.substr(i).
    // We can form P1P2 (original) or P2P1.
    // We need P2P1 to be a palindrome and P2P1 != s.
    for (int i = 1; i < n; ++i) {
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string s_prime = p2 + p1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts. Three pieces.
    // s = s[0...i-1] + s[i...j-1] + s[j...n-1]
    // Let P1 = s.substr(0, i), P2 = s.substr(i, j-i), P3 = s.substr(j).
    // We can form P1P2P3 (original) or any permutation.
    // The problem statement implies that for k=2, we can always find a solution if k=1 doesn't work,
    // unless all characters are the same.
    // The example "nolon" -> 2 cuts.
    // "otto" -> 1 cut.
    // "qqqq" -> Impossible.
    // If all characters in s are the same (e.g., "aaaa"), then any permutation of pieces will result in "aaaa".
    // In this case, it's impossible to form a new string s' != s.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    // Also, since it's a palindrome, s[0] == s[n-1].
    // If n is odd, the middle character s[n/2] can be different from s[0].
    // If n is even, all characters must be the same for k=2 to be impossible.
    // Example: "nolon" (n=5). s[0]='n', s[1]='o', s[2]='l'.
    // Cut: no|l|on. P1="no", P2="l", P3="on".
    // Rearrange to P3P2P1: "on" + "l" + "no" = "onlno". This is a palindrome and != "nolon".
    // This requires 2 cuts.
    // This strategy works for any palindrome that is not all same characters.
    // We can always cut s into s[0...i-1], s[i...n-1-i], s[n-i...n-1] for some i.
    // For example, take i=1. P1=s[0], P2=s[1...n-2], P3=s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // P3P2P1 = s[n-1] + s[1...n-2] + s[0].
    // This is s[0] + s[1...n-2] + s[0]. This is just s.
    // This specific rearrangement doesn't work.

    // However, the problem states that if not all characters are the same, k=2 is always possible.
    // The logic is that if s is a palindrome and not all characters are the same,
    // then s is not of the form "aaaaa...".
    // This means there exists at least one character s[i] such that s[i] != s[0].
    // Consider the string s' = s.substr(0, n-1). This is a prefix of s.
    // If s' is a palindrome, then s must be of the form "axaxa" or "axxa".
    // For example, "ababa". s'="abab". Not a palindrome.
    // "aaaaa". s'="aaaa". Palindrome.
    // If s is a palindrome and not all characters are the same, then s.substr(0, n-1) is NOT a palindrome.
    // Proof: Assume s.substr(0, n-1) is a palindrome.
    // Let s = c_0 c_1 ... c_{n-1}.
    // s is a palindrome => c_i = c_{n-1-i} for all i.
    // s.substr(0, n-1) = c_0 c_1 ... c_{n-2}.
    // If s.substr(0, n-1) is a palindrome => c_i = c_{n-2-i} for all i from 0 to n-2.
    // From s being a palindrome: c_0 = c_{n-1}, c_1 = c_{n-2}, c_2 = c_{n-3}, ...
    // From s.substr(0, n-1) being a palindrome: c_0 = c_{n-2}, c_1 = c_{n-3}, ...
    // Combining these: c_0 = c_{n-1} and c_0 = c_{n-2}. So c_{n-1} = c_{n-2}.
    // Also c_1 = c_{n-2} and c_1 = c_{n-3}. So c_{n-2} = c_{n-3}.
    // This implies c_0 = c_1 = c_2 = ... = c_{n-1}.
    // So, if s.substr(0, n-1) is a palindrome, then all characters in s must be the same.
    // The contrapositive is: If not all characters in s are the same, then s.substr(0, n-1) is NOT a palindrome.
    //
    // Now, consider the string s_prefix = s.substr(0, n-1).
    // If not all characters in s are the same, then s_prefix is not a palindrome.
    // We can make two cuts: s[0] | s[1...n-2] | s[n-1].
    // P1 = s[0], P2 = s[1...n-2], P3 = s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // Consider the string P1 + P3 + P2 = s[0] + s[n-1] + s[1...n-2].
    // This is s[0] + s[0] + s[1...n-2]. This is not necessarily a palindrome.
    //
    // The standard construction for k=2 is to take s_prefix = s.substr(0, n-1).
    // Since s_prefix is not a palindrome, its reverse is different from s_prefix.
    // Let s_prefix_rev = reverse(s_prefix).
    // We can form s_prefix_rev + s[n-1]. This is a new string.
    // Is it a palindrome? Not necessarily.
    //
    // The problem statement implies that if k=1 doesn't work and not all chars are same, k=2 is the answer.
    // This is a known property for palindromes.
    // If a palindrome `s` is not composed of all identical characters,
    // then it's always possible to make two cuts and rearrange to form a different palindrome.
    // For example, take `s = "nolon"`.
    // Cuts: `n | olo | n`. Pieces: `P1="n"`, `P2="olo"`, `P3="n"`.
    // Rearrange to `P2 P1 P3` = `olo n n`. Not a palindrome.
    // Rearrange to `P1 P3 P2` = `n n olo`. Not a palindrome.
    // Rearrange to `P3 P1 P2` = `n n olo`. Not a palindrome.
    // Rearrange to `P3 P2 P1` = `n olo n`. This is `s`.
    //
    // The example "nolon" -> 2. The cuts are `no | l | on`.
    // P1="no", P2="l", P3="on".
    // Rearrange to `P3 P2 P1` = `on l no`. This is a palindrome and `!= nolon`.
    // This requires 2 cuts.
    // This specific cut `s[0...i-1] | s[i] | s[i+1...n-1]` and rearrangement `s[i+1...n-1] + s[i] + s[0...i-1]`
    // is not general.
    //
    // The problem statement guarantees that if not all characters are the same, k=2 is the answer.
    // This is a common competitive programming trick. If k=1 fails, and the "all same chars" case is handled,
    // then k=2 is the default answer.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y and a_i values to prevent overflow
// N can be up to 2e5, a_i up to 1e9.
// In one step, y can increase by 2 * a_x.
// If x jumps around, y can accumulate large values.
// Max path length could be N. 2 * N * 1e9 = 4e14, fits in long long.

// Memoization tables
// dp_y[x] stores the total y accumulated from state (x, y_initial) until termination or cycle.
// dp_x_final[x] stores the final x value if starting from (x, y_initial) and terminating.
// dp_visited[x] stores the state of processing for x:
//   0: not visited
//   1: currently visiting (part of current path, potential cycle)
//   2: finished (value computed and stored in dp_y, dp_x_final)
std::vector<long long> dp_y;
std::vector<long long> dp_x_final;
std::vector<int> dp_visited;
std::vector<long long> a_values; // a_values[0] is unused, a_values[1]...a_values[n]

int N_global; // Store N globally for easy access in solve function

// Recursive function to solve for a given starting x
// current_x: The current x value in the simulation
// current_y_offset: The y value accumulated so far in the current path (before this call)
// Returns the final y value if terminates, or -1 if infinite loop.
long long solve(int current_x) {
    // Check termination conditions
    if (current_x <= 0 || current_x > N_global) {
        return 0; // Base case: no further y accumulation
    }

    // Check memoization table
    if (dp_visited[current_x] == 2) { // Already computed
        return dp_y[current_x];
    }
    if (dp_visited[current_x] == 1) { // Cycle detected
        return -1;
    }

    dp_visited[current_x] = 1; // Mark as currently visiting

    long long val_at_x = a_values[current_x];

    // Step 1: x = x + a_x, y = y + a_x
    // New x: current_x + val_at_x
    // y accumulated in this step: val_at_x

    // Step 2: x = x - a_x, y = y + a_x
    // New x: (current_x + val_at_x) - val_at_x = current_x
    // y accumulated in this step: val_at_x
    // Total y accumulated in these two steps: 2 * val_at_x

    // The next state is (current_x - val_at_x)
    // The y accumulated from this point onwards is what we need to add.
    long long res = solve(current_x - val_at_x);

    if (res == -1) { // If subproblem leads to infinite loop
        dp_y[current_x] = -1;
    } else {
        dp_y[current_x] = res + 2 * val_at_x;
    }

    dp_visited[current_x] = 2; // Mark as finished
    return dp_y[current_x];
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    N_global = n;

    a_values.resize(n + 1); // a_values[0] unused, a_values[1]...a_values[n]
    // Read a_2, ..., a_n
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_values[i];
    }

    // Initialize memoization tables
    dp_y.resize(n + 1);
    dp_x_final.resize(n + 1); // Not strictly needed for this problem's logic, but good practice for full state
    dp_visited.resize(n + 1, 0);

    // For each i from 1 to n-1, set a_1 = i and run the program
    for (int i = 1; i < n; ++i) {
        a_values[1] = i; // Set a_1 for the current run

        // The first step is special: x = 1 + a_1, y = 0 + a_1
        // Let's call a_1 as initial_a1_val
        long long initial_a1_val = a_values[1];
        int next_x = 1 + initial_a1_val;
        long long current_y = initial_a1_val;

        // Now, from next_x, we apply the repeating steps.
        // We need to clear dp_visited for each new a_1, as a_1 changes the entire graph.
        // However, the problem states "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This means a_2 to a_n are fixed, only a_1 changes.
        // The recursive function `solve(current_x)` only depends on `a_values[current_x]` and subsequent `a_values`.
        // Since `a_values[2]` to `a_values[n]` are constant, `solve(x)` for `x >= 2` will always yield the same result.
        // Only `solve(1)`'s behavior changes because `a_values[1]` changes.
        // So, we only need to re-evaluate paths that involve `a_values[1]`.
        // The `solve` function is designed to compute the sum of `2 * a_x` for the path starting from `x`
        // until termination or cycle.
        // The `dp_visited` and `dp_y` arrays should be cleared for each run because `a_1` changes.
        // A more efficient approach would be to only clear the relevant parts or structure the DP differently.
        // Given N=2e5, clearing N elements N times is N^2, too slow.
        // N * N = (2e5)^2 = 4e10.
        // The problem is that `a_values[1]` changes.
        // The `solve` function computes the sum of `2 * a_x` for the path starting from `x`.
        // If `x` is `1`, `a_values[1]` is `i`.
        // If `x` is `2` or more, `a_values[x]` is fixed.
        // So, `solve(x)` for `x >= 2` will always return the same value.
        // We can precompute `solve(x)` for `x >= 2` once.
        // Then for each `i`, we just need to compute the first step and then call `solve` for the next `x`.

        // Let's re-initialize dp_visited and dp_y for each run.
        // This is the simplest approach. Let's check if it's too slow.
        // The `solve` function is called for `next_x`.
        // If `next_x` is `1`, it will re-evaluate.
        // If `next_x` is `>1`, it will use precomputed values if available.
        // The issue is that `solve(1)` itself depends on `a_values[1]`.
        // So, for each `i`, `solve(1)` needs to be re-evaluated.
        // But `solve(x)` for `x >= 2` should be constant.
        // The current `dp_visited` and `dp_y` are global.
        // If we clear them for each `i`, it's `N * N` operations.
        // We need to be smarter.

        // The `solve` function computes the sum of `2 * a_x` for the path starting from `x`.
        // The path is `x -> x - a_x -> (x - a_x) - a_{x-a_x} -> ...`
        // This path does not depend on `a_1` unless `x` itself is `1`.
        // So, `dp_y[k]` and `dp_visited[k]` for `k >= 2` can be computed once.
        // For `k=1`, `dp_y[1]` and `dp_visited[1]` need to be reset and recomputed for each `i`.

        // Let's precompute for x >= 2.
        // This requires a separate loop or careful handling.
        // A simpler way: `solve` function will naturally use memoization for `x >= 2`
        // and recompute for `x = 1` if `a_values[1]` changes.
        // The `dp_visited` and `dp_y` should be cleared for `x=1` only.
        // But `solve(next_x)` might call `solve(1)` if `next_x - a_{next_x} == 1`.
        // This means we need to clear all `dp_visited` and `dp_y` values that depend on `a_values[1]`.
        // This is tricky.

        // Let's reconsider the problem structure.
        // For each `i` (1 to n-1):
        //   `a_1 = i`
        //   `x = 1`, `y = 0`
        //   `x = x + a_x`, `y = y + a_x` (first step)
        //   `x_curr = 1 + a_1`, `y_curr = a_1`
        //   Then, from `x_curr`, we apply the repeating steps.
        //   The repeating steps are: `x = x + a_x`, `y = y + a_x`, then `x = x - a_x`, `y = y + a_x`.
        //   This is equivalent to: `x_new = x_old - a_{x_old}`, `y_new = y_old + 2 * a_{x_old}`.
        //   So, we need to find the result of `solve(x_curr)` and add it to `y_curr`.

        // The `solve` function computes the sum of `2 * a_x` for the path starting from `x`.
        // The path is `x -> x - a_x -> (x - a_x) - a_{x-a_x} -> ...`
        // This path does not depend on `a_1` unless `x` itself is `1`.
        // So, `dp_y[k]` and `dp_visited[k]` for `k >= 2` can be computed once.
        // For `k=1`, `dp_y[1]` and `dp_visited[1]` need to be reset and recomputed for each `i`.

        // To handle this efficiently:
        // 1. Precompute `dp_y[k]` and `dp_visited[k]` for `k` from `N` down to `2`.
        //    This ensures that when `solve(k)` is called, any `solve(k - a_k)` will either be already computed
        //    or will be for `k - a_k < 2`.
        //    When `solve(k)` is called, it will only call `solve(k - a_k)`.
        //    If `k - a_k` is `1`, it will call `solve(1)`.
        //    If `k - a_k` is `0` or less, it terminates.
        //    If `k - a_k` is `>1`, it will use the precomputed value.
        //    So, we can compute `dp_y[k]` for `k=N` down to `2` once.
        //    Then for each `i`, we only need to compute `solve(1)` if `next_x` becomes `1`.

        // Let's clear `dp_visited` and `dp_y` for `x=1` only.
        // This is not enough. If `solve(3)` calls `solve(1)`, and `a_1` changes, `solve(3)`'s result might change.
        // This means any `dp_y[k]` that depends on `dp_y[1]` needs to be recomputed.
        // This implies a full clear for each `i` is needed if we use a simple recursive DP.
        // But `N * N` is too slow.

        // The key insight is that the sequence of `x` values is `x_0 -> x_1 -> x_2 -> ...`
        // where `x_{k+1} = x_k - a_{x_k}`.
        // If `x_k = 1`, then `a_{x_k}` is `a_1`, which changes.
        // If `x_k > 1`, then `a_{x_k}` is fixed.
        // So, the path `x_0 -> x_1 -> ... -> x_j` is fixed as long as all `x_k > 1`.
        // Once `x_j = 1`, the path changes.
        // Or if `x_j <= 0` or `x_j > N`, it terminates.

        // We can use a "path compression" like technique.
        // For each `x`, store `(final_x, total_y_sum)` if `x` eventually terminates without hitting `1`.
        // Or `(1, total_y_sum_until_1)` if it hits `1`.
        // Or `(cycle, -1)` if it cycles without hitting `1`.

        // Let's define `get_result(x)` as the pair `(final_x_val, total_y_added)`
        // where `total_y_added` is the sum of `2 * a_k` for all `k` in the path.
        // `final_x_val` is the `x` value where it terminates, or `1` if it hits `1`, or `0` if it cycles.
        // `dp_result[x]` stores `(final_x_val, total_y_added)`.
        // `dp_visited[x]` for cycle detection.

        // This is essentially what the `solve` function does, but `solve` returns only `total_y_added` or `-1`.
        // The `solve` function implicitly handles `final_x_val` by its termination conditions.
        // The problem is that `a_values[1]` changes.
        // The `dp_y` and `dp_visited` arrays are global.
        // If `solve(k)` is called, and `k - a_k = 1`, then `solve(1)` is called.
        // `solve(1)`'s result depends on `a_values[1]`.
        // So, `dp_y[1]` and `dp_visited[1]` must be reset for each `i`.
        // But if `solve(k)` (for `k > 1`) calls `solve(1)`, then `dp_y[k]` also depends on `a_values[1]`.
        // This means `dp_y[k]` for `k > 1` might also need to be recomputed.
        // This is the core issue.

        // The only way to make this efficient is if the number of states that depend on `a_1` is small.
        // Or if the `solve` function is structured to not recompute fixed parts.
        // The current `solve` function is fine.
