#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If initial 'a' has an odd number of '1's, we can append a '1'.
    // This means the maximum number of '1's we can achieve in 'a'
    // (before any removals) is 'ones_a' if 'ones_a' is even,
    // or 'ones_a + 1' if 'ones_a' is odd.
    // This is equivalent to (ones_a + (ones_a % 2)).
    int max_ones_a_possible = ones_a + (ones_a % 2);

    // To transform 'a' into 'b', 'b' must be a suffix of some string 'a''
